-- Poems batch 108
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('f0f01bb4-b771-4a80-8123-551fe337fc38','方福州生日行','洪适','宋','宋诗','song-poetry','','[]','雪峰高高雪如許，海門潮生浪吞浦。',128,'全唐诗/poet.song.122000.json','["雪峰高高雪如許，海門潮生浪吞浦。", "郎罷携囝街西東，到處歡然聞好語。", "舊日大官多養高，民詞獄寄充官曹。", "橫行阡陌喧夜鼓，唯征關市析秋豪。", "只今事事無長蠹，五月政成歌召父。", "尺一方來問鳳儀，魁三快刷聯鴛羽。", "三山岌嶪摩曾空，便是方丈蓬瀛中。", "他年圖畫凌烟了，却向山中訪赤松。"]'),
('382f5c54-d506-4e4d-af27-41a02b606468','謝唐守送朱櫻二絕句  其一','洪适','宋','宋诗','song-poetry','','[]','鈴齋一樹滴階春，翻走髹盤贈野人。',32,'全唐诗/poet.song.122000.json','["鈴齋一樹滴階春，翻走髹盤贈野人。", "欲進麴生呼伯雅，却無樊素啟丹唇。"]'),
('37dd4869-106f-4003-b013-641bb696ad96','謝唐守送朱櫻二絕句  其二','洪适','宋','宋诗','song-poetry','','[]','乳酪醍醐僻郡無，多酸梅子豈吾徒。',32,'全唐诗/poet.song.122000.json','["乳酪醍醐僻郡無，多酸梅子豈吾徒。", "香擎翠籠青冥出，舊事從誰說上都。"]'),
('65df6fe6-86c5-476a-84e0-bbd47f79d81f','答林神童','洪适','宋','宋诗','song-poetry','','[]','快睹終童英妙時，跫然銜袖出明璣。',64,'全唐诗/poet.song.123000.json','["快睹終童英妙時，跫然銜袖出明璣。", "家聲不詫大哉問，文律何愁知者希。", "益利鋒鋩臨大敵，養成羽翼看高飛。", "紅塵可厭忙車馬，挹取西山爽氣歸。"]'),
('2c2770d5-8b84-45cf-854c-5419c946d2c2','海棠花二絕句  其一','洪适','宋','宋诗','song-poetry','','[]','雨濯吳粧膩，風催蜀錦裁。',24,'全唐诗/poet.song.123000.json','["雨濯吳粧膩，風催蜀錦裁。", "自嫌生較晚，不得聘寒梅。"]'),
('3c9a420f-4926-4dc1-b650-2c6b09c32488','海棠花二絕句  其二','洪适','宋','宋诗','song-poetry','','[]','鴨殼非難致，鮫胎業已成。',24,'全唐诗/poet.song.123000.json','["鴨殼非難致，鮫胎業已成。", "夜深寧覓睡，相照月偏明。"]'),
('69f45ca5-ed16-43c1-830f-63f8ad06300c','瑞香花','洪适','宋','宋诗','song-poetry','','[]','衮衮香毬次第開，結根幽獨謝紛埃。',64,'全唐诗/poet.song.123000.json','["衮衮香毬次第開，結根幽獨謝紛埃。", "芳蓉妬入鴛鴦社，異馥清傳錦繡堆。", "睡裏魂交非自衍，醒時心賞可無猜。", "品題盍在春林石，不是花王喜後來。"]'),
('61afe73e-df2f-4576-8f44-69da27aad55d','題信州吳傅朋郎中游絲書','洪适','宋','宋诗','song-poetry','','[]','上饒甿俗醇且古，千室鳴弦方按堵。',288,'全唐诗/poet.song.123000.json','["上饒甿俗醇且古，千室鳴弦方按堵。", "黄堂丈人今循良，河南治平追鼻祖。", "訟棠留景分清陰，爐篆方羊燕寢深。", "笑談了却邦人事，游戲翰墨惟書林。", "自從真行易篆隸，草聖書絕馳極摯。", "游雲驚龍初振奇，渴驥怒猊爭作勢。", "臣中第一茲謂誰，寥寥典則其幾希。", "丈人尺牘妙天下，臧去收拾生光輝。", "作古要須從我始，直欲名家自成體。", "手追心摹前無人，一掃塵蹤有新意。", "縱橫經緯生胸中，落紙便與游絲同。", "繰甕繭車飛白雪，織簷蛛網破清風。", "一行一筆相聯屬，姿態規撫駭凡目。", "臨池漫勞三十年，千兔從教後人禿。", "舊聞呂向連錦書，百字環寫縈髮如。", "惜哉淟汩已無考，盍使北面稱臺輿。", "獨步不復名相甲，端恨二王無此法。", "只今四海書同文，使者來求至將押。"]'),
('3e109bd3-105b-49e2-803c-96ccc2d8531b','雪詩用晁無咎韻','洪适','宋','宋诗','song-poetry','','[]','密雪舞冬晝，祁寒反夏炎。',288,'全唐诗/poet.song.123000.json','["密雪舞冬晝，祁寒反夏炎。", "竹枝低未濕，梅萼瑩先霑。", "怯冷昂肩立，欣繁矯首瞻。", "隨風方北渡，際海必東漸。", "軒簸來如摻，繽紛勢轉嚴。", "枯荄新點綴，曲砌巧增添。", "伺隙花穿戶，承隅箸插簷。", "高飛迷皎鶴，夜影逼清蟾。", "砧凈綃橫石，窗虛粉雜匳。", "崑丘千璧碎，武庫五兵銛。", "烟徑楊吹絮，香蹊蝶奮髯。", "鯨鯢陸骨腐，鵠鷺野翎爓。", "白髮秦人遯，厖眉漢尉潜。", "漬蠶功孰及，平地瑞初占。", "窖卧行人節，門扃志士恬。", "已甘穿履困，奚避割氈嫌。", "醉慕雙螯畢，寒懷五绔廉。", "飄颻疑宓女，刻畫謝無鹽。", "河闊凝新浪，峰高失舊尖。", "山陰賓欲返，淮右寇將殲。", "穆滿三章著，宣溫五板兼。", "君恩捐衛粟，天意絕齊痁。", "江上蓑堪畫，籬間氅可覘。", "客觀眸已眩，兒咀手頻拈。"]'),
('cad2fd7e-ae17-44ef-bab2-77c87e5aab3e','前韻雖險用之未盡掇其餘復成三百言','洪适','宋','宋诗','song-poetry','','[]','一苦寒威重，清晨雨脚□。',288,'全唐诗/poet.song.123000.json','["一苦寒威重，清晨雨脚□。", "嚴風號宇宙，飛雪下閭閻。", "布地鹽初撒，穿帷粉乍黏。", "裴回輕點袖，縈積滿盈檐。", "騁巧飄雖急，乘危勢或沾。", "梨花芳小圃，桂魄射疏簾。", "烟濕茶翁竈，竿低酒舍帘。", "清泉埋沼沚，蒼幹聳楩柟。", "玉匝齊君履，銀封魯國詹。", "盆收新琢璧，階展未裁縑。", "木杪疑飛絮，江干雜秀蒹。", "正隨雲陣合，未放日光暹。", "處壯山屠虎，高興澤殪蚺。", "重巔聞折木，邃野絕飛鶼。", "隼擊翎添厲，鱗藏口敢噞。", "狼隨姬滿駕，鵲集叔才苫。", "授簡詞臣敏，乘車海若謙。", "漢傳王母絳，周貢嵰山甜。", "王脧師方整，高昌眾欲熸。", "漢光開帝業，蘇烈貫兵鈐。", "豹曳荆人舄，牙抽孫子籤。", "膚寒方起粟，手坼正憂𪚫。", "挾纊冬裘燠，傾罍夜飲厭。", "寒光欺寶鑑，素質奪朱綅。"]'),
('60950b74-b77c-459e-982e-67d0d60360ef','用雪詩韻謝三外弟見和','洪适','宋','宋诗','song-poetry','','[]','我昔檇李寓，君方錫山潜。',288,'全唐诗/poet.song.123000.json','["我昔檇李寓，君方錫山潜。", "欲馳咫尺書，駃足無飛廉。", "相望參與商，引首徒遐瞻。", "朅來萍梗蹤，遠野得茅簷。", "獲與譚壘接，何詢龜筮占。", "青山整烟鬟，澄波開鑑奩。", "喬松與怪柏，如虬老龍髯。", "悠然一望間，野色皆可覘。", "范甑飛埃塵，墨突寒不黔。", "好友豈厭頻，雞黍供炊爓。", "外家三遺珠，穎脫皆囊尖。", "交情謝流俗，不問凉及炎。", "著鞭挹清風，從者屢我淹。", "高論極根源，師友識所漸。", "大略搉治忽，細談析毫纖。", "皮裏有陽秋，褒貶追齊殲。", "古稱學如殖，秋成觀執鐮。", "吾匪董夫子，家居下帷幨。", "言經雖敗績，寧防整冠嫌。", "抽軋强成章，句鄙不任拈。", "骩骳且艱澀，疵瑕費鍼砭。", "君詩粲珠琲，光焰古人兼。", "詎覆傖父酒，不道胡兒鹽。", "陳檄愈頭疾，杜詞逐寒痁。"]'),
('4317ace6-54e8-45ed-b510-79a19f872901','讀秦本紀','洪适','宋','宋诗','song-poetry','','[]','應侯一語幽宣后，長信蒙辜徙萯陽。',32,'全唐诗/poet.song.123000.json','["應侯一語幽宣后，長信蒙辜徙萯陽。", "秦室無親類梟獍，借箕誶語亦其常。"]'),
('70ee21dc-bec6-4cfd-ba85-06527e5f619d','侯生','洪适','宋','宋诗','song-poetry','','[]','淮陰束手九江閑，誰信功成頰舌間。',32,'全唐诗/poet.song.123000.json','["淮陰束手九江閑，誰信功成頰舌間。", "不惜鴻溝分二國，太公今日得生還。"]'),
('9c7fc26f-a194-4e4c-8feb-028f44a9fb72','楚懷王','洪适','宋','宋诗','song-poetry','','[]','武關謀詐却稱臣，冤魄游魂尚在秦。',32,'全唐诗/poet.song.123000.json','["武關謀詐却稱臣，冤魄游魂尚在秦。", "墓木蕭條冢猶濕，流聞其子作昏姻。"]'),
('9198c203-96d4-4dbc-aff2-4212a7f92ae7','讀戰國史','洪适','宋','宋诗','song-poetry','','[]','折足黥徒未易欺，簀中死士亦何爲。',32,'全唐诗/poet.song.123000.json','["折足黥徒未易欺，簀中死士亦何爲。", "魏齊斷首龐涓死，禍報由來不可知。"]'),
('4c24fc8d-03f2-4fb8-9ce1-c7ec2441b67a','讀召公世家','洪适','宋','宋诗','song-poetry','','[]','齊晉瓜分四國王，嬴秦爲呂羋爲黄。',32,'全唐诗/poet.song.123000.json','["齊晉瓜分四國王，嬴秦爲呂羋爲黄。", "六雄當日皆新主，獨有甘棠澤未亡。"]'),
('5570c157-02b3-4cff-9779-f288de12ee24','穰侯','洪适','宋','宋诗','song-poetry','','[]','推轂曾聞薦武安，威伸三晉走荆蠻。',32,'全唐诗/poet.song.123000.json','["推轂曾聞薦武安，威伸三晉走荆蠻。", "廁中犬彘圖攘奪，猶道藏兵不出關。"]'),
('b070b0ae-4281-43dc-8f51-619f38b016ab','田單','洪适','宋','宋诗','song-poetry','','[]','齊主輕忘在莒時，解裘淄水遽相疑。',32,'全唐诗/poet.song.123000.json','["齊主輕忘在莒時，解裘淄水遽相疑。", "若無貂勃明勳業，幾使功臣枉見夷。"]'),
('4b7d7f53-057d-4a63-915e-c872a19c4e1d','長平','洪适','宋','宋诗','song-poetry','','[]','一敗長平振古無，趙邦臣主亦何愚。',32,'全唐诗/poet.song.123000.json','["一敗長平振古無，趙邦臣主亦何愚。", "當時已中馮亭計，猶自區區遣鄭朱。"]'),
('50acad11-841b-48b2-929d-ee7aeb9d2f3f','春申君','洪适','宋','宋诗','song-poetry','','[]','珠履三千盡在門，爭無國士解銜恩。',32,'全唐诗/poet.song.123000.json','["珠履三千盡在門，爭無國士解銜恩。", "棘門難作無遺類，死黨寧聞報李園。"]'),
('dd198fa4-6d41-49af-9d1c-a1cde6d5a675','題陳體仁判官休齋','洪适','宋','宋诗','song-poetry','','[]','翔纓彯組盍中留，綠水芙蓉且漫游。',64,'全唐诗/poet.song.123000.json','["翔纓彯組盍中留，綠水芙蓉且漫游。", "過耳從教千不是，處心渾欲一宜休。", "爐中異馥非多愛，架上新籤弗外求。", "寂寂掩扉無所事，飽聽風竹韻凉秋。"]'),
('bbcab900-6370-4eac-ae72-b206ce841351','次韻陳體仁惠詩幷示遊山詩卷','洪适','宋','宋诗','song-poetry','','[]','人生名利場，羈絆無休假。',120,'全唐诗/poet.song.123000.json','["人生名利場，羈絆無休假。", "沉迷雁鶩行，夢寐雞豚社。", "見謂游子欺，更防官長罵。", "何如山中樂，松窗肆嘉話。", "陳侯青雲客，英聲蜚日下。", "當年金馬門，掉鞅示閒暇。", "小試芙蓉池，未整驪駒駕。", "台嶽十日行，樛蘿若相迓。", "來歸探古囊，篇篇可圖畫。", "傾耳金石聲，鄭衛敢爭霸。"]'),
('48eae367-2545-44e2-b564-2e9ae43c1675','次韻李舉之縣丞秋日偶成  其一','洪适','宋','宋诗','song-poetry','','[]','當年使節反穹廬，解綬歸來得少娛。',32,'全唐诗/poet.song.123000.json','["當年使節反穹廬，解綬歸來得少娛。", "底事微官又縈縛，强顔文墨受意烏。"]'),
('9967b44a-e01b-4ba5-a049-211882f29736','次韻李舉之縣丞秋日偶成  其二','洪适','宋','宋诗','song-poetry','','[]','朝來傾耳得街談，頗說塵容亦可慚。',32,'全唐诗/poet.song.123000.json','["朝來傾耳得街談，頗說塵容亦可慚。", "從事未知三尺守，醉心空向六經酣。"]'),
('c7814878-a76d-4779-ab85-267fd30b64a5','次韻李舉之縣丞秋日偶成  其三','洪适','宋','宋诗','song-poetry','','[]','宦途陸陸未回車，秋桂春蘿總負渠。',32,'全唐诗/poet.song.123000.json','["宦途陸陸未回車，秋桂春蘿總負渠。", "目送飛鴻千里去，故山應草絕交書。"]'),
('a1e0bc05-51df-4de2-89e9-7f58759ca305','次韻李舉之縣丞秋日偶成  其四','洪适','宋','宋诗','song-poetry','','[]','筆底淵源萬頃多，卷中句法不隨波。',32,'全唐诗/poet.song.123000.json','["筆底淵源萬頃多，卷中句法不隨波。", "覃思正作青雲計，寡和聊成白雪歌。"]'),
('abec64d6-2613-4842-a077-81517f52cc89','次韻題謝景思少卿藥寮','洪适','宋','宋诗','song-poetry','','[]','壯歲揮金邁二疏，眼看餘子伏鹽車。',64,'全唐诗/poet.song.123000.json','["壯歲揮金邁二疏，眼看餘子伏鹽車。", "芷蘭清馥渾紉佩，芝朮新苗幾荷鋤。", "剩作好詩傳近體，誰言巧宦勝閑居。", "北窗睡起琴聲寂，便若身登太皞墟。"]'),
('64c13da5-cd35-4e44-b1f1-2717f40dfccc','蔡瞻明寺丞有詩見簡次其韻','洪适','宋','宋诗','song-poetry','','[]','漱芳傾液飽心胸，久矣高名在郢中。',64,'全唐诗/poet.song.123000.json','["漱芳傾液飽心胸，久矣高名在郢中。", "遂請叢祠方養氣，卜居蕭寺且談空。", "結交許入芝蘭室，招隱奚須桑苧翁。", "妙語鼎來驚創見，益慚白豕過河東。"]'),
('a2998264-ef70-419f-86a5-18d1cb391727','酬李舉之','洪适','宋','宋诗','song-poetry','','[]','象載凝華落筆工，一時英妙盍居中。',64,'全唐诗/poet.song.123000.json','["象載凝華落筆工，一時英妙盍居中。", "交情耐久惟同味，詩意求新更鑿空。", "揮麈寧談阿堵物，聯珠不數囁嚅翁。", "文成間被雞林得，復有聲名到海東。"]'),
('b1625fb4-64a3-4c83-8fc9-e17430572c98','次韻曹功顯都承賞梅','洪适','宋','宋诗','song-poetry','','[]','紛紛凡卉怯嚴冬，獨有清姿對雪中。',64,'全唐诗/poet.song.123000.json','["紛紛凡卉怯嚴冬，獨有清姿對雪中。", "拂幌更宜粧嫵媚，巡簷誰憚履穿空。", "南來未見傳聲使，東望方思避俗翁。", "聞道聯鑣得幽趣，無因同醉玉堂東。"]'),
('735aeb0b-a45b-49f9-bec1-d4962e322f9f','次韻李舉之立春四絕句  其一','洪适','宋','宋诗','song-poetry','','[]','東皇先遣雪清塵，一夜山川眼界新。',32,'全唐诗/poet.song.123000.json','["東皇先遣雪清塵，一夜山川眼界新。", "共喜太平今有象，更將歌舞爲迎春。"]'),
('a403bab3-14af-42c9-ae00-142a683e240a','次韻李舉之立春四絕句  其二','洪适','宋','宋诗','song-poetry','','[]','三冬文史總空虛，獨有施行寬大書。',32,'全唐诗/poet.song.123000.json','["三冬文史總空虛，獨有施行寬大書。", "坐對南牆千箇竹，何妨留客煮園蔬。"]'),
('eec51251-69d7-4205-840b-ac99448020f1','次韻李舉之立春四絕句  其三','洪适','宋','宋诗','song-poetry','','[]','雪後疏梅正壓枝，春來朝日已暉暉。',32,'全唐诗/poet.song.123000.json','["雪後疏梅正壓枝，春來朝日已暉暉。", "癡兒公事何時了，一醉花前心似飛。"]'),
('f321b5fb-29a1-4803-8ea8-b2815e4c7d9e','次韻李舉之立春四絕句  其四','洪适','宋','宋诗','song-poetry','','[]','他鄉春日思如何，屏去茶甌任睡魔。',32,'全唐诗/poet.song.123000.json','["他鄉春日思如何，屏去茶甌任睡魔。", "且得小窗成好夢，片時江上逐烟蓑。"]'),
('dc4fdb18-6d39-4ca3-896d-d99c1d3a86dc','次韻蔡瞻明惜花五絕句  其一','洪适','宋','宋诗','song-poetry','','[]','底事春愁減玉肌，誰能獺髓爲扶衰。',32,'全唐诗/poet.song.123000.json','["底事春愁減玉肌，誰能獺髓爲扶衰。", "可憐傍巘臨池處，非復嫣然一笑時。"]'),
('cd32f21d-fa01-4e7e-9697-51848d225a43','次韻蔡瞻明惜花五絕句  其二','洪适','宋','宋诗','song-poetry','','[]','無情誰似東風薄，相見那思雪夜初。',32,'全唐诗/poet.song.123000.json','["無情誰似東風薄，相見那思雪夜初。", "欲把紅顔借桃杏，便教枝上白紛如。"]'),
('89491ee8-2269-480f-b828-37f8ac5152dd','次韻蔡瞻明惜花五絕句  其三','洪适','宋','宋诗','song-poetry','','[]','月地雲階滿意開，牽花準擬尚裴回。',32,'全唐诗/poet.song.123000.json','["月地雲階滿意開，牽花準擬尚裴回。", "抗瓊解佩已仙去，駭綠紛紅徒後來。"]'),
('78ef884d-9606-406a-a32f-2a21e53fb723','次韻蔡瞻明惜花五絕句  其四','洪适','宋','宋诗','song-poetry','','[]','試因子墨賦瓌姿，獨記朝容在一披。',32,'全唐诗/poet.song.123000.json','["試因子墨賦瓌姿，獨記朝容在一披。", "著粉直嫌粧太白，只今何似夢中時。"]'),
('55f00581-122c-4528-88bd-76c95158e828','次韻蔡瞻明惜花五絕句  其五','洪适','宋','宋诗','song-poetry','','[]','一聲橫笛曉林空，知是春風十日東。',32,'全唐诗/poet.song.123000.json','["一聲橫笛曉林空，知是春風十日東。", "來歲花時在何處，探芳還有幾人同。"]'),
('6dcdf8eb-5574-4651-8fae-d74d94a7b1b1','陳體仁以心清聞妙香作詩惠末利花香次韻爲謝  其一','洪适','宋','宋诗','song-poetry','','[]','塵勞昏獨志，祿利蠶良心。',48,'全唐诗/poet.song.123000.json','["塵勞昏獨志，祿利蠶良心。", "掃地香一爐，澹然清興深。", "假寐頃刻間，烟霏遂盈襟。", "聯翩珊瑚鉤，逼人何駸駸。"]'),
('f9eef58a-a210-453b-8286-348fed7379ea','陳體仁以心清聞妙香作詩惠末利花香次韻爲謝  其二','洪适','宋','宋诗','song-poetry','','[]','東風將小雨，一夕池中平。',48,'全唐诗/poet.song.123000.json','["東風將小雨，一夕池中平。", "春聲在疏竹，琅琅有餘清。", "公退遠世氛，心地莫與京。", "寶薰凝窗牖，爲君尋鷗盟。"]'),
('0cc9ec41-cf4a-458f-8ce3-4c7fc365fb0e','陳體仁以心清聞妙香作詩惠末利花香次韻爲謝  其三','洪适','宋','宋诗','song-poetry','','[]','鼻觀拜嘉况，名香如前聞。',48,'全唐诗/poet.song.123000.json','["鼻觀拜嘉况，名香如前聞。", "塵容方一洗，藻思期三薰。", "久坐欣有得，飄飄欲陵雲。", "都良與迷迭，芳馨此其分。"]'),
('ad4a56a7-0567-47d2-9d13-d0182004f9d7','陳體仁以心清聞妙香作詩惠末利花香次韻爲謝  其四','洪适','宋','宋诗','song-poetry','','[]','英英末利花，素蕤馥清曉。',48,'全唐诗/poet.song.123000.json','["英英末利花，素蕤馥清曉。", "誰將煮水沉，採擷得奇妙。", "吾非范蔚宗，品題能了了。", "雜佩媿報酬，蕪音發嘲笑。"]'),
('16db1db5-cdbd-4996-8978-acb9cae17265','陳體仁以心清聞妙香作詩惠末利花香次韻爲謝  其五','洪适','宋','宋诗','song-poetry','','[]','春日紫宸朝，合殿縈天香。',48,'全唐诗/poet.song.123000.json','["春日紫宸朝，合殿縈天香。", "玉筍粲風采，雞舌相芬芳。", "陳侯金閨彥，指期簉鵷行。", "安能久鬰鬰，俛首回剛腸。"]'),
('b8e4bd5d-0318-466c-a2b0-e94deb1524b4','偶得梅一種疏枝清香附萼之花五出與江梅無異但花色微紅而五出之上復有一重或十葉或九葉他日皆並蒂雙實俗呼爲鴛鴦梅昔上林有趙昭儀所植同心梅疑即此也因成四絕  其一','洪适','宋','宋诗','song-poetry','','[]','却月凌風一種香，更勻粉面作紅粧。',32,'全唐诗/poet.song.123000.json','["却月凌風一種香，更勻粉面作紅粧。", "枝頭自結鴛鴦社，爲倩東風謝海棠。"]'),
('e5df21a8-c712-4c91-ad07-83e7413e73ec','偶得梅一種疏枝清香附萼之花五出與江梅無異但花色微紅而五出之上復有一重或十葉或九葉他日皆並蒂雙實俗呼爲鴛鴦梅昔上林有趙昭儀所植同心梅疑即此也因成四絕  其二','洪适','宋','宋诗','song-poetry','','[]','重重香蘤故多情，索笑初聞带薄酲。',32,'全唐诗/poet.song.123000.json','["重重香蘤故多情，索笑初聞带薄酲。", "翻恨前村雪深處，一枝幽獨太憨生。"]'),
('e0680a0c-55cb-4343-a79e-c1acfabbea3a','偶得梅一種疏枝清香附萼之花五出與江梅無異但花色微紅而五出之上復有一重或十葉或九葉他日皆並蒂雙實俗呼爲鴛鴦梅昔上林有趙昭儀所植同心梅疑即此也因成四絕  其三','洪适','宋','宋诗','song-poetry','','[]','客子逢花心欲灰，異方初見眼還開。',32,'全唐诗/poet.song.123000.json','["客子逢花心欲灰，異方初見眼還開。", "故應臨水橫斜日，曾作于飛一念來。"]'),
('3bf3de27-c6d1-4735-8021-1d534eb92385','偶得梅一種疏枝清香附萼之花五出與江梅無異但花色微紅而五出之上復有一重或十葉或九葉他日皆並蒂雙實俗呼爲鴛鴦梅昔上林有趙昭儀所植同心梅疑即此也因成四絕  其四','洪适','宋','宋诗','song-poetry','','[]','開花已作鴛鴦侶，著子還成鴻雁行。',32,'全唐诗/poet.song.123000.json','["開花已作鴛鴦侶，著子還成鴻雁行。", "舊日同心上林種，至今千載亦流芳。"]'),
('7628bbe8-0327-42ef-9d79-136b66df8180','次韻蔡瞻明登巾山三絕句  其一','洪适','宋','宋诗','song-poetry','','[]','朝來爽氣冠曾丘，急雨驚風正麥秋。',32,'全唐诗/poet.song.123000.json','["朝來爽氣冠曾丘，急雨驚風正麥秋。", "要得雲軒聊放目，何妨松徑暫低頭。"]'),
('ce2387a8-1ad2-4493-ae30-c39b4935e56e','次韻蔡瞻明登巾山三絕句  其二','洪适','宋','宋诗','song-poetry','','[]','名韁局促祇懷慚，飄忽熙春月過三。',32,'全唐诗/poet.song.123000.json','["名韁局促祇懷慚，飄忽熙春月過三。", "矯首白雲千里外，此心無日不江南。"]'),
('a2ab9e08-dc00-4423-90c6-3d7b5b2a0863','次韻蔡瞻明登巾山三絕句  其三','洪适','宋','宋诗','song-poetry','','[]','好句聯翩見未曾，品題今日欠鍾嶸。',32,'全唐诗/poet.song.123000.json','["好句聯翩見未曾，品題今日欠鍾嶸。", "登臨自有江山助，豈是胸中不得平。"]'),
('3aa769cf-0051-48f0-9447-65e499761a37','得二弟消息','洪适','宋','宋诗','song-poetry','','[]','倚欄春晝靜，花柳自芳香。',48,'全唐诗/poet.song.123000.json','["倚欄春晝靜，花柳自芳香。", "消息三州遠，塵埃兩地忙。", "鵲聲傳近喜，鴻影憶初行。", "抄得新書策，歸時補墨莊。"]'),
('ec331ccc-d931-45c9-ac63-16027d9aca44','次韻李舉之風雨中書事四絕句  其一','洪适','宋','宋诗','song-poetry','','[]','掛壁鳴琴久斷絃，强反書帙本相便。',32,'全唐诗/poet.song.123000.json','["掛壁鳴琴久斷絃，强反書帙本相便。", "詞源顧我非流峽，藻思如君已掞天。"]'),
('a35d21ff-3663-4d26-b257-03d8b26ee707','次韻李舉之風雨中書事四絕句  其二','洪适','宋','宋诗','song-poetry','','[]','雨勢風聲何太雄，群山答響亂賁鏞。',32,'全唐诗/poet.song.123000.json','["雨勢風聲何太雄，群山答響亂賁鏞。", "青奴今夕安用汝，玉友此時留得儂。"]'),
('8936095b-7dd6-4995-b618-47ea7f0d4a8d','次韻李舉之風雨中書事四絕句  其三','洪适','宋','宋诗','song-poetry','','[]','怒號通夕攪空虛，好夢那能到玉除。',32,'全唐诗/poet.song.123000.json','["怒號通夕攪空虛，好夢那能到玉除。", "枕上泰然無一念，只愁雨滴架中書。"]'),
('13557a30-b557-4dda-a439-5d0f1e360544','次韻李舉之風雨中書事四絕句  其四','洪适','宋','宋诗','song-poetry','','[]','向曉登樓憑小欄，蕭然歸興在江干。',32,'全唐诗/poet.song.123000.json','["向曉登樓憑小欄，蕭然歸興在江干。", "癡兒未了公家事，且把雲山子細看。"]'),
('ead4f9ff-bb3a-41fd-a971-269888277c96','次韻蔡瞻明秋園五絕句  其一','洪适','宋','宋诗','song-poetry','','[]','芥毛金爪勇難干，肯作霜花對乍寒。',32,'全唐诗/poet.song.123000.json','["芥毛金爪勇難干，肯作霜花對乍寒。", "若說乘軒有癡鶴，司晨如此合峨冠。"]'),
('ef4bcd42-f1f4-436c-9095-75a480300489','次韻蔡瞻明秋園五絕句  其二','洪适','宋','宋诗','song-poetry','','[]','翔仞當年覽德輝，傳芳花品未思歸。',32,'全唐诗/poet.song.123000.json','["翔仞當年覽德輝，傳芳花品未思歸。", "晚來霧鬢憑軒處，直恐金翹相對飛。"]'),
('22c104d1-8d92-4a5e-b9d0-d1c8e8ed9086','次韻蔡瞻明秋園五絕句  其三','洪适','宋','宋诗','song-poetry','','[]','澤蘭萱草比多言，謂汝分陰久奪鮮。',32,'全唐诗/poet.song.123000.json','["澤蘭萱草比多言，謂汝分陰久奪鮮。", "政恐淇園修竹勁，不如秦嶺老松堅。"]'),
('42f374b7-fbb3-4ac7-a1cb-2d5b764485f0','次韻蔡瞻明秋園五絕句  其四','洪适','宋','宋诗','song-poetry','','[]','高標幽艷自宜霜，弱草繁葩莫中傷。',32,'全唐诗/poet.song.123000.json','["高標幽艷自宜霜，弱草繁葩莫中傷。", "肯與紅蓮媚三夏，要同黄菊向重陽。"]'),
('932f4d13-ff12-4d67-a326-e29c4ff259bb','次韻蔡瞻明秋園五絕句  其五','洪适','宋','宋诗','song-poetry','','[]','臨風裛露早秋天，範出南金色更鮮。',32,'全唐诗/poet.song.123000.json','["臨風裛露早秋天，範出南金色更鮮。", "若向東籬比標格，定知花市不言錢。"]'),
('5b6bd2f4-15a2-4763-ab7c-2147f614a4df','宿佛窟寺','洪适','宋','宋诗','song-poetry','','[]','籃輿登佛窟，高閣望中清。',48,'全唐诗/poet.song.123000.json','["籃輿登佛窟，高閣望中清。", "古木爾許蔭，飛泉無限聲。", "雨消今日暑，雲作晚來晴。", "獨對青山久，相逢如有情。"]'),
('85f4c666-4936-4f75-ab96-2628cd11a65e','過瑞巖寺示勝上人','洪适','宋','宋诗','song-poetry','','[]','逗曉亂山中，來尋古佛宮。',48,'全唐诗/poet.song.123000.json','["逗曉亂山中，來尋古佛宮。", "荷間留夜雨，松下進秋風。", "瑞氣舊如許，巖姿今亦同。", "惺惺有盤石，應記主人公。"]'),
('d0dc2326-2787-40d0-ac60-91b5bd776746','惺惺石','洪适','宋','宋诗','song-poetry','','[]','簿領久沉迷，誰能不忍欺。',24,'全唐诗/poet.song.123000.json','["簿領久沉迷，誰能不忍欺。", "我來慚此石，拈出問吾師。"]'),
('32b7df4b-ab4b-4e6b-b86e-8f0595f51cf7','滴滴泉','洪适','宋','宋诗','song-poetry','','[]','石罅來泉滴，松風雜澗聲。',24,'全唐诗/poet.song.123000.json','["石罅來泉滴，松風雜澗聲。", "天明有公事，還憶此時清。"]'),
('a66a8a00-d44f-4771-89a5-9f29c0cdade3','題靈石寺并簡景思','洪适','宋','宋诗','song-poetry','','[]','聞道飛來石，當年却畔亡。',48,'全唐诗/poet.song.123000.json','["聞道飛來石，當年却畔亡。", "烟杉行客路，風竹護禪房。", "有酒對玉麈，無詩夸錦囊。", "塵纓自羈束，真賞負山光。"]'),
('3387c667-270d-4c50-84b8-42199072c65c','夜飲藥寮次景思韻','洪适','宋','宋诗','song-poetry','','[]','主人知我樂郊居，藥圃嘉招走尺書。',64,'全唐诗/poet.song.123000.json','["主人知我樂郊居，藥圃嘉招走尺書。", "笑語池邊欣促席，醉歸林下却肩輿。", "正聞雁過猨啼後，更是風清月白初。", "見說長安消息近，却須高興謝鱸魚。"]'),
('dd2d3b50-851c-4853-ba26-c641f773e161','題景思水芝亭','洪适','宋','宋诗','song-poetry','','[]','遠意閟千雲，亭幽不受塵。',48,'全唐诗/poet.song.123000.json','["遠意閟千雲，亭幽不受塵。", "來爲池上客，本是社中人。", "影密龜魚蔭，花開鷗鷺馴。", "買山如遂志，應許卜比鄰。"]'),
('b21ac3c7-3c52-4756-9705-5e79ed422f00','黄巖道中','洪适','宋','宋诗','song-poetry','','[]','兩日黄巖縣，紛然百慮侵。',48,'全唐诗/poet.song.123000.json','["兩日黄巖縣，紛然百慮侵。", "乍聽幽鳥語，復起故園心。", "冒熱度峻嶺，憚勞休茂林。", "潮來知海近，三島可能尋。"]'),
('2055190c-825d-43f9-9308-e02d5a886f50','過妙緣寺聽懷上人琴','洪适','宋','宋诗','song-poetry','','[]','斷澗復危岑，紅塵且滿襟。',48,'全唐诗/poet.song.123000.json','["斷澗復危岑，紅塵且滿襟。", "疾驅觸炎熱，小憩得禪林。", "煮茗對清話，弄琴知好音。", "秋風不借便，去轍已駸駸。"]'),
('4814899c-639f-410f-9721-a84aa9362b4c','行縣道中寄曾谹父','洪适','宋','宋诗','song-poetry','','[]','雲山初見非昔遊，一瞬不許回雙眸。',64,'全唐诗/poet.song.123000.json','["雲山初見非昔遊，一瞬不許回雙眸。", "二年佐州已强半，七月行縣難罷休。", "濺濺微溜響縈谷，薿薿多稼光盈疇。", "兵厨願留一罇酒，霜螯醉嚼期中秋。"]'),
('adf1585b-ed20-44bd-a6a9-8e7a0633eb4d','登寧和嶺','洪适','宋','宋诗','song-poetry','','[]','初識寧和嶺，有懷占夢時。',48,'全唐诗/poet.song.123000.json','["初識寧和嶺，有懷占夢時。", "聞詩千里隔，斷織九京悲。", "草木應相記，烟雲渾異宜。", "西風襲懷抱，泪睫不勝垂。"]'),
('1b0caacf-03fa-4cf5-b1b8-8c7a9aae18d2','懷孫邦求','洪适','宋','宋诗','song-poetry','','[]','酒開桑落泛觥觩，行子驅車恨不留。',64,'全唐诗/poet.song.123000.json','["酒開桑落泛觥觩，行子驅車恨不留。", "雁塔自是丈人行，麟臺更參儒者流。", "官居二年有十月，別思一日真三秋。", "冰輪今已可人意，何時來賞城東樓。"]'),
('0570fed3-e429-497f-a288-2aa32412e287','宿大龍山寺贈海上人','洪适','宋','宋诗','song-poetry','','[]','看山論舊事，拂石認前題。',48,'全唐诗/poet.song.123000.json','["看山論舊事，拂石認前題。", "雨滑苔徑阻，雲收松嶠迷。", "三秋文豹隱，一夜寒螿啼。", "又復問程去，清遊懷虎溪。"]'),
('0c36f170-1b9b-41b7-8407-8df893ef5f15','大龍山五詠用家君所和胡別駕韻 經藏','洪适','宋','宋诗','song-poetry','','[]','萬法俱一空，忘筌亦忘字。',24,'全唐诗/poet.song.123000.json','["萬法俱一空，忘筌亦忘字。", "勿置齒牙間，回觀方寸地。"]'),
('1ddb6ddf-85e7-4ddb-baeb-405f89e8a261','大龍山五詠用家君所和胡別駕韻 龍祠','洪适','宋','宋诗','song-poetry','','[]','夾日授五飛，論功中興主。',24,'全唐诗/poet.song.123000.json','["夾日授五飛，論功中興主。", "宛宛龍父尊，茲山職霖雨。"]'),
('1fa772dd-8988-4534-9d0a-bdfd776fba5c','大龍山五詠用家君所和胡別駕韻 密室','洪适','宋','宋诗','song-poetry','','[]','小室坐蒲團，死灰念不作。',24,'全唐诗/poet.song.123000.json','["小室坐蒲團，死灰念不作。", "所以護明珠，精修企先覺。"]'),
('2ebee830-b2db-4602-a99d-9f44e7789785','大龍山五詠用家君所和胡別駕韻 小池','洪适','宋','宋诗','song-poetry','','[]','山椒有龍湫，清泉日夜流。',24,'全唐诗/poet.song.123000.json','["山椒有龍湫，清泉日夜流。", "疏巖作方沼，漱甘非外求。"]'),
('5b133a50-66a8-4676-9b74-6a77ab8431fe','大龍山五詠用家君所和胡別駕韻 湯爐','洪适','宋','宋诗','song-poetry','','[]','蟹眼候松風，雲腴挾霜月。',24,'全唐诗/poet.song.123000.json','["蟹眼候松風，雲腴挾霜月。", "爐下豈常炎，灰飛即烟滅。"]'),
('954c4863-ed77-476b-af53-bdc2dee48b5e','懷李氏昆弟二十韻','洪适','宋','宋诗','song-poetry','','[]','城南兩佳士，英躔名硉矹。',240,'全唐诗/poet.song.123000.json','["城南兩佳士，英躔名硉矹。", "相之妙才具，玉筍班中闕。", "胡爲彯長纓，去去事輗軏。", "舉之登詞壇，龍虎榜未揭。", "歸循南陔蘭，不使芳馨歇。", "胸中蟠五車，一一思英發。", "有中清廟瑟，審聲知度越。", "我來貳銀菟，接袂俱墨髮。", "情期膠漆堅，門受車馬謁。", "筆陣幾鏖戰，君盈我先竭。", "別來勤相思，十日倏飄忽。", "遲明蒙囂塵，畢景邁崷崪。", "躋高怯肩輿，挹秀欣拄笏。", "泉清甘著齒，巖幽冷縈骨。", "西風涌波瀾，極望際溟渤。", "是中三神山，縹緲雲出沒。", "問津舊乘槎，引舟今捨筏。", "俛首傾縹瓷，獨醉徑兀兀。", "起看天宇開，詩成走郵卒。", "歸歟及中秋，高樓共嘉月。"]'),
('1b22ac8b-ba89-42ef-a771-13ef9755d336','宿廣潤寺書倫上人靈雲庵','洪适','宋','宋诗','song-poetry','','[]','寶地深深俯碧潭，有僧酌茶延我談。',64,'全唐诗/poet.song.123000.json','["寶地深深俯碧潭，有僧酌茶延我談。", "千巖狀秀躡風磴，萬竹含翠藏雲庵。", "西來指栢本無著，一見悟桃須再參。", "登臨已是秋欲半，霜葉枝頭纔兩三。"]'),
('276e743a-2e67-4ac4-96e6-d5eed53996a2','摘星嶺','洪适','宋','宋诗','song-poetry','','[]','披山鑿道何嶮巇，上摘星漢摩虹霓。',64,'全唐诗/poet.song.123000.json','["披山鑿道何嶮巇，上摘星漢摩虹霓。", "七襄終日往曾問，一握去天今可躋。", "叱馭已排蘿蔓去，下車不復烟雲迷。", "舉頭此際長安遠，願借六翮凌丹梯。"]'),
('3cc7bd9d-4fb5-4998-8864-34e1be4fe98f','交翠亭','洪适','宋','宋诗','song-poetry','','[]','三十年中事，鸞棲筑小亭。',48,'全唐诗/poet.song.123000.json','["三十年中事，鸞棲筑小亭。", "寒聲長新籜，清閟拂疏欞。", "水轉前時綠，山濃遠處青。", "重來勤問訊，此別記秋螢。"]'),
('0746ec1a-aafe-4004-84a3-18485df69e37','交翠亭  其一','洪适','宋','宋诗','song-poetry','','[]','三十年中事，鸞棲筑小亭。',24,'全唐诗/poet.song.123000.json','["三十年中事，鸞棲筑小亭。", "寒聲長新籜，清閟拂疏欞。"]'),
('6801eefd-2691-4045-8d51-b0fb0d0f27b5','交翠亭  其二','洪适','宋','宋诗','song-poetry','','[]','水轉前時綠，山濃遠處青。',24,'全唐诗/poet.song.123000.json','["水轉前時綠，山濃遠處青。", "重來勤問訊，此別記秋螢。"]'),
('c3130085-5b05-4b76-9610-49c84959f958','三瑞堂','洪适','宋','宋诗','song-poetry','','[]','久矣馳魂夢，今登三瑞堂。',48,'全唐诗/poet.song.123000.json','["久矣馳魂夢，今登三瑞堂。", "故山有喬木，近事話甘棠。", "展驥慚充位，占熊憶問祥。", "白雲留未去，極望是吾鄉。"]'),
('b4046a67-9c2d-4d71-a19b-57c246892f4f','留別縣僚','洪适','宋','宋诗','song-poetry','','[]','滿城鼓吹出林坰，珍重來思此日情。',64,'全唐诗/poet.song.123000.json','["滿城鼓吹出林坰，珍重來思此日情。", "共說棲鸞留政迹，自憐展驥墜家聲。", "一時宦侶推儒雅，百里民編樂治平。", "山意川容若相挽，不堪整駕問歸程。"]'),
('191c8df2-3449-4cf8-8df1-1b859f133b13','過梁王寺書家君祠堂','洪适','宋','宋诗','song-poetry','','[]','生還未列麒麟畫，舊德猶懷鸞鳳棲。',32,'全唐诗/poet.song.123000.json','["生還未列麒麟畫，舊德猶懷鸞鳳棲。", "共問翰林今孰似，凜然眉宇染風㙠。"]'),
('b081b015-4a70-4ce3-86c3-6d269f327023','山行遇雨','洪适','宋','宋诗','song-poetry','','[]','天公作意轟雷霆，風雨驟至神如兵。',64,'全唐诗/poet.song.123000.json','["天公作意轟雷霆，風雨驟至神如兵。", "翻手爲雲只俄頃，舉頭見日尤精明。", "蟻君一戰方奏凱，鳩婦復還已和鳴。", "稅駕欲投佳處所，林間隱隱疏鐘聲。"]'),
('99aee47c-ad8b-43eb-a078-4ecea76ca160','蔡瞻明以詩還行邑鄙卷次韻謝之','洪适','宋','宋诗','song-poetry','','[]','凉秋野趣已蕭騷，方駕看山念我曹。',64,'全唐诗/poet.song.123000.json','["凉秋野趣已蕭騷，方駕看山念我曹。", "十日空歸才每下，一篇來况曲彌高。", "詞華若我慚雌霓，筆力惟公掣巨鼇。", "欲作歌詩興協律，清朝今日有王褒。"]'),
('4906d2f4-bd93-4811-9198-b98243607f48','酬李舉之用前韻見寄','洪适','宋','宋诗','song-poetry','','[]','閱盡千峰不憚勞，歸來文墨厭官曹。',64,'全唐诗/poet.song.123000.json','["閱盡千峰不憚勞，歸來文墨厭官曹。", "浮槎問漢秋期近，埋劍衝星夜氣高。", "那復精思如吐鳳，初無壯志欲乘鼇。", "詩壇軒輊歸題品，濫得陽秋一字褒。"]'),
('0540a53e-e435-4486-a559-628aaf5a98c4','褒字詩已得十二章請各賦其一以足巨鼇','洪适','宋','宋诗','song-poetry','','[]','紛紛吏道誇吹毛，未肯留心效此曹。',64,'全唐诗/poet.song.123000.json','["紛紛吏道誇吹毛，未肯留心效此曹。", "象齒好辭降二妙，鱸魚歸思羨三高。", "吟毫未禿一千兔，詩軸須聯十五鼇。", "敢道嚴霜起中夏，益知趁韻有龍褒。"]'),
('061f2d98-a37d-439c-b0c1-983ee213c8a2','次韻蔡瞻明木犀八絕句  其一','洪适','宋','宋诗','song-poetry','','[]','誰爲花王定等差，清芬端合佩金犀。',32,'全唐诗/poet.song.123000.json','["誰爲花王定等差，清芬端合佩金犀。", "上林他日移根去，應記詩仙綵筆題。"]'),
('ecbb37e0-6365-4041-b6e0-4c802556da86','次韻蔡瞻明木犀八絕句  其二','洪适','宋','宋诗','song-poetry','','[]','香清爲借三秋露，葩絢寧禁五日風。',32,'全唐诗/poet.song.123000.json','["香清爲借三秋露，葩絢寧禁五日風。", "俯對猗蘭振寒綠，靜看飛葉隕輕紅。"]'),
('2d6b46eb-1822-46ed-998a-e93bc0e8f637','次韻蔡瞻明木犀八絕句  其三','洪适','宋','宋诗','song-poetry','','[]','風流直欲占秋光，葉底深藏粟蘂黄。',32,'全唐诗/poet.song.123000.json','["風流直欲占秋光，葉底深藏粟蘂黄。", "共道幽香聞十里，絕知芳譽亙千鄉。"]'),
('3c7c9a23-91bf-4dc4-9c38-18903544a9cc','次韻蔡瞻明木犀八絕句  其四','洪适','宋','宋诗','song-poetry','','[]','笑含菊彩媚疏籬，巧作葵粧傍曲池。',32,'全唐诗/poet.song.123000.json','["笑含菊彩媚疏籬，巧作葵粧傍曲池。", "顔色從他矜速肖，芬馨如此孰爭馳。"]'),
('2e8e9bdc-861b-41ca-b3ce-64b90b42c56c','次韻蔡瞻明木犀八絕句  其五','洪适','宋','宋诗','song-poetry','','[]','心稟犀文饒地力，體薰蟾影奪天香。',32,'全唐诗/poet.song.123000.json','["心稟犀文饒地力，體薰蟾影奪天香。", "圖形好命丹青手，絺句須煩錦繡腸。"]'),
('467e04c9-6af3-4b6a-93e0-38f03d5bfc3f','次韻蔡瞻明木犀八絕句  其六','洪适','宋','宋诗','song-poetry','','[]','廣寒秋桂映天池，休說當年折得時。',32,'全唐诗/poet.song.123000.json','["廣寒秋桂映天池，休說當年折得時。", "韻勝今逢巖下種，價高寧靳橐中資。"]'),
('5f4d89a7-62e2-4577-9315-c0a7de98ea6a','次韻蔡瞻明木犀八絕句  其七','洪适','宋','宋诗','song-poetry','','[]','簪鬢新枝立晚晴，淡粧異馥稱雙清。',32,'全唐诗/poet.song.123000.json','["簪鬢新枝立晚晴，淡粧異馥稱雙清。", "夢魂不記前來事，愁逐江潮日日平。"]'),
('f10d52da-da41-4c1c-b6ab-cb63b15a6375','次韻蔡瞻明木犀八絕句  其八','洪适','宋','宋诗','song-poetry','','[]','黄絹家聲映古今，隨和發彩驚詞林。',32,'全唐诗/poet.song.123000.json','["黄絹家聲映古今，隨和發彩驚詞林。", "高樓宴坐清商晚，獨向此花垂意深。"]'),
('868b96db-62dd-403c-9d48-4fdab1af0097','次韻李相之觀溪漲二首  其一','洪适','宋','宋诗','song-poetry','','[]','愁霖方注射，駭浪忽衝斜。',48,'全唐诗/poet.song.123000.json','["愁霖方注射，駭浪忽衝斜。", "宿鳥行驚鴈，遊魚目失蝦。", "夕波奔析木，春漲過桃花。", "沸渭今如此，誰乘犯斗槎。"]'),
('386da56d-0861-4ce9-8fa2-8490f4a58cef','次韻李相之觀溪漲二首  其二','洪适','宋','宋诗','song-poetry','','[]','風聲隨雨急，水勢滿川黄。',48,'全唐诗/poet.song.123000.json','["風聲隨雨急，水勢滿川黄。", "巨艦困澎湃，窮閻悲混茫。", "爲魚懷洛汭，揵竹謝宣防。", "共徯陰雲卷，冰輪替戾岡。"]'),
('9dff9500-8041-46fc-bb2d-19e6dbc1ddea','次韻酬丁致遠司戶','洪适','宋','宋诗','song-poetry','','[]','翰墨場中識面初，珠璣粲粲似相如。',64,'全唐诗/poet.song.123000.json','["翰墨場中識面初，珠璣粲粲似相如。", "盍簪多士登臺省，却掾諸曹親簿書。", "白社不妨閑泚筆，赤城更好命巾車。", "寸心淟汩方茅塞，快讀新詩得剪除。"]'),
('e123f4b3-bbae-4dc1-a8b7-edb7d0e6b0a5','次韻蔡瞻明江樓秋晚二首  其一','洪适','宋','宋诗','song-poetry','','[]','斜照穿林迥，歸雲歛岫遲。',48,'全唐诗/poet.song.123000.json','["斜照穿林迥，歸雲歛岫遲。", "蝸文寒壁篆，蛛巧暮簷絲。", "待月是愁處，對山無倦時。", "掀髯阻談綺，細讀寄來詩。"]'),
('6cda0430-0609-4897-94c6-80c77734396d','次韻蔡瞻明江樓秋晚二首  其二','洪适','宋','宋诗','song-poetry','','[]','竹外秋風急，樓頭夕靄微。',48,'全唐诗/poet.song.123000.json','["竹外秋風急，樓頭夕靄微。", "遣懷須命酒，怯冷幾更衣。", "嚴鼓縈城去，輕舟劈浪歸。", "登臨多少意，墜葉滿庭飛。"]'),
('af1178c7-3516-4a74-b48e-761b2528dc40','九日官舍種竹','洪适','宋','宋诗','song-poetry','','[]','獨整陳編對北窗，烟雲渾欲助凄凉。',64,'全唐诗/poet.song.123000.json','["獨整陳編對北窗，烟雲渾欲助凄凉。", "庭前且使竹交翠，籬下從他菊自黄。", "遠官只今同旅泊，壯懷誰復問行藏。", "携壺已失登臨便，不待微吟恨夕陽。"]'),
('5737f51b-cd80-4f92-a911-8a5d1d95662b','天台道中','洪适','宋','宋诗','song-poetry','','[]','灘聲因雨急，山勢向雲斜。',48,'全唐诗/poet.song.123000.json','["灘聲因雨急，山勢向雲斜。", "橘綠誰能畫，楓丹遠似花。", "舂鋤懷淺水，郭索上寒沙。", "漸聽鳴梭近，林中三數家。"]'),
('177ba2ba-00cf-410e-9dd3-322cfaa7eb67','赤城','洪适','宋','宋诗','song-poetry','','[]','平生幾讀興公賦，今日霞標對赤城。',32,'全唐诗/poet.song.123000.json','["平生幾讀興公賦，今日霞標對赤城。", "此是南門入山路，山祇乞我一番晴。"]'),
('32e5ec20-392a-45a8-ba98-cb8c5733efd4','玉京洞','洪适','宋','宋诗','song-poetry','','[]','飆輪曾此宅靈仙，洞府今稱第六天。',32,'全唐诗/poet.song.123000.json','["飆輪曾此宅靈仙，洞府今稱第六天。", "規往不辭蘿蔓險，回看雲物起瓊田。"]'),
('d2fc19c4-8e00-438c-80d2-a5f0148b180f','國清寺','洪适','宋','宋诗','song-poetry','','[]','紺宇今方盛，名知國已清。',48,'全唐诗/poet.song.123000.json','["紺宇今方盛，名知國已清。", "萬松九里影，雙澗四時聲。", "杖策將窮覽，巾車不計程。", "登堂山更好，人去曉猿鳴。"]'),
('5cb311d9-3485-4ddd-af4b-cb195bef4f5f','清音亭','洪适','宋','宋诗','song-poetry','','[]','久坐俯潺湲，流清詩思慳。',48,'全唐诗/poet.song.123000.json','["久坐俯潺湲，流清詩思慳。", "跳珠鳴蘚石，淙玉下松關。", "此日耳塵靜，幾人心地閑。", "抽琴作新曲，歸去要怡顔。"]'),
('013123b7-b210-4c71-92d4-7d17fb9f754d','禪林寺','洪适','宋','宋诗','song-poetry','','[]','振策快秋晴，伽藍倚翠屏。',48,'全唐诗/poet.song.123000.json','["振策快秋晴，伽藍倚翠屏。", "看雲不留瞬，對竹已忘形。", "銀地聲千載，虹橋拱百靈。", "至今鐘磬響，如講凈名經。"]'),
('75c226c6-e2e3-4690-8293-753f47ba3e1e','山中阻雨欲登華頂峰而不果','洪适','宋','宋诗','song-poetry','','[]','昔聞天台山，一萬八千丈。',216,'全唐诗/poet.song.123000.json','["昔聞天台山，一萬八千丈。", "層峰目華頂，魂夢幾馳想。", "朅來乘清秋，明發將獨往。", "小雨巧作難，祥雲約仍爽。", "風磴漬苔蘚，霜崖亂榛莽。", "崢嶸一何峻，梯空不可上。", "便思捐竹輿，徐行倩藤杖。", "老僧挹而言，茲山韜萬象。", "舉頭天宇逼，寓目巖扉敞。", "重溟倒寒影，萬壑振幽響。", "峽迥啼猱猿，林高隕楂橡。", "仙袂挹浮丘，飄然頓塵網。", "今茲風雨時，烟霧接穹壤。", "勁寒或薄人，跬步迷俯仰。", "不如遊石梁，重來事真賞。", "斯言既纚纚，誠哉非我誑。", "俗駕爲之回，蕪音不堪榜。", "寄聲山中靈，心期空鞅鞅。"]'),
('f3c99583-62ba-4bce-9d02-f0c37d885ceb','石橋','洪适','宋','宋诗','song-poetry','','[]','懸磴跨幽崖，奔流漱深壑。',144,'全唐诗/poet.song.123000.json','["懸磴跨幽崖，奔流漱深壑。", "宛然臥蒼龍，天巧謝鎸鑿。", "萬木森前山，笙竽真籟作。", "長嘯斥猩猱，來巢怖烏鵲。", "莓苔助危梁，下瞰心膽落。", "橫前限翠屏，峭壁旁如削。", "於此判塵凡，只尺遂綿邈。", "飛錫躡空虛，樓臺變林薄。", "寶輝覿華燈，金翰過神雀。", "二年佐銅虎，渠能解羈絡。", "來烹紫雲腴，寒甌散葩萼。", "奇事訂前聞，詩成識層閣。"]'),
('d92cd57b-da6b-4efb-ab1d-3b477e4b035a','雨中宿萬年寺','洪适','宋','宋诗','song-poetry','','[]','夢回深夜耿秋燈，泉竇爭流一味清。',64,'全唐诗/poet.song.123000.json','["夢回深夜耿秋燈，泉竇爭流一味清。", "過雁不聞天外影，寒松長送枕邊聲。", "饕風可但久無賴，急雨那能便寢行。", "已問瓊臺雙闕路，此心何必羨層城。"]'),
('f708a51f-145a-40fc-8a19-a6a22fe3b4a8','閑上人覽眾亭','洪适','宋','宋诗','song-poetry','','[]','籃輿行盡白雲層，來款禪居得小亭。',64,'全唐诗/poet.song.123000.json','["籃輿行盡白雲層，來款禪居得小亭。", "亂石引泉歸曲澗，寒風吹雨過中庭。", "四旁野色朝昏別，一覽巖姿遠近青。", "宴坐蒲團作何想，光陰不復問堯蓂。"]'),
('b6e48101-85a5-4292-b0a3-fa1af2e46d1b','賀子忱吏部抱膝庵','洪适','宋','宋诗','song-poetry','','[]','主人蚤歲抽華簪，隱居時作梁父吟。',64,'全唐诗/poet.song.123000.json','["主人蚤歲抽華簪，隱居時作梁父吟。", "于今松窗在人境，空有蕙帳留烟岑。", "風來翠篠自摇玉，秋著黄花仍散金。", "拂拭塵埃記行役，興來命酒還孤斟。"]'),
('b65297cc-4f10-4ccd-a6fa-a5719db39634','桐柏觀','洪适','宋','宋诗','song-poetry','','[]','屹然雙闕峙瓊臺，仰見彤雲郁郁開。',64,'全唐诗/poet.song.123000.json','["屹然雙闕峙瓊臺，仰見彤雲郁郁開。", "三井窮源知海眼，六符垂象應天台。", "松杉滿道欣初過，芝朮何年得自培。", "更聽鳴泉雜風籟，直疑笙鶴紫霄來。"]'),
('fcf378e3-3994-41f2-af7e-9c5f2e1aec85','眾妙臺','洪适','宋','宋诗','song-poetry','','[]','白雲仙蹟紀琅函，三體丹書寶翠嵐。',32,'全唐诗/poet.song.123000.json','["白雲仙蹟紀琅函，三體丹書寶翠嵐。", "欲問仕塗今捷徑，不須高價借終南。"]'),
('5ade48ab-1335-4856-a0e3-9576756f10ba','石道士妙聲堂','洪适','宋','宋诗','song-poetry','','[]','泉溜古今同，臨流萬慮空。',48,'全唐诗/poet.song.123000.json','["泉溜古今同，臨流萬慮空。", "采芝歸絕嶂，添竹映疏叢。", "影漾高秋月，聲宜深夜風。", "真清長在耳，何用撫孤桐。"]'),
('0cca01a2-abdd-4d9e-8248-0a8f77c4146c','仙壇院','洪适','宋','宋诗','song-poetry','','[]','蕉聞王子晉，雲卧夜吹笙。',24,'全唐诗/poet.song.123000.json','["蕉聞王子晉，雲卧夜吹笙。", "控鶴沖天去，松風千古聲。"]'),
('98a0a060-c1fd-4efb-abff-57d193195b7a','天台觀','洪适','宋','宋诗','song-poetry','','[]','芝田環拱碧崔嵬，流瀑高從天際來。',64,'全唐诗/poet.song.123000.json','["芝田環拱碧崔嵬，流瀑高從天際來。", "飛沫有風長是雪，寒聲無日不如雷。", "巖前八桂人誰折，溪畔千桃路未開。", "便覺仙都清晝永，翻愁歸路染黄埃。"]'),
('1f405950-475e-4d4e-b75b-24faa30803b9','劉阮洞','洪适','宋','宋诗','song-poetry','','[]','桃花當日未成蹊，已有幽禽語翠微。',64,'全唐诗/poet.song.123000.json','["桃花當日未成蹊，已有幽禽語翠微。", "楚峽行雲空入夢，秦臺鳴鳳要同飛。", "仙家長若三春好，人境何知萬事非。", "訪問丘園荒舊迹，却應回首悔來歸。"]'),
('5c3afbf6-4850-46f5-9223-0c68f5453d21','贈護國昌老','洪适','宋','宋诗','song-poetry','','[]','緩轡到禪扃，高談得細聽。',48,'全唐诗/poet.song.123000.json','["緩轡到禪扃，高談得細聽。", "茗花泛輕碗，烟篆度虛欞。", "門外雲千片，軒中水一瓶。", "我來無好語，留此待丹青。"]'),
('976c54b1-255b-420f-8fd6-ad069f3a1aaf','慈雲祖老相邀至悠然閣倦不克往','洪适','宋','宋诗','song-poetry','','[]','幾日陟雲烟，危峰懶著鞭。',24,'全唐诗/poet.song.123000.json','["幾日陟雲烟，危峰懶著鞭。", "聊將臨別意，爲我謝悠然。"]'),
('a1665819-6526-4044-ace0-2520792f6bb4','明巖寺','洪适','宋','宋诗','song-poetry','','[]','路轉霞標外，雲開綬带前。',48,'全唐诗/poet.song.123000.json','["路轉霞標外，雲開綬带前。", "幾層山底屋，一線竹間泉。", "洞口石孤聳，巖頭峰倒懸。", "故應風雨際，行子總迴鞭。"]'),
('1b15a188-89b1-4067-816a-80f393b0ea1b','寒巖寺','洪适','宋','宋诗','song-poetry','','[]','峭壁插青冥，層巖覆化城。',48,'全唐诗/poet.song.123000.json','["峭壁插青冥，層巖覆化城。", "空中清磬發，幽處慧燈明。", "萬瓦足雲氣，四簷無雨聲。", "豐干不饒舌，此地孰知名。"]'),
('0c8d72f6-2a3f-494c-823e-652b49f74b7c','寧國寺','洪适','宋','宋诗','song-poetry','','[]','幾日山南北，端期汗漫游。',48,'全唐诗/poet.song.123000.json','["幾日山南北，端期汗漫游。", "水痕秋雨過，竹色曉烟收。", "宦海何時了，僧房爲少留。", "却尋歸去路，餘興謾回眸。"]'),
('a7f102f2-c3b0-4657-b5e9-e5fd10f4c6a9','曉發秦安驛','洪适','宋','宋诗','song-poetry','','[]','秋夢不能曉，起行山徑迷。',48,'全唐诗/poet.song.123000.json','["秋夢不能曉，起行山徑迷。", "小車驚宿鷺，列炬誤鳴雞。", "冷覺霜華重，光瞻斗柄低。", "金庭有佳處，芳桂想幽棲。"]'),
('12fa78dd-027c-4d2f-bdd0-ea0fdaeb6bae','以糟蟹送曾守','洪适','宋','宋诗','song-poetry','','["\u592a\u6e56"]','太湖九月霜波寒，郭索不幸逢漁蠻。',64,'全唐诗/poet.song.123000.json','["太湖九月霜波寒，郭索不幸逢漁蠻。", "誰令骨醉糟丘裏，使我涎流書卷間。", "黄堂丈人思幼玉，耳邊不復親絲竹。", "一杯聊使破愁顔，要遣詩情踵山谷。"]'),
('c53af95e-89cd-4c23-97bc-014becf91f71','得景嚴弟書','洪适','宋','宋诗','song-poetry','','[]','往年同入洛，此日各監州。',48,'全唐诗/poet.song.123000.json','["往年同入洛，此日各監州。", "慣見浮雲改，相思野水流。", "有書將遠意，何處話新愁。", "莫爲癡兒事，乾螢滿案頭。"]'),
('4423b78c-b40c-4432-abe5-54cfe8c391d8','夢中送妙興寺僧','洪适','宋','宋诗','song-poetry','','[]','西望霞光東望雲，劃然晴晦此區分。',32,'全唐诗/poet.song.123000.json','["西望霞光東望雲，劃然晴晦此區分。", "小橋過盡盤龍險，回首高人多謝君。"]'),
('fea66677-6d9e-431a-a9b1-3786c66dfcd1','次韻曾宏父探梅未開','洪适','宋','宋诗','song-poetry','','[]','梅枝渾待雪，山意漸呼風。',48,'全唐诗/poet.song.123000.json','["梅枝渾待雪，山意漸呼風。", "欲索簷間笑，那憂徑外窮。", "英辭窺玉潔，拙句愧雷同。", "只恐花開日，綸言下法宮。"]'),
('e7b1115b-74ce-41f2-852b-22a48ea6d66f','招曾宏父待雪','洪适','宋','宋诗','song-poetry','','[]','欲把詩催雪，先將酒送寒。',48,'全唐诗/poet.song.123000.json','["欲把詩催雪，先將酒送寒。", "凍雲方作意，微霰已開端。", "目斷鄉城遠，心驚歲事闌。", "擬同今日醉，待取玉花看。"]'),
('f7bc5f28-729f-4884-8a86-51d6a76ba849','次韻錢處和運使郡齋晚集','洪适','宋','宋诗','song-poetry','','[]','風聲止雨歲云暮，雪態兼雲晝欲昏。',64,'全唐诗/poet.song.123000.json','["風聲止雨歲云暮，雪態兼雲晝欲昏。", "共喜高軒歸別墅，肯臨畫戟對清樽。", "埋輪前事空豺路，授簡英辭踵兔園。", "是處梅花寢消息，更憑玉藻爲招魂。"]'),
('78399699-fa0c-4ffb-8484-647d438c94b2','遊蓋竹洞','洪适','宋','宋诗','song-poetry','','[]','曉出山城故著鞭，荒荒寒日滿晴川。',64,'全唐诗/poet.song.123000.json','["曉出山城故著鞭，荒荒寒日滿晴川。", "幽棲未卜誅茅地，乘興來登蓋竹天。", "霜凝陰崖疑積雪，雲躋重障雜飛烟。", "洞門今古無關鍵，俗客那能見列仙。"]'),
('d85291c8-712c-40d2-807e-d8fcf31126c5','仙居道中','洪适','宋','宋诗','song-poetry','','[]','雪霙方瑞臘，雨勢欲凋年。',48,'全唐诗/poet.song.123000.json','["雪霙方瑞臘，雨勢欲凋年。", "此日信泥軾，來風侵坐氈。", "爲官渾漫爾，行邑又徒然。", "爲報仙居令，無勞負弩前。"]'),
('8bc6cd5c-d5b7-46ba-a630-7b2d852d465a','寄吳明可正字','洪适','宋','宋诗','song-poetry','','[]','歲晚仍多病，春來尚異鄉。',48,'全唐诗/poet.song.123000.json','["歲晚仍多病，春來尚異鄉。", "愁城誰與破，談壘漫相望。", "體怯山嵐重，心隨驛路長。", "後亭梅若放，爲寄一枝香。"]'),
('2899a130-2490-4aa5-92e5-fca123b50ab6','次韻范子芬雪中同訪曹功顯','洪适','宋','宋诗','song-poetry','','[]','明朝春琯欲飛葭，臘裏重看舞雪斜。',64,'全唐诗/poet.song.123000.json','["明朝春琯欲飛葭，臘裏重看舞雪斜。", "筆下百篇非事業，樽前一醉即生涯。", "初疑高柳狂吹絮，却伴寒梅好放花。", "踏凍不辭方駕遠，閉門留客更誰家。"]'),
('e50290c0-2623-4373-a20b-c42f4b32c555','憶梅呈曾宏父','洪适','宋','宋诗','song-poetry','','[]','重憶東城路，盈盈十里梅。',48,'全唐诗/poet.song.123000.json','["重憶東城路，盈盈十里梅。", "彌旬阻風雪，幾處雜塵埃。", "已是春移律，何時酒泛杯。", "好花那忍落，直待使君來。"]'),
('198f3248-2f3a-46d8-905b-c0ee662ddfde','題王氏秀野堂','洪适','宋','宋诗','song-poetry','','[]','飽聞居處好，遠意快心胸。',48,'全唐诗/poet.song.123000.json','["飽聞居處好，遠意快心胸。", "樹接高低影，山分朝暮容。", "佳時能自適，閑客幾相從。", "勿訝題詩晚，新來百事慵。"]'),
('c4d4bd00-52e8-4048-9cde-43eda8fe7059','除夜懷景嚴弟并寄景盧','洪适','宋','宋诗','song-poetry','','[]','遠鄉勞薄宦，綵服共思親。',48,'全唐诗/poet.song.123000.json','["遠鄉勞薄宦，綵服共思親。", "耿耿胸中事，紛紛眼底塵。", "與誰同別歲，到此兩迎春。", "獨有還家夢，書窗一笑新。"]'),
('8f574fcd-bee5-4fe7-a1e6-1d94029458a8','次韻曾宏父欲賞山宮梅花','洪适','宋','宋诗','song-poetry','','[]','黄堂清興動官梅，遥望花林首屢回。',64,'全唐诗/poet.song.123000.json','["黄堂清興動官梅，遥望花林首屢回。", "命駕許同狂客往，舒牋頻有好詩催。", "空懷月觀橫千影，趁取山宮舉一杯。", "爲語東皇相假借，莫教零亂點蒼苔。"]'),
('696e770a-e3f5-47b4-a18e-459adb301df2','宏父見招賞梅時范子芬欲行','洪适','宋','宋诗','song-poetry','','[]','翩翩畫戟對春光，命客重登千仞岡。',64,'全唐诗/poet.song.123000.json','["翩翩畫戟對春光，命客重登千仞岡。", "坐上行人傾別酒，花前小雨伴啼妝。", "雪膚不爲輕寒瘦，玉骨何如昨夜香。", "麗句競傳新樂府，誰誇何遜在維揚。"]'),
('ee03dab6-70de-4c26-9d6a-f1d49babd0c2','次日宏父携家出遊而小雨新晴','洪适','宋','宋诗','song-poetry','','[]','山頭霞彩發天光，初日曈曨射短岡。',64,'全唐诗/poet.song.123000.json','["山頭霞彩發天光，初日曈曨射短岡。", "莫使吹簫尋古曲，直宜點額作新妝。", "不禁風雨飛來急，頗覺園林減却香。", "花下凌波奏奇舞，腰支尺六笑垂楊。"]'),
('145d0f22-2497-43be-8211-ccfcc8fdd2de','丁卯正月十六日作舞漪亭于池上盡廢蔬畦植花數十本','洪适','宋','宋诗','song-poetry','','[]','二年倥傯緩歸期，漫作新亭接舞漪。',64,'全唐诗/poet.song.123000.json','["二年倥傯緩歸期，漫作新亭接舞漪。", "舉郡定嗤推不去，故山已訝到何遲。", "園官不屬藜莧腹，花史好呈桃李姿。", "待得浮萍是飛絮，誰能愛樹一相思。"]'),
('fc2aa86f-a26a-4101-83d2-1e63d2785111','檢校園花','洪适','宋','宋诗','song-poetry','','[]','往夏新閣成，拔去園中葵。',240,'全唐诗/poet.song.123000.json','["往夏新閣成，拔去園中葵。", "萬花間千蕊，十夫勞徙移。", "羣香頗猗狔，密影初參差。", "烈日吁可畏，時雨不能滋。", "未秋葉先隕，欲冬柯已萎。", "虛蒙灌溉恩，無復嫣然姿。", "啅雀飛且止，不肯登空枝。", "寒螿守枯荄，未忍相棄離。", "永懷斬新日，豈料憔悴期。", "誰呼殷七七，來伴紅裳兒。", "金鼎一劑藥，返魂庸可追。", "春來作高亭，綠沼揚清漪。", "舊蹊類陳迹，遠圃分芳蕤。", "結根旬浹間，生意渾熙熙。", "微白李賦質，小紅桃入肌。", "柳條無顔色，已含烟雨眉。", "遊蜂相召引，有底渠先知。", "地力固自若，大鈞不偏私。", "競秀非機巧，向衰非鈍遲。", "萬物理固然，颺芬須得時。"]'),
('e90b60ea-8e8e-4644-9b0f-27651e209cbc','添竹','洪适','宋','宋诗','song-poetry','','[]','添竹乘春力，期君共歲寒。',48,'全唐诗/poet.song.123000.json','["添竹乘春力，期君共歲寒。", "青青懷特操，碌碌愧麤官。", "尚有哦詩日，尤勝借宅看。", "他時誰檢校，何處報平安。"]'),
('f016bbfc-3952-4875-9212-0000b91f1edb','次韻景思謝送四時纂要并惠乳泉且許見顧  其一','洪适','宋','宋诗','song-poetry','','[]','斷壺食鬰遵時令，蓮芡櫜韜辨土宜。',32,'全唐诗/poet.song.123000.json','["斷壺食鬰遵時令，蓮芡櫜韜辨土宜。", "若解養生供伏臘，自然卜筑數期頤。"]'),
('e07b3fa2-cbb1-4cda-a8ae-0fe3f19aed1c','次韻景思謝送四時纂要并惠乳泉且許見顧  其二','洪适','宋','宋诗','song-poetry','','[]','我無巵茜等通侯，不作多田望蓐收。',32,'全唐诗/poet.song.123000.json','["我無巵茜等通侯，不作多田望蓐收。", "松菊漫成三逕夢，烟蓑已失五湖秋。"]'),
('81d5c23d-408b-420b-a92c-2837a2f2ff1f','次韻景思謝送四時纂要并惠乳泉且許見顧  其三','洪适','宋','宋诗','song-poetry','','[]','青編送似補山房，妙語相酬掩夜光。',32,'全唐诗/poet.song.123000.json','["青編送似補山房，妙語相酬掩夜光。", "盜甕不須睎吏部，將軍何日命元方。"]'),
('7e41e84a-d100-4fa9-a489-67df59a15cd6','送范子芬赴浙東機幕','洪适','宋','宋诗','song-poetry','','[]','男兒三十富春秋，况復才華出輩流。',64,'全唐诗/poet.song.123000.json','["男兒三十富春秋，况復才華出輩流。", "傳家不墜右丞相，入幕少佐東諸侯。", "梅花頗惜詩人去，草色正牽行客愁。", "修禊蘭亭訪陳迹，應懷同醉仲宣樓。"]'),
('6d2ce78a-9495-44be-8491-48717435c271','送季元衡教授赴調','洪适','宋','宋诗','song-poetry','','["\u897f\u6e56"]','三年淹講席，斗酒動離情。',48,'全唐诗/poet.song.123000.json','["三年淹講席，斗酒動離情。", "此去登臺省，諸公熟姓名。", "驊騮看地絕，鸞鳳爲時鳴。", "春日西湖上，煩君一寄聲。"]'),
('e0b3f319-e0a6-495c-99b5-c514b446a674','送石初平歸四明','洪适','宋','宋诗','song-poetry','','[]','析別梁谿七換春，海邊相過意能勤。',64,'全唐诗/poet.song.123000.json','["析別梁谿七換春，海邊相過意能勤。", "袴襦不羨千金子，簡策無慚萬石君。", "豪氣掀雷須給札，他時修月待揮斤。", "鏤衢又揖東風去，情話無人可夜分。"]'),
('8535016d-d7f4-461f-8c87-614f5ab9230f','送李相之提幹閩中十二韻','洪适','宋','宋诗','song-poetry','','[]','官柳訖春事，落絮東復西。',144,'全唐诗/poet.song.123000.json','["官柳訖春事，落絮東復西。", "門外高軒過，行行將何之。", "七閩繡衣屬，非如州縣卑。", "少留長者轍，酌酒語別離。", "五年官他壤，一面即故知。", "辯囿麈仍落，詩壇襟屢題。", "撞鐘問今古，邃然五總龜。", "迢迢千里去，風過衫裳吹。", "我亦及更書，歸耘楚江涯。", "河梁携手歎，參辰後難期。", "曼倩寧自衒，長卿固同時。", "征途慎勿遽，會看軺車馳。"]'),
('56cf53b5-e733-49d0-8b0d-42afc94cb223','題左達功秀才桂香齋','洪适','宋','宋诗','song-poetry','','[]','小齋面蓬瀛，昂霄得雙桂。',96,'全唐诗/poet.song.123000.json','["小齋面蓬瀛，昂霄得雙桂。", "黄卷對聖賢，欣然有餘地。", "筆端妙言語，挾此波瀾勢。", "熒熒百鍊剛，自是青萍器。", "衝星不我識，鉛刀且爭利。", "于今修月手，益振陵雲氣。", "明年廣寒宮，聲名郄詵似。", "歸來八桂鄉，浮丘挹仙袂。"]'),
('6ab04135-6b3b-497c-b40e-4b2923c60c62','還李舉之太平廣記','洪适','宋','宋诗','song-poetry','','[]','稗官九百起虞初，過眼寧論所失誣。',32,'全唐诗/poet.song.123000.json','["稗官九百起虞初，過眼寧論所失誣。", "午枕黑甜君所賜，持還深媿一瓻無。"]'),
('90957279-aec9-47c6-94a0-ab5fa07f3a1e','酬光吉叔用前韻見寄','洪适','宋','宋诗','song-poetry','','[]','怨鶴今誰侶，馴鷗詎可親。',48,'全唐诗/poet.song.123000.json','["怨鶴今誰侶，馴鷗詎可親。", "頗思同淥酒，久已厭紅塵。", "歸夢常通夕，微吟漫惜春。", "床頭易在否，觸手不應新。"]'),
('09055a28-a13d-473a-ac4a-011271296336','次韻蔡瞻明雨中書懷','洪适','宋','宋诗','song-poetry','','[]','梅雨冥冥晴復陰，小軒終日起歸心。',64,'全唐诗/poet.song.123000.json','["梅雨冥冥晴復陰，小軒終日起歸心。", "自憐宦業初何補，獨喜交情久益深。", "憶得微醺看錦瑟，媿無好語比南金。", "青山千里江南路，它日郵籤幸見尋。"]'),
('9b89a997-3b79-4e2d-aec6-46bc78548f6f','贈傳神陳秀才','洪适','宋','宋诗','song-poetry','','[]','舉世人心別，端如面不同。',48,'全唐诗/poet.song.123000.json','["舉世人心別，端如面不同。", "山川險難測，筆墨思何工。", "未索形骸外，聊先阿堵中。", "自憐無骨相，不到漢南宮。"]'),
('bf1177c8-9625-40b6-a7ae-79dcca06bdf1','次韻向憲見贈三首  其一','洪适','宋','宋诗','song-poetry','','[]','理財無管晏，言利析秋豪。',48,'全唐诗/poet.song.123000.json','["理財無管晏，言利析秋豪。", "吐論千人廢，摩空六翮高。", "未簪安世筆，先佩呂虔刀。", "楚澤東風勁，寧辭攬轡勞。"]'),
('6e3ec1ed-4e81-4f19-8133-a601991b0aaa','次韻向憲見贈三首  其二','洪适','宋','宋诗','song-poetry','','[]','四望荒樓觀，登高動土思。',48,'全唐诗/poet.song.123000.json','["四望荒樓觀，登高動土思。", "山川相映带，桃李已紛披。", "漢節人重仰，黄陂世莫窺。", "三章堆錦繡，唐突古西施。"]'),
('f3ae9a94-6ee1-4289-9db0-ebb53e250a2a','次韻向憲見贈三首  其三','洪适','宋','宋诗','song-poetry','','[]','河東空有賦，人不道揚雄。',48,'全唐诗/poet.song.123000.json','["河東空有賦，人不道揚雄。", "貴賤雲泥隔，寅緣井邑同。", "平番依列宿，談笑霽威風。", "終賴帡幪力，能成尺寸功。"]'),
('016c0734-56bf-4eff-ab04-032b1bc57101','次韻向憲道中偶成','洪适','宋','宋诗','song-poetry','','[]','四牡馳原隰，侯邦害必除。',48,'全唐诗/poet.song.123000.json','["四牡馳原隰，侯邦害必除。", "疲民端可念，茅舍未如初。", "消息三春異，創痍二紀餘。", "君王心在遠，諭意倚相如。"]'),
('5d53c881-27c7-42ea-b9da-e103e260194f','聞景嚴弟遷西掖并寄景盧','洪适','宋','宋诗','song-poetry','','[]','俛仰梁谿歲幾寒，向來墨沼已中乾。',64,'全唐诗/poet.song.123000.json','["俛仰梁谿歲幾寒，向來墨沼已中乾。", "傳家紫橐榮三子，得路青雲喜二難。", "爵位方知稽古力，論思當使覆盂安。", "自憐骨相宜塵土，那得絲言動筆端。"]'),
('3b042a5c-8174-46f4-be68-c318f26d8a58','次韻向憲留題荆門惠泉卒章見及','洪适','宋','宋诗','song-poetry','','[]','對泉一洗心如水，誦詩三歎顙有泚。',128,'全唐诗/poet.song.123000.json','["對泉一洗心如水，誦詩三歎顙有泚。", "字比渴驥駸駸來，文如翠瀲鱗鱗起。", "皇華轍迹環諸道，濟物良籌載襟抱。", "雙泉復見等故人，竹馬兒童半羸老。", "吾君豐澤要下流，慚愧長瀾力不侔。", "一方始此一滴潤，千畝長有千鍾收。", "去瘼未盡惠未施，可使剜肉生新痍。", "塵埃滿面語甚惡，虛辱逢人統項斯。"]'),
('b6285506-248f-4416-bc85-da21d2141751','獨步惠泉用石刻中韻','洪适','宋','宋诗','song-poetry','','[]','拂崖看古字，倚策仰前英。',204,'全唐诗/poet.song.123000.json','["拂崖看古字，倚策仰前英。", "雕章細細讀，清思源源生。", "文傳峴山石，句敵渼陂行。", "一字或華衮，五言有長城。", "林蟬眾作噪，下里羞混并。", "坐令蕞爾國，宇內渾知名。", "茲泉發地脈，有玉潜山庭。", "神龍職何護，老蚌呈煌熒。", "楚人力水耨，倚沼仍畦瀛。", "觱沸晝復夜，輸出無窮聲。", "演迤清漢接，旋折數日程。", "膏潤亙原陌，穀價年年平。", "非才忝敷惠，下考乃爲榮。", "疲民未擊壤，循吏難聯橫。", "獨行挹清泚，誰與論丹誠。", "銷憂賴季雅，遣興煩客卿。", "信美非吾土，千古仲宣情。"]'),
('31b87fe4-1b95-4449-ad11-a979a916639b','楊元素題蒙泉詩云源有雌雄分碧白注謂南泉色白爲雌因爲之解嘲二絕句  其一','洪适','宋','宋诗','song-poetry','','[]','小孤寧有匹，織女自無家。',24,'全唐诗/poet.song.123000.json','["小孤寧有匹，織女自無家。", "浪比人間世，增添白玉瑕。"]'),
('8f24b432-8e27-42c0-92bf-ce14b9ab203c','楊元素題蒙泉詩云源有雌雄分碧白注謂南泉色白爲雌因爲之解嘲二絕句  其二','洪适','宋','宋诗','song-poetry','','[]','雄風波不動，雌霓影空垂。',24,'全唐诗/poet.song.123000.json','["雄風波不動，雌霓影空垂。", "欲洗蒙泉謗，須刪蜀客詩。"]'),
('1219eb02-378c-425b-b3e4-39454ff2940f','曲水','洪适','宋','宋诗','song-poetry','','[]','杯去渾無勇退時，偶然遇坎亦安之。',32,'全唐诗/poet.song.123000.json','["杯去渾無勇退時，偶然遇坎亦安之。", "不教坐有獨醒客，便與投醪倒接籬。"]'),
('0d9bfead-5912-4d54-bc42-a37568571923','金蓮','洪适','宋','宋诗','song-poetry','','[]','綠衣黄裏水蒼笄，朝暮凌波步武齊。',32,'全唐诗/poet.song.123000.json','["綠衣黄裏水蒼笄，朝暮凌波步武齊。", "一種清高樂泉石，移根不肯污塗泥。"]'),
('9f348ad0-300d-4419-b45b-35f22f613ead','古柳','洪适','宋','宋诗','song-poetry','','[]','異時古木蔽巖阿，去盜來兵厄斧柯。',32,'全唐诗/poet.song.123000.json','["異時古木蔽巖阿，去盜來兵厄斧柯。", "老柳如龍壽千百，獨全煨燼傲清波。"]'),
('f907057a-0ca6-4ed0-a5ec-2b27f3f99abe','同姚當可胡元質錢舜仁張昭甫遊上泉','洪适','宋','宋诗','song-poetry','','[]','避暑遠簿書，尋幽踏菅蒯。',96,'全唐诗/poet.song.123000.json','["避暑遠簿書，尋幽踏菅蒯。", "寒泉浮玉根，巨石開眼界。", "靈湫幾千年，洗盡塵土礙。", "老藤走長蛇，茂木欹翠蓋。", "掃葉坐水旁，可喜此風快。", "炎雲不能神，潜虬祕奇怪。", "滿酌白玉鍾，嚥甘猶沆瀣。", "何如習家池，舉鞭同倒載。"]'),
('6df48e3d-2b6c-4aa3-980e-58afa17f4f34','次韻朱宣州見寄','洪适','宋','宋诗','song-poetry','','[]','十載蕭蕭麋鹿姿，那知出守得同時。',64,'全唐诗/poet.song.123000.json','["十載蕭蕭麋鹿姿，那知出守得同時。", "黄山白水空孤諷，疊嶂雙溪屬好詩。", "擊柝曉傳邾子國，舉鞭春到習家池。", "只今霖雨思賢佐，會見絲綸下王墀。"]'),
('9c2be682-1f4a-4c5f-be50-067201c96408','謝景高兄惠魚蟹','洪适','宋','宋诗','song-poetry','','[]','霜風激水蟹舍寒，漁火獻俘清夜闌。',128,'全唐诗/poet.song.123000.json','["霜風激水蟹舍寒，漁火獻俘清夜闌。", "不烹五鼎若賒死，使之骨醉尤加餐。", "尺半之魚鱗六六，同入糟丘隨小牘。", "鼎來兼味口流涎，可使盤中食無肉。", "潯陽從事姿南金，高山調古誰知音。", "寧同娵隅作蠻語，生憎郭索多躁心。", "簷頭雪消春有意，洗盞開尊宜一醉。", "持螯頗憶左手同，尺素不妨時遣使。"]'),
('bd16b703-19ff-4cd6-a6d8-5511df1a0052','送唐左史紙墨','洪适','宋','宋诗','song-poetry','','[]','黄山奇峰三十六，聳壑壽松多節目。',128,'全唐诗/poet.song.123000.json','["黄山奇峰三十六，聳壑壽松多節目。", "真工曲突掃芳煤，介圭拱璧陳玄玉。", "淛河千里茲濫觴，萬穀之皮搗冰霜。", "肌理細膩色白皙，蜀網剡藤難雁行。", "使君來自岷峨麓，曾賦客卿朝奏牘。", "細字不作蠅頭書，高文富有牛腰軸。", "向來平步第一螭，勇退宛在番之湄。", "陶泓毛穎幸旅進，快寫元和聖德詩。"]'),
('f2327327-a587-4986-a7e1-54e937f0719b','送李泉','洪适','宋','宋诗','song-poetry','','[]','周人九府有圜法，漢京金布在令甲。',192,'全唐诗/poet.song.123000.json','["周人九府有圜法，漢京金布在令甲。", "炊炭冶鎔多亂真，紛紛輕薄如榆莢。", "即山不復私下臣，張官置吏幾王春。", "君子謂之阿堵物，方兄不知何許人。", "十羊九牧其弊近，談何容易趣銷印。", "事權頓使歸民曹，鼓鑄伊誰察諸郡。", "詔書懇懇修廢官，諸公爭言隃度難。", "向來矯枉亦太過，疇咨英俊乘輶軒。", "鼎新能事推心計，貫朽不須夸古始。", "共瞻使者振繡衣，曾見真人興白水。", "荀卿自有富國篇，高視管蕭宜併肩。", "錢流地上小小爾，便合論思雨露邊。"]'),
('f0d7b0b8-a2e0-4edc-b1b8-b7955f027044','江州塵外亭','洪适','宋','宋诗','song-poetry','','[]','使君人物風塵表，亭下纖埃遠白蘋。',64,'全唐诗/poet.song.123000.json','["使君人物風塵表，亭下纖埃遠白蘋。", "佳傳緬懷方外友，漫郎端是社中人。", "山光水色長排闥，鵠侶鴻儔已卜鄰。", "莫語軟紅車馬客，香鑪峰下有遺民。"]'),
('1fa57e50-cf47-47bc-b273-c049c4c7f754','喜景徐作小圃因懷東閣二絕句  其一','洪适','宋','宋诗','song-poetry','','[]','數頃澄湖練有光，小亭處處得疏篁。',32,'全唐诗/poet.song.123000.json','["數頃澄湖練有光，小亭處處得疏篁。", "夢中春草多佳句，一洗塵埃速寄將。"]'),
('9e3f4d8e-f27e-4c26-ad5b-8241364eebac','喜景徐作小圃因懷東閣二絕句  其二','洪适','宋','宋诗','song-poetry','','[]','白白朱朱手自栽，兩年憶著滿林開。',32,'全唐诗/poet.song.123000.json','["白白朱朱手自栽，兩年憶著滿林開。", "莫教童稚輕攀折，惜取濃陰待我來。"]'),
('395835f8-4c3f-4588-a794-045136b22981','次韻董伯魯','洪适','宋','宋诗','song-poetry','','[]','讀破群書有遠謀，逢時便可動凝旒。',64,'全唐诗/poet.song.123000.json','["讀破群書有遠謀，逢時便可動凝旒。", "不辭巖邑千山險，肯作鈴齋十日留。", "辯舌未容蠡測海，歸心已夢蝶爲周。", "松關萬一逢佳友，爲說相如故倦游。"]'),
('fb6228ce-437f-4808-a074-f836969ec952','端午日應賢小集戲用坐中語','洪适','宋','宋诗','song-poetry','','[]','短檠長憶桂巖東，翰墨新來莫論功。',64,'全唐诗/poet.song.123000.json','["短檠長憶桂巖東，翰墨新來莫論功。", "日日簿書成俗吏，星星鬢髮逼衰翁。", "公祠難緩三人带，小壘聊吟一馬驄。", "共飲昌蒲修故事，山肴野蔌是家風。"]'),
('1bddcabe-f89c-40ca-9d63-977ecb3d859d','次韻黄子餘惠雙井茶二首  其一','洪适','宋','宋诗','song-poetry','','[]','荻花楓葉醉爲鄉，每憶臨分一鼎香。',64,'全唐诗/poet.song.123000.json','["荻花楓葉醉爲鄉，每憶臨分一鼎香。", "枉費光陰驚老大，略無治行媿循良。", "歸心來往雞豚社，清思消磨雁鶩行。", "且喜弦歌餘樂地，好詩句句挾風霜。"]'),
('97c419c8-cd23-4993-81d3-431911b40a05','次韻黄子餘惠雙井茶二首  其二','洪适','宋','宋诗','song-poetry','','[]','峰橫萬仞臨雙井，調護旗槍春怕深。',64,'全唐诗/poet.song.123000.json','["峰橫萬仞臨雙井，調護旗槍春怕深。", "白雪有芽鷹作爪，黄粱無夢蝶何心。", "聞名可信非虛語，知味端如賞好音。", "祇欠谷廉一杯水，末能相就盍朋簪。"]'),
('153e2e09-3343-4e51-b930-1488d4ca98cb','送范至能','洪适','宋','宋诗','song-poetry','','[]','愁雲暗千山，欲雪意未歇。',84,'全唐诗/poet.song.123000.json','["愁雲暗千山，欲雪意未歇。", "雨脚侵夜分，鷁首勇朝發。", "軟紅英俊林，定不冗干謁。", "磊落胸中書，高談傾上笏。", "結駟映天街，登瀛有仙骨。", "摩挲先友碑，姓名或湮沒。", "却顧浮丘亭，寄聲頻日月。"]'),
('1546b064-f2c4-4c03-aaa8-a76a8fbd5de0','次韻王偉文二首  其一','洪适','宋','宋诗','song-poetry','','[]','山城碌碌負魚符，尺五家園好坦途。',64,'全唐诗/poet.song.123000.json','["山城碌碌負魚符，尺五家園好坦途。", "可惜光陰迷簿領，漫無惠露到樵蘇。", "雞豚小社元相接，鷗鷺新盟不敢渝。", "莫話彈冠仍結綬，祇宜襏襫與夫須。"]'),
('737d730f-d82c-41aa-8950-562aabac59e8','次韻王偉文二首  其二','洪适','宋','宋诗','song-poetry','','[]','衒石難夸和氏場，揮犀久避蓋公堂。',64,'全唐诗/poet.song.123000.json','["衒石難夸和氏場，揮犀久避蓋公堂。", "筆端風雨真無敵，紙上寒溫細作行。", "結屋競傳千畝竹，奉祠聊對一爐香。", "朝中環賜無虛月，遥想眉黄已效祥。"]'),
('7368b568-f1a4-4500-8269-de45a9f43aef','次韻程觀過','洪适','宋','宋诗','song-poetry','','[]','山城寂寂簿書稀，梅際春風一夜歸。',64,'全唐诗/poet.song.123000.json','["山城寂寂簿書稀，梅際春風一夜歸。", "忽喜烹魚中有得，恍然揮麈久相違。", "折腰豈愛蘄州竹，問漢須尋織女機。", "奇絕黄山待佳句，何時小雨濕征衣。"]'),
('1a3d2104-99d2-4d88-b6f6-5b04743359bb','和州','洪适','宋','宋诗','song-poetry','','[]','嘆息和州事，腥羶未易除。',48,'全唐诗/poet.song.123000.json','["嘆息和州事，腥羶未易除。", "驚濤飲胡馬，壯士葬江魚。", "列戍俱奔命，斯民不奠居。", "元戎猶擁鉞，資斧定何如。"]'),
('c2b3dc99-eeea-4aba-afa6-88fbf733a862','三將','洪适','宋','宋诗','song-poetry','','[]','鼎立淮南將，胡來競退師。',48,'全唐诗/poet.song.123000.json','["鼎立淮南將，胡來競退師。", "折衝潜白羽，告捷鬧黄旗。", "已報瓜洲敗，還驚采石危。", "邊防恃天塹，百萬豈熊羆。"]'),
('575834f3-c2a2-4f8f-86b4-26193489ab86','胡虜','洪适','宋','宋诗','song-poetry','','[]','胡虜猖狂甚，妖星近日畿。',48,'全唐诗/poet.song.123000.json','["胡虜猖狂甚，妖星近日畿。", "俄聞佛狸死，不得帝羓歸。", "虎旅空增竈，狼狐爲解圍。", "人人說恢復，進退在投機。"]'),
('1abd492d-c9c6-48f9-bc98-f68a441164e5','詹氏仁壽軒','洪适','宋','宋诗','song-poetry','','[]','修竹林林貫四時，厖眉扶杖到期頤。',32,'全唐诗/poet.song.123000.json','["修竹林林貫四時，厖眉扶杖到期頤。", "子孫長憶當年事，留取軒楹客賦詩。"]'),
('a07882a1-323e-4ce9-af35-6defa3720d5b','道中懷景盧','洪适','宋','宋诗','song-poetry','','[]','宦路多睽別，春游隔弟兄。',48,'全唐诗/poet.song.123000.json','["宦路多睽別，春游隔弟兄。", "頻年再登陛，十日又離京。", "吏責倉臺少，官曹省闥清。", "床頭何夕月，冷話聽殘更。"]'),
('7ba604a1-3139-441f-ba3b-cda18cc63eee','闡陽驛二絕句  其一','洪适','宋','宋诗','song-poetry','','[]','略略春晴天亦慳，雷驚雨作轉頭間。',32,'全唐诗/poet.song.123000.json','["略略春晴天亦慳，雷驚雨作轉頭間。", "浮雲又逐東風起，不見前山出髻鬟。"]'),
('d1b603d3-c2a0-4bf9-9a62-612136922e6f','闡陽驛二絕句  其二','洪适','宋','宋诗','song-poetry','','[]','觸石泉聲高下聞，曾將兩耳洗埃塵。',32,'全唐诗/poet.song.123000.json','["觸石泉聲高下聞，曾將兩耳洗埃塵。", "相逢尊酒今誰侶，細草青花是故人。"]'),
('6cd9a871-500b-45a0-92c8-bc9a9f21fe6b','次韻范守翠微亭','洪适','宋','宋诗','song-poetry','','[]','带郭長堤十里春，是中佳處外風塵。',64,'全唐诗/poet.song.123000.json','["带郭長堤十里春，是中佳處外風塵。", "層層危磴渾依舊，一一高亭已斬新。", "領略江山初縱目，剪除荆棘不勞神。", "携壺一笑須投隙，官事何時可脫身。"]'),
('a6ac5a41-9ff0-4bc0-b0ca-a7a7f5fbf70a','次韻施德初遊齊山','洪适','宋','宋诗','song-poetry','','[]','詩塵誰復數齊梁，小杜文章楚大邦。',64,'全唐诗/poet.song.123000.json','["詩塵誰復數齊梁，小杜文章楚大邦。", "曾爲黄花酬九日，至今陳迹擅三江。", "新亭高下依喬木，遠岫參差進曲窗。", "著屐與君時茗飲，後車何必酒盈缸。"]'),
('f7b9fff4-fbd0-4a4a-b17b-db664eefcdfd','再賦','洪适','宋','宋诗','song-poetry','','[]','向來胡馬遠跳梁，奔命紛紛不一邦。',64,'全唐诗/poet.song.123000.json','["向來胡馬遠跳梁，奔命紛紛不一邦。", "景物何期新劚壑，夢魂猶自怯防江。", "看山小隱紅蓮幙，批敕須臨青瑣窗。", "無事肯來文字飲，爲將紅酒倒鵝缸。"]'),
('ac2fbea6-5ee1-4459-9895-1ff2dc1a5721','喻江寧欲遺蘄笛辭之','洪适','宋','宋诗','song-poetry','','[]','蘄州美竹今古名，白雲吹裂笛一聲。',64,'全唐诗/poet.song.123000.json','["蘄州美竹今古名，白雲吹裂笛一聲。", "臞儒所對筆墨客，長物虛尋疏比僧。", "還君不用君莫怪，綺窗辦得千金買。", "誰與移根到草堂，它日風來聽天籟。"]'),
('9a2f918b-023a-4bb3-9f39-995272f8e7d3','烈士','洪适','宋','宋诗','song-poetry','','[]','烈士死知己，交情重同心。',48,'全唐诗/poet.song.123000.json','["烈士死知己，交情重同心。", "反眼如不識，怨深恩更深。", "憶昔邂逅初，一諾百黄金。", "口血顧未乾，舊盟何許尋。"]'),
('9ba8e57e-fe2c-47a1-99bc-35de4cfff879','景盧自右史假北門出疆再用前韻','洪适','宋','宋诗','song-poetry','','[]','漢節螭坳出，青氈映父兄。',48,'全唐诗/poet.song.123000.json','["漢節螭坳出，青氈映父兄。", "天方摧醜虜，人已望神京。", "使指今茲重，邊塵定可清。", "歸來陳口伐，蓮燭問嚴更。"]'),
('5ecf586a-db0d-4395-8e80-d697142917a1','聞應賢景高文特少張景孫同客景盧官舍','洪适','宋','宋诗','song-poetry','','[]','使回親舊集，虎穴問穹廬。',48,'全唐诗/poet.song.123000.json','["使回親舊集，虎穴問穹廬。", "半夜櫪喧馬，高秋盤進魚。", "真成聚東井，誰復話南徐。", "底事桃源客，新來書也疏。"]'),
('84109206-81bc-4bef-9fb0-69cdcae1eda5','左舉善求草堂詩','洪适','宋','宋诗','song-poetry','','[]','孤山佳處著茅廬，飽看雲烟自卷舒。',32,'全唐诗/poet.song.123000.json','["孤山佳處著茅廬，飽看雲烟自卷舒。", "莫向淮南戀戎幕，松關恐有絕交書。"]'),
('58ad3023-9e33-4f22-b4b5-c0049eaa423b','次韻景裴贊喜農扈之除','洪适','宋','宋诗','song-poetry','','[]','北固金焦顧眄中，裴回於此再踰冬。',64,'全唐诗/poet.song.123000.json','["北固金焦顧眄中，裴回於此再踰冬。", "徒勞金穀供諸將，未有田園問老農。", "且喜邊亭罷歐脫，不須水戰習蒙衝。", "九卿已媿班行忝，敢向明時歎不逢。"]'),
('6aef4979-6298-4bef-85dd-c3e20183b3e8','答木縕之用前韻見寄','洪适','宋','宋诗','song-poetry','','[]','魁星秀句挾東風，便覺陽春變盛冬。',64,'全唐诗/poet.song.123000.json','["魁星秀句挾東風，便覺陽春變盛冬。", "媿我供軍儕絳灌，羨君汲古到羲農。", "北鄰再講衣裳會，京口今爲冠蓋衝。", "已具扁舟勇歸去，粲花清論度難逢。"]'),
('75d69ed5-4648-466f-b8a4-3d42bca76d58','得江樓','洪适','宋','宋诗','song-poetry','','[]','官事何時了，憑高思豁然。',48,'全唐诗/poet.song.123000.json','["官事何時了，憑高思豁然。", "逐江開北戶，望岫頓修椽。", "繁卉渾相亞，新篁便可憐。", "歸心入春夢，已遶故山前。"]'),
('20ccbd71-d815-4649-9147-90a0bcda9e81','花信亭','洪适','宋','宋诗','song-poetry','','[]','解報花消息，江邊有好風。',48,'全唐诗/poet.song.123000.json','["解報花消息，江邊有好風。", "吹香四時別，問訊幾人同。", "梅塢難藏白，桃蹊豈借紅。", "但能長檢校，定不酒尊空。"]'),
('fa2ba5bc-cfba-4ba9-a44c-3c418f33e539','小雨同裴弟深甫堅上人登新亭次韻','洪适','宋','宋诗','song-poetry','','[]','移梅種竹趁陽春，舉目江山發興新。',64,'全唐诗/poet.song.123000.json','["移梅種竹趁陽春，舉目江山發興新。", "曲檻疏窗那草草，飛簷碧瓦已鱗鱗。", "鼎來好語酬佳景，更有高僧話凈因。", "步屧躊躇烏亦喜，不嫌風雨墊冠巾。"]'),
('872806f6-9fd4-49ff-851b-e52b0af42bdb','春雪再作戲成絕句','洪适','宋','宋诗','song-poetry','','[]','常年窮臘無一白，盈尺冬來已屢書。',32,'全唐诗/poet.song.123000.json','["常年窮臘無一白，盈尺冬來已屢書。", "底事天公太手熟，又同春絮到階除。"]'),
('32724738-b47a-4db6-8e6f-b40c4a089af9','寄題陳阜卿總秀堂','洪适','宋','宋诗','song-poetry','','[]','佳麗并包地，曼花子夜香。',48,'全唐诗/poet.song.123000.json','["佳麗并包地，曼花子夜香。", "望中團野色，塵外發天光。", "小隊高牙駐，輕裘清嘯長。", "故應堂上燕，相與賀雕梁。"]'),
('0124d850-3c80-4993-827d-676dea6e7001','使虜道中次韻會亭','洪适','宋','宋诗','song-poetry','','[]','平野風烟闊，孤村父老存。',48,'全唐诗/poet.song.123000.json','["平野風烟闊，孤村父老存。", "薄雲低故堞，落日逐輶軒。", "分裂時云久，澄清敵未吞。", "春光滿花柳，天道竟何言。"]'),
('74775c49-b704-43c1-b7d1-35ba3ea41fbb','過穀熟','洪适','宋','宋诗','song-poetry','','[]','玉帛齊盟亦可尋，東風著面客塵侵。',64,'全唐诗/poet.song.123000.json','["玉帛齊盟亦可尋，東風著面客塵侵。", "隋堤望遠人烟少，汴水流乾轍迹深。", "桃李不言應感舊，山川無主祇傷今。", "遺民久厭腥羶苦，辟國謀乖負此心。"]'),
('e3c18d14-2dbd-4411-b856-17230f8b363d','次韻馬上偶成','洪适','宋','宋诗','song-poetry','','[]','天遣祥風掃塞氛，越疆軺傳禮儀新。',64,'全唐诗/poet.song.123000.json','["天遣祥風掃塞氛，越疆軺傳禮儀新。", "禦戎可鑒秦無策，覘國誰夸鄭有人。", "鳴鶴九臯聞徹響，翔龍千載仰攀鱗。", "垂鞭日日陪清話，談笑成章泣鬼神。"]'),
('f1e1915a-f039-44b0-b531-3f4dac914cf0','次韻車中倦吟二首  其一','洪适','宋','宋诗','song-poetry','','[]','舊國于今作兩家，鄰翁有酒不能賒。',32,'全唐诗/poet.song.123000.json','["舊國于今作兩家，鄰翁有酒不能賒。", "明朝又逐歸鴻去，祇有塵埃滿一車。"]'),
('4d63a989-0f92-40d1-8851-669820678e99','次韻車中倦吟二首  其二','洪适','宋','宋诗','song-poetry','','[]','叱馭寧辭歷險難，投戈且幸邇遐安。',32,'全唐诗/poet.song.123000.json','["叱馭寧辭歷險難，投戈且幸邇遐安。", "氈車軒簸長危坐，恰似舟行八節灘。"]'),
('37abe144-3ab6-4d68-a7de-b755459044f5','次韻初入東京二首  其一','洪适','宋','宋诗','song-poetry','','[]','乾坤正欲稔天驕，會見降胡款聖朝。',32,'全唐诗/poet.song.123000.json','["乾坤正欲稔天驕，會見降胡款聖朝。", "蓄銳乘機先自治，莫令武庫五兵銷。"]'),
('210cf377-0fa7-46ce-806e-7bc88ae4d0da','次韻初入東京二首  其二','洪适','宋','宋诗','song-poetry','','[]','五門雙闕未央城，碧瓦朱甍雲霧生。',32,'全唐诗/poet.song.123000.json','["五門雙闕未央城，碧瓦朱甍雲霧生。", "真主南巡正嘗膽，從今瞻仰泰階平。"]'),
('590200a5-607e-4b39-acdb-d46123b4a711','過黄河用上介龍深甫遷居舊韻','洪适','宋','宋诗','song-poetry','','[]','風埃如霧滿川黄，馬上朝來識太行。',64,'全唐诗/poet.song.123000.json','["風埃如霧滿川黄，馬上朝來識太行。", "水瀉濁河橋甚壯，沙連遠塞路何長。", "皇華復講衣裳會，京闕今爲氈罽鄉。", "夾道桑麻過千畝，野花時有一枝香。"]'),
('885c42db-998b-40a0-8588-8b086009c5b6','絕句','洪适','宋','宋诗','song-poetry','','[]','宣防瓠子撓西京，向者河堤役不寧。',32,'全唐诗/poet.song.123000.json','["宣防瓠子撓西京，向者河堤役不寧。", "胡虜任教流就下，始知談舌誤朝廷。"]'),
('e404caee-8236-4a80-8eec-85827caab7f6','次韻北使邀觀常豐湖','洪适','宋','宋诗','song-poetry','','[]','一派澄湖何處來，鳴桹漁子聚還開。',32,'全唐诗/poet.song.123000.json','["一派澄湖何處來，鳴桹漁子聚還開。", "主人甚顧他鄉客，莫使歸途欠一杯。"]'),
('f07d04af-e3f9-4acd-9d15-184cea2b50d1','次韻初望太行山','洪适','宋','宋诗','song-poetry','','[]','曾巒逾碣石，形勝鎮神州。',48,'全唐诗/poet.song.123000.json','["曾巒逾碣石，形勝鎮神州。", "可惜羊腸險，今包鼠穴羞。", "天心端有待，人力豈能謀。", "未老如憑軾，壺漿爲曲留。"]'),
('b2d290bb-b0ce-4b12-943c-c148b3838835','次韻伊洛道中','洪适','宋','宋诗','song-poetry','','[]','萬里修鄰好，氈裘不亂羣。',48,'全唐诗/poet.song.123000.json','["萬里修鄰好，氈裘不亂羣。", "邊鋒方兩解，春事已平分。", "發軔雞三唱，揮毫酒半醺。", "問途殊未已，返顧羨歸雲。"]'),
('907e4dab-8932-4eb8-9c6d-c4a79ce8c5a7','次韻湯陰寒食遇雨','洪适','宋','宋诗','song-poetry','','[]','殊方遇寒食，節物負年華。',48,'全唐诗/poet.song.123000.json','["殊方遇寒食，節物負年華。", "小雨偏宜柳，輕風未落花。", "見餳如隔嶺，對月共忘家。", "俗重之推廟，誰祠萬里沙。"]'),
('e25ffcfc-7872-41db-91e2-80afc12ff2ee','次韻講武城','洪适','宋','宋诗','song-poetry','','[]','漢鼎三分霸業成，并吞猶未戒佳兵。',64,'全唐诗/poet.song.123000.json','["漢鼎三分霸業成，并吞猶未戒佳兵。", "故城四壁存陳迹，荒冢千年斷樂聲。", "何必枕戈防詭計，豈容橫槊竊詩名。", "我來弔古停車轍，壟上農人也輟耕。"]'),
('e9941cb1-6329-4707-a413-0922d1f7b741','次韻趙州石橋','洪适','宋','宋诗','song-poetry','','[]','訪古汶河上，聊忘道路勞。',48,'全唐诗/poet.song.123000.json','["訪古汶河上，聊忘道路勞。", "仙蹤嘗策蹇，海怪或鎸鼇。", "濟遠徒杠小，憑虛亂石牢。", "何時冠蓋集，一變犬羊臊。"]'),
('77efd388-c7de-440a-bfb2-e58436f7693f','過中山','洪适','宋','宋诗','song-poetry','','[]','三關標重鎮，自昔護邊陲。',48,'全唐诗/poet.song.123000.json','["三關標重鎮，自昔護邊陲。", "觀者堵牆立，紛然簾幕垂。", "欲謀千日醉，恐誤十旬期。", "可喜中庭月，何妨盡一巵。"]'),
('4f3ea91c-6fcb-4a91-84c4-186f6a9bb167','過保州','洪适','宋','宋诗','song-poetry','','[]','藝祖枌榆社，唐人保塞軍。',48,'全唐诗/poet.song.123000.json','["藝祖枌榆社，唐人保塞軍。", "百年鄰毳幕，今日聚妖氛。", "故老垂黄髮，妍姬艷綵裙。", "白溝才一舍，何計可中分。"]'),
('1c62e863-9bf2-47ef-a487-74701cbcaaa4','次韻早行','洪适','宋','宋诗','song-poetry','','[]','夙駕星光動，徐行霧氣迷。',48,'全唐诗/poet.song.123000.json','["夙駕星光動，徐行霧氣迷。", "塞鴻翻月去，胡馬向風嘶。", "柝靜譙門曉，輪欹沙路低。", "頗思眠蕙帳，枕上聽鄰雞。"]'),
('f63a3dde-764c-4766-995c-86e2303c5150','次韻得保州老張瓦研','洪适','宋','宋诗','song-poetry','','[]','毛穎傳既成，陶泓名不朽。',120,'全唐诗/poet.song.123000.json','["毛穎傳既成，陶泓名不朽。", "陳楮接武來，論交篇籍囿。", "千年銅雀臺，瓦解淪坤厚。", "何人澄其泥，頗能髣髴否。", "龍公天上客，金蘭幸同臭。", "結束萬里行，聯翩五旬久。", "清談落玉麈，痛飲盡金斗。", "咳唾珠璣粲，揮翰不停手。", "窮邊得佳研，可出老呂右。", "瓦缶莫雷鳴，龍尾羞牛後。"]'),
('c4f12940-79cc-4510-891e-88868ade4dac','次韻保州聞角  其一','洪适','宋','宋诗','song-poetry','','[]','覺來屈指數修程，歷遍中原長短亭。',32,'全唐诗/poet.song.123000.json','["覺來屈指數修程，歷遍中原長短亭。", "誰向城頭曉鳴角，胡音嘈囋不須聽。"]'),
('4f15e27f-cdd2-43d4-9b6d-952735d118bd','次韻保州聞角  其二','洪适','宋','宋诗','song-poetry','','[]','胡音嘈囋不須聽，整頓征衫待啟明。',32,'全唐诗/poet.song.123000.json','["胡音嘈囋不須聽，整頓征衫待啟明。", "已把哀笳變清角，可傷任昧雜韶英。"]'),
('0d5938e8-19be-4ba0-9c3d-5d19e490c17e','次韻梁門','洪适','宋','宋诗','song-poetry','','[]','雙壘依然柳作陰，故疆行盡倍傷心。',32,'全唐诗/poet.song.123000.json','["雙壘依然柳作陰，故疆行盡倍傷心。", "時平且得無爭戰，苔上戈槍卧綠沈。"]'),
('b61f1dc2-9a34-41f7-a904-3903b42a7278','次韻白溝河','洪适','宋','宋诗','song-poetry','','[]','唐餘畫壤媿鴻溝，西閉關門漢道柔。',32,'全唐诗/poet.song.123000.json','["唐餘畫壤媿鴻溝，西閉關門漢道柔。", "一自旄頭入京洛，至今泉水不東流。"]'),
('473a6651-b3f7-402c-a2c0-76066d0ffec7','次韻回程至涿鹿','洪适','宋','宋诗','song-poetry','','[]','回首燕然日再西，一杯相屬使軺歸。',64,'全唐诗/poet.song.123000.json','["回首燕然日再西，一杯相屬使軺歸。", "殘花媚野不妨好，倦鳥投林自在飛。", "可惜光陰銷客枕，不嫌塵土染征衣。", "大明退直清和日，已約梯雲訪翠微。"]'),
('7bf1755a-a5f7-469e-b77c-15f16899adc2','燕館日膳得四雁籠之以歸','洪适','宋','宋诗','song-poetry','','[]','提携乘雁脫庖丁，等待他年羽翼成。',32,'全唐诗/poet.song.123000.json','["提携乘雁脫庖丁，等待他年羽翼成。", "唳月摩雲須有便，莫教更作不能鳴。"]'),
('23f03b16-5ec2-4270-bcd5-2791ccb918b4','次韻楊花二首  其一','洪适','宋','宋诗','song-poetry','','[]','桃花開落不同時，燕子銜泥相伴飛。',32,'全唐诗/poet.song.123000.json','["桃花開落不同時，燕子銜泥相伴飛。", "若向章臺問春色，可無清淚濕征衣。"]'),
('ae797c43-7f9d-48bd-92d9-1bfab4aa9d99','次韻楊花二首  其二','洪适','宋','宋诗','song-poetry','','[]','官路風輕落絮迷，望中高下雜游絲。',32,'全唐诗/poet.song.123000.json','["官路風輕落絮迷，望中高下雜游絲。", "糝氈擬雪春無際，只有騷人聖得知。"]'),
('0f60963f-f1b0-4415-84ab-ba466ca5b7c6','再至保州','洪适','宋','宋诗','song-poetry','','[]','再入中原境，相迎有暮鴉。',48,'全唐诗/poet.song.123000.json','["再入中原境，相迎有暮鴉。", "柔桑新迸葉，高柳細吹花。", "短幘人如禿，尖冠女不髽。", "指期淮可渡，寧歎在天涯。"]'),
('c593569b-7e21-41ea-a009-69e8c1341ddf','次韻再至中山','洪适','宋','宋诗','song-poetry','','[]','路指中山國，人歸析木津。',48,'全唐诗/poet.song.123000.json','["路指中山國，人歸析木津。", "終風震簷瓦，細雨壓車塵。", "落紙詩章速，開尊酒力醇。", "無功慚報國，來往謾勞人。"]'),
('cc44c40f-ee2d-473a-a200-dd2daa0fb5f5','次韻中山雨後','洪适','宋','宋诗','song-poetry','','[]','好雨連宵鳩喚晴，曉行襟袂有餘清。',64,'全唐诗/poet.song.123000.json','["好雨連宵鳩喚晴，曉行襟袂有餘清。", "遠遊朔塞殊風景，夢到東阡看火耕。", "紅退桃蹊三月晚，綠添麥垅一川平。", "纖塵不逐車輪起，喜聽驅驢叱馬聲。"]'),
('d20cb355-65d2-417e-a278-a424dcaff411','次韻村店得牡丹','洪适','宋','宋诗','song-poetry','','[]','花品稱王擅洛京，朱朱白白莫齊名。',32,'全唐诗/poet.song.123000.json','["花品稱王擅洛京，朱朱白白莫齊名。", "相逢河朔春將暮，半吐檀心若有情。"]'),
('b99398e9-beae-4c72-95fe-94ee8f02db3f','次韻陳留聞鶯','洪适','宋','宋诗','song-poetry','','[]','恰恰啼鶯馬上聽，凝雲欲雨曉寒輕。',32,'全唐诗/poet.song.123000.json','["恰恰啼鶯馬上聽，凝雲欲雨曉寒輕。", "滿郊碧草皆春色，祇欠山光與水聲。"]'),
('5d0dd255-9d4e-41b7-8c05-83689970f05d','次韻寧陵憩驛','洪适','宋','宋诗','song-poetry','','[]','野外人聲寂，林間鳥羽翻。',48,'全唐诗/poet.song.123000.json','["野外人聲寂，林間鳥羽翻。", "朱櫻喜堆案，青杏助開尊。", "故國多荒草，遺黎有怨言。", "雨餘塵土靜，不復污歸軒。"]'),
('2c6ccd9c-2919-427a-99b0-ccc8763d9e3b','次韻南京道中','洪适','宋','宋诗','song-poetry','','["\u897f\u6e56"]','密葉成陰行路寬，鳩鳴鶯囀足開顔。',64,'全唐诗/poet.song.123000.json','["密葉成陰行路寬，鳩鳴鶯囀足開顔。", "半塗泥滑夜來雨，數片雲飛何處山。", "薄暮每尋樽俎共，殘春能伴節旄還。", "塵襟好濯西湖水，偷取禪房一日閑。"]'),
('fcc11ae4-db8f-4f85-b894-ae502285c560','次韻遊臞菴不果','洪适','宋','宋诗','song-poetry','','[]','水紋如縠送歸船，漸近觚稜尺五天。',64,'全唐诗/poet.song.123000.json','["水紋如縠送歸船，漸近觚稜尺五天。", "適意蓴鱸公有興，尋盟鷗鳥我無緣。", "遠懷並轡穿紅皺，近阻携筇款碧鮮。", "却待湖山最高處，醉中一笑挹臞仙。"]'),
('81b42d59-03a8-4804-a7d8-32ba32a8c1ce','寄別景盧','洪适','宋','宋诗','song-poetry','','[]','禹穴遺書不可尋，坐看綠葉再成林。',64,'全唐诗/poet.song.123000.json','["禹穴遺書不可尋，坐看綠葉再成林。", "千巖競秀非吾土，三徑就荒勞我心。", "誰是周人思召伯，今無老叟出山陰。", "台階穩上添花萼，時倩來鴻續好音。"]'),
('98d6212b-0ae7-404c-a147-f685d55387ad','藍憲遣人往吳門移洛花未至而去  其一','洪适','宋','宋诗','song-poetry','','[]','雒京隔絕花難得，茂苑移將信已通。',32,'全唐诗/poet.song.123000.json','["雒京隔絕花難得，茂苑移將信已通。", "世事好乖猶獻鵠，雕欄不用怨東風。"]'),
('97f32c0a-79e8-48b0-81f8-44c07927bbad','藍憲遣人往吳門移洛花未至而去  其二','洪适','宋','宋诗','song-poetry','','[]','新壇巧斲列東西，准擬看花倒接籬。',32,'全唐诗/poet.song.123000.json','["新壇巧斲列東西，准擬看花倒接籬。", "交臂失之端可笑，儻來外物盡難期。"]'),
('e6116287-1bcb-47cf-95dc-30f7c32a68cd','藍憲遣人往吳門移洛花未至而去  其三','洪适','宋','宋诗','song-poetry','','[]','三春桃李家家有，不費陽和特地恩。',32,'全唐诗/poet.song.123000.json','["三春桃李家家有，不費陽和特地恩。", "名品異芳天亦靳，未教容易到丘園。"]'),
('9f8d2d09-b64e-451f-a74f-821ff1af4f89','登芝榭見景盧所增月臺','洪适','宋','宋诗','song-poetry','','[]','臺榭相望聞語聲，茹芝觀月有餘清。',64,'全唐诗/poet.song.123000.json','["臺榭相望聞語聲，茹芝觀月有餘清。", "旁連小隱分三徑，細數修篁限一城。", "日日杖頭思徑醉，年年鐺脚玩欣榮。", "誰人知我歸歟樂，趁此登臨未憚行。"]'),
('c78a470e-d058-4f83-94e0-978177d2fc6f','許倩報白榴已得玉茗未諧以詩趣之','洪适','宋','宋诗','song-poetry','','[]','萬里移根安石國，何年傅粉未知名。',64,'全唐诗/poet.song.123000.json','["萬里移根安石國，何年傅粉未知名。", "須邀玉茗來巖壑，便結瓊花作弟兄。", "詩客定疑天外得，園人已辦臘前迎。", "東家阿措休相妬，不學穠粧照眼明。"]'),
('d24735e0-52f4-4081-8099-e4d58b56430d','次韻景盧喜得安州牡丹','洪适','宋','宋诗','song-poetry','','[]','洛中花信已沉聲，涇渭寧分濁與清。',64,'全唐诗/poet.song.123000.json','["洛中花信已沉聲，涇渭寧分濁與清。", "近出黟山空接壤，遠來安陸比連城。", "虛壇僅免遊人問，浪蘂從教著處榮。", "更欲丁寧新芍藥，莫誇多少便橫行。"]'),
('5e2be766-d467-4b95-bac7-5d46e08664b1','次韻景盧野處解嘲之什','洪适','宋','宋诗','song-poetry','','[]','地偏不接市廛聲，古木參天鶴唳清。',64,'全唐诗/poet.song.123000.json','["地偏不接市廛聲，古木參天鶴唳清。", "臺榭迥窮千里目，詩章突過五言城。", "花移瓊樹真無敵，酒換金貂未足榮。", "燈火歸時笙管作，解嘲何事有歌行。"]'),
('d1a77ac7-3fed-4881-b37a-7c6dbd905b14','再賦','洪适','宋','宋诗','song-poetry','','[]','幽壑藏雲水作聲，紉蘭入室好風清。',64,'全唐诗/poet.song.123000.json','["幽壑藏雲水作聲，紉蘭入室好風清。", "高蜚便有縹縹意，進筑如開蕩蕩城。", "百尺樓成同日涉，四時花發匪朝榮。", "園池如許誰言小，但放芻蕘雉兔行。"]'),
('750ac902-cb66-40a6-89cf-1cae687f7727','酬景盧賦圃中種橘移花','洪适','宋','宋诗','song-poetry','','[]','甕頭玉友已銷聲，小試山齋百末清。',64,'全唐诗/poet.song.123000.json','["甕頭玉友已銷聲，小試山齋百末清。", "十客對花休避席，千奴呼橘擬專城。", "微霜到處葉未落，小雨移來根易榮。", "情話團欒亦終日，坐中惟欠十般行。"]'),
('648287a3-3e9b-47c9-a082-5ce4fdbda6a7','酬景盧謝菊','洪适','宋','宋诗','song-poetry','','[]','涉秋無復滴階聲，夜雨隨風塵已清。',64,'全唐诗/poet.song.123000.json','["涉秋無復滴階聲，夜雨隨風塵已清。", "平日愛山營一壑，老來學圃列三城。", "園夫種樹元無術，籬菊分叢獨晚榮。", "躡屐問花兼問柳，不須乘毳可泥行。"]'),
('469cf431-34a4-42f5-9c1c-f9b30165909f','答景盧','洪适','宋','宋诗','song-poetry','','[]','雁翅齊飛有雋聲，文章何止賦華清。',64,'全唐诗/poet.song.123000.json','["雁翅齊飛有雋聲，文章何止賦華清。", "誰教短策長尋壑，不擁高牙且典城。", "臺省向來非獨冷，身名此日已俱榮。", "盈旬詩軸牛腰大，抱牘須同饕虱行。"]'),
('1d8d5c6f-5801-45fb-9b1a-cf25e9858c93','病酒','洪适','宋','宋诗','song-poetry','','[]','三日惟聞煮藥聲，一中可怕聖之清。',64,'全唐诗/poet.song.123000.json','["三日惟聞煮藥聲，一中可怕聖之清。", "移花種竹已得地，逢酒當歌須閉城。", "遠避霜風嚴北戶，靜看朝日滿東榮。", "雙螯退步輸年少，誰與抽琴作蟹行。"]'),
('4cc2aed9-7bfd-4907-8161-41b709dfb65f','答景嚴','洪适','宋','宋诗','song-poetry','','[]','向來戎馬沸邊聲，曾出良籌助掃清。',64,'全唐诗/poet.song.123000.json','["向來戎馬沸邊聲，曾出良籌助掃清。", "六載倦游潜楚澤，一枝同折記欒城。", "北門西府仍班綴，後雁前鴻媿寵榮。", "兩鬢星星吾老矣，看君重上赤墀行。"]'),
('5a5f481d-6112-4af1-a128-406342452592','景嚴送冬杏','洪适','宋','宋诗','song-poetry','','[]','蒼頭呼夢雜雞聲，蘂杏詩來句轉清。',64,'全唐诗/poet.song.123000.json','["蒼頭呼夢雜雞聲，蘂杏詩來句轉清。", "獨傲風霜愛冬日，不隨桃李媚花城。", "一枝得得能相對，凡卉紛紛孰並榮。", "大隊開時春且盡，醉吟當續麗人行。"]'),
('9792540e-c9de-4778-a1f5-4515a0415fef','景盧送瑞香','洪适','宋','宋诗','song-poetry','','[]','翠幄藏春巧寄聲，熏籠織錦曉天清。',64,'全唐诗/poet.song.123000.json','["翠幄藏春巧寄聲，熏籠織錦曉天清。", "幽香端是花中瑞，仙派初來塵外城。", "酒海何妨三雅進，鬢雲誰稱一枝榮。", "雨來頓使鄰牆遠，不到闌干深處行。"]'),
('78f7c094-ece0-4ae3-a721-3f84ac65f872','野處有詩羨山居小隱之廣而有拓地不可之歎','洪适','宋','宋诗','song-poetry','','[]','敗葉翻風策策聲，山根可掬石泉清。',64,'全唐诗/poet.song.123000.json','["敗葉翻風策策聲，山根可掬石泉清。", "東鄰美荈久成塢，北陌新柑小筑城。", "臺在家邊來更好，地連郭外得非榮。", "曾樓縱目無窮景，安用垂涎杖屨行。"]'),
('b6705063-2d58-4059-bcfa-54084f775717','再賦','洪适','宋','宋诗','song-poetry','','[]','厭聽朱弦裂帛聲，携鋤劚壑賦臨清。',64,'全唐诗/poet.song.123000.json','["厭聽朱弦裂帛聲，携鋤劚壑賦臨清。", "賞心盡得難并景，舒足休嫌踏破城。", "夜璧朝瓊寧獨樂，春蘭秋菊豈爭榮。", "閉關不使高軒過，只許漁樵爲輔行。"]'),
('54b6a6b3-01fd-43fc-9a2c-9c40315fe7be','憶城東來禽','洪适','宋','宋诗','song-poetry','','[]','遠送來禽我獨無，後來纔得兩三株。',32,'全唐诗/poet.song.123000.json','["遠送來禽我獨無，後來纔得兩三株。", "隱園野處花難比，祇恐人評棣萼圖。"]'),
('cf48c38a-5bdb-4398-9521-7e3e7b86a166','憶古城柿','洪适','宋','宋诗','song-poetry','','[]','果園幽僻少能知，丹柿烏椑手自移。',32,'全唐诗/poet.song.123000.json','["果園幽僻少能知，丹柿烏椑手自移。", "欲學鄭虔書墜葉，何人解有寄來時。"]'),
('69aaa160-9513-4ec8-91f0-98a46dd6d37a','憶隆庭竹','洪适','宋','宋诗','song-poetry','','[]','聞道隆庭竹滿園，許分蒼翠長兒孫。',32,'全唐诗/poet.song.123000.json','["聞道隆庭竹滿園，許分蒼翠長兒孫。", "看看冬盡無消息，始信壯周是寓言。"]'),
('0d5fad21-ec3a-46d6-b4f7-6b172c7c6128','憶吳中洛花','洪适','宋','宋诗','song-poetry','','[]','書郵浸失鱗鴻約，欄檻長教蜂蝶猜。',32,'全唐诗/poet.song.123000.json','["書郵浸失鱗鴻約，欄檻長教蜂蝶猜。", "待擬子虛烏有賦，東賓仍遣耳孫來。"]'),
('8509feb1-e8d3-4017-b3cd-375600adade2','戲孫陳二弟  其一','洪适','宋','宋诗','song-poetry','','[]','城東卜筑有期無，須爲簷楹動百株。',32,'全唐诗/poet.song.123000.json','["城東卜筑有期無，須爲簷楹動百株。", "可忍非時歸爨下，合尖何似助浮圖。"]'),
('d4910365-a6cb-4c08-aeb1-267bffd232db','戲孫陳二弟  其二','洪适','宋','宋诗','song-poetry','','[]','古城栽種畏人知，定是根盤不可移。',32,'全唐诗/poet.song.123000.json','["古城栽種畏人知，定是根盤不可移。", "車載斗量稗販走，果綱却有入州時。"]'),
('dd1cd68c-40ab-411a-8477-496f0ffe9d72','戲孫陳二弟  其三','洪适','宋','宋诗','song-poetry','','[]','傍巘經營雜果園，翻愁它日逐王孫。',32,'全唐诗/poet.song.123000.json','["傍巘經營雜果園，翻愁它日逐王孫。", "不如種竹招風月，此意難逢俗子言。"]'),
('fed3d598-2eed-44ce-8b53-9a07dd034bab','戲孫陳二弟  其四','洪适','宋','宋诗','song-poetry','','[]','林居草創名花少，柳徑苔生過客猜。',32,'全唐诗/poet.song.123000.json','["林居草創名花少，柳徑苔生過客猜。", "不管空言無實惠，只嫌巧取近嗟來。"]'),
('dadac0d9-51fe-4f11-8113-a94a2f2fcd04','再賦  其一','洪适','宋','宋诗','song-poetry','','[]','外求它壤曾攀桂，近捨家園尚守株。',32,'全唐诗/poet.song.123000.json','["外求它壤曾攀桂，近捨家園尚守株。", "待得枝頭如赤柰，却來看我百花圖。"]'),
('7e2a6355-aec7-4798-936b-63c5bc3652d6','再賦  其二','洪适','宋','宋诗','song-poetry','','[]','圃在前村若箇知，山逢愚叟會須移。',32,'全唐诗/poet.song.123000.json','["圃在前村若箇知，山逢愚叟會須移。", "前言戲耳君休怪，七絕成陰自有時。"]'),
('5e06c091-a807-482b-b86c-bdd06edbb67a','再賦  其三','洪适','宋','宋诗','song-poetry','','[]','何人種柳成門巷，幾處看花到子孫。',32,'全唐诗/poet.song.123000.json','["何人種柳成門巷，幾處看花到子孫。", "且盡山齋一杯酒，此君相對已忘言。"]'),
('1f43deda-3a7d-4203-a529-c8ebf9b481ed','再賦  其四','洪适','宋','宋诗','song-poetry','','[]','長慚無地起樓臺，覓果尋花頗受猜。',32,'全唐诗/poet.song.123000.json','["長慚無地起樓臺，覓果尋花頗受猜。", "且向園林聊寓意，不教絲管逐人來。"]'),
('a87b831e-a496-41fd-a233-d352a905cf59','送景盧','洪适','宋','宋诗','song-poetry','','[]','涉世難防犬吠聲，放懷安可俟河清。',64,'全唐诗/poet.song.123000.json','["涉世難防犬吠聲，放懷安可俟河清。", "昂霄莫辨千尋木，鑿牖聊看三里城。", "丹橘黄甘隨處好，美花香草逐時榮。", "晚來寒雨催歸騎，酷似鄒人接淅行。"]'),
('c1b18d82-8c5e-4d22-86f4-cf67e7d67902','送朱叔召歸吳中','洪适','宋','宋诗','song-poetry','','[]','長憶吳中鳴櫓聲，風高月上水波清。',64,'全唐诗/poet.song.123000.json','["長憶吳中鳴櫓聲，風高月上水波清。", "臞菴掩映花成聚，笠澤微茫烟若城。", "十載相忘存夢想，一帆此去喜歸榮。", "老來無復蓴鱸會，尚看驊騮得路行。"]'),
('5dbdd16b-973c-4e5c-81f7-7af67c98189f','景孫以婦病稽賞甘嘗蟹之約景盧以詩詰之','洪适','宋','宋诗','song-poetry','','[]','鄭莊好客底虛聲，藥裹關心興未清。',64,'全唐诗/poet.song.123000.json','["鄭莊好客底虛聲，藥裹關心興未清。", "應恐被圍因魯酒，也防完璧棄秦城。", "雙螯弗講連宵會，千橘誰教滿路榮。", "見說高臺新斷手，何如自索玉杯行。"]'),
('71c6811a-8282-45ae-b209-2057e4036106','戲景盧','洪适','宋','宋诗','song-poetry','','[]','千橘亭前莫聽聲，豈無鄴酌和汾清。',64,'全唐诗/poet.song.123000.json','["千橘亭前莫聽聲，豈無鄴酌和汾清。", "輕裾長袖閑列屋，碧瓦朱甍高照城。", "臺上金波催夜集，樓邊玉樹待春榮。", "賞花斫鱠言猶在，還被題輿誚却行。"]'),
('f11b0c39-2f12-4aa2-8264-c9783504b52f','隆庭竹至四絕句  其一','洪适','宋','宋诗','song-poetry','','[]','憶昨分抄種樹書，三荆今古美同株。',32,'全唐诗/poet.song.123000.json','["憶昨分抄種樹書，三荆今古美同株。", "閑將草木供詩戲，待把漁樵足畫圖。"]'),
('20c8d65b-1a85-4397-b7ca-4f2a4184553a','隆庭竹至四絕句  其二','洪适','宋','宋诗','song-poetry','','[]','竹里巧傳幽鳥語，月臺高視客星移。',32,'全唐诗/poet.song.123000.json','["竹里巧傳幽鳥語，月臺高視客星移。", "鄉園何幸立分鼎，鳴鼓鏗鐘樂聖時。"]'),
('f1dd2853-91c7-4aea-aff3-682e5f41936d','隆庭竹至四絕句  其三','洪适','宋','宋诗','song-poetry','','[]','斑籜遠移湘岸種，貓頭亦是渭川孫。',32,'全唐诗/poet.song.123000.json','["斑籜遠移湘岸種，貓頭亦是渭川孫。", "百金得諾今無恨，千畝封侯不在言。"]'),
('17939cd0-df85-45e4-b0b1-22f64ab3be21','隆庭竹至四絕句  其四','洪适','宋','宋诗','song-poetry','','[]','裝景松篁渾可喜，忘機鷗鷺不相猜。',32,'全唐诗/poet.song.123000.json','["裝景松篁渾可喜，忘機鷗鷺不相猜。", "南窗情話有時盡，喚取青州從事來。"]'),
('2135e3a0-d7e8-4e4a-a95a-d024f4886825','答景盧久陰遣悶','洪适','宋','宋诗','song-poetry','','[]','幾日思君環珮聲，方冬天宇未澄清。',64,'全唐诗/poet.song.123000.json','["幾日思君環珮聲，方冬天宇未澄清。", "衝寒也到臨春閣，處暗如登却月城。", "整頓建瓴愁雨作，商量設醴卜花榮。", "錦囊不用詩排悶，起看朝雲亦倦行。"]'),
('65ec67fd-26f3-42ae-b1c5-26fa4c690cfd','喜小隱新得山茶','洪适','宋','宋诗','song-poetry','','[]','芳園封植閱年華，異卉搜求鬧小車。',64,'全唐诗/poet.song.123000.json','["芳園封植閱年華，異卉搜求鬧小車。", "不羨竹林生石竹，獨來茶塢補山茶。", "遊人認柿枝頭子，歸鶴求雌葉底花。", "我去臨川尋玉茗，遥將白雪映紅霞。"]'),
('08f72d0a-fecd-466a-9f4c-73fb159687df','答小隱惠山茶','洪适','宋','宋诗','song-poetry','','[]','何處仙官萼綠華，鞭鸞獨御五雲車。',64,'全唐诗/poet.song.123000.json','["何處仙官萼綠華，鞭鸞獨御五雲車。", "來從月窟曾依桂，分種盤洲不礙茶。", "枝耐歲寒犀換葉，蘂藏朝霧錦羞花。", "紅顔不逐東君老，須著頻來鬭臉霞。"]'),
('ec4c97df-c196-4137-b06e-b14dbded3581','答小隱聞野處開尊','洪适','宋','宋诗','song-poetry','','[]','遺我雙魚集棣華，尚疑信馬誤隨車。',64,'全唐诗/poet.song.123000.json','["遺我雙魚集棣華，尚疑信馬誤隨車。", "絲聲自是不如肉，酒薄須知大勝茶。", "翠袖明朝看倚竹，蘭燈昨夜報開花。", "飲闌同步曾臺月，古堞危亭見綺霞。"]'),
('bc24dc0a-14b8-40fb-bbdd-81551d46ab60','答小隱喜得白山茶之報','洪适','宋','宋诗','song-poetry','','[]','素質寧嫌潘鬢華，來時應有雪翻車。',64,'全唐诗/poet.song.123000.json','["素質寧嫌潘鬢華，來時應有雪翻車。", "賦傳山谷文堆繡，種出麻源韻勝茶。", "不向桂宮藏玉兔，合橫蘂觀儷瓊花。", "冥搜未獲詩先作，駐目輕帆泝落霞。"]'),
('6d24bc6a-8c28-4260-a9ea-99932d2381e2','憶東閣手植花木用雍陶過舊宅看花詩韻','洪适','宋','宋诗','song-poetry','','[]','分根徙核望春栽，曲徑幽蹊手自開。',32,'全唐诗/poet.song.123000.json','["分根徙核望春栽，曲徑幽蹊手自開。", "今日成林渾著子，花時不折一枝來。"]'),
('38f86907-9a57-4e22-9f57-88b00d35efb3','玉茗未有耗而小隱作詩以瓊花爲二絕當專美野處可也','洪适','宋','宋诗','song-poetry','','[]','休論官業出金華，共樂家林鹿挽車。',64,'全唐诗/poet.song.123000.json','["休論官業出金華，共樂家林鹿挽車。", "何日尋春携漉酒，有時留客試擂茶。", "望梅止渴寧非夢，却月橫枝始是花。", "祇恐偏枯慚好句，空教步障錦如霞。"]'),
('146eb53c-2071-4e93-8b59-974e34b11f97','和景嚴送方蒂柿','洪适','宋','宋诗','song-poetry','','[]','萬株紅葉詠光華，嘉實堆盤走紺車。',64,'全唐诗/poet.song.123000.json','["萬株紅葉詠光華，嘉實堆盤走紺車。", "方蒂寧同牛奶柿，朱唇應笑鳩盤茶。", "園官急送須足繭，童子爭觀多眼花。", "羅列林珍生飲興，詎思辟穀更餐霞。"]'),
('07e1e437-8867-46cb-ba8b-d164d6f5c842','答景盧懷舊','洪适','宋','宋诗','song-poetry','','[]','了無夢寐到京華，來往園林整釣車。',64,'全唐诗/poet.song.123000.json','["了無夢寐到京華，來往園林整釣車。", "緩步競移霜後橘，清談旋碾雨前茶。", "虛名長媿稱三鳳，舊事休懷判五花。", "共把詩筒銷永日，喜君襟韻秀朱霞。"]'),
('d0c366cd-7273-4b83-9055-7f95a01431e8','園中觀種樹','洪适','宋','宋诗','song-poetry','','[]','望中赤葉漬霜華，林下徐行便當車。',64,'全唐诗/poet.song.123000.json','["望中赤葉漬霜華，林下徐行便當車。", "好處見山仍見水，興來呼酒不呼茶。", "旋移朱橘添盧橘，更揀紅花間白花。", "出郭最欣塵事少，飽看孤鶩逐飛霞。"]'),
('ef77d474-3226-4610-8cd8-5a57301d843f','答景盧報月臺將畢工','洪适','宋','宋诗','song-poetry','','[]','新筑崇臺款桂華，凌虛如跨白鸞車。',64,'全唐诗/poet.song.123000.json','["新筑崇臺款桂華，凌虛如跨白鸞車。", "西瓜來自余吾水，遠物誰詢悉里茶。", "不減平泉書草木，更尋南部錄烟花。", "落成有約何時講，舞袖還看舉彩霞。"]'),
('b21db189-fb31-4a37-8a5f-c8af621a87d3','答景嚴詠山居夾道種松','洪适','宋','宋诗','song-poetry','','[]','投黻歸來髮半華，蒼官怪我出無車。',64,'全唐诗/poet.song.123000.json','["投黻歸來髮半華，蒼官怪我出無車。", "樹當樵徑頻爭席，地接禪房好覓茶。", "要使行人長蔭樾，不教侍女獨司花。", "十園五鬣它年事，會見摩空薄絳霞。"]'),
('87615c05-dd04-4bfe-a7dc-2ff2752f7a4e','和景盧餞朱叔召往宣城','洪适','宋','宋诗','song-poetry','','[]','與客窺園春未華，也須日昃始迴車。',64,'全唐诗/poet.song.123000.json','["與客窺園春未華，也須日昃始迴車。", "松間共賞貓頭竹，酒半先嘗雀舌茶。", "雲覆疏欞香起篆，風侵密坐燭吹花。", "雙溪疊嶂催行色，佳句重吟綺散霞。"]'),
('ca43bb3a-dbb3-446c-8d70-280265519061','答景盧詠道上新松','洪适','宋','宋诗','song-poetry','','[]','落落喬松說九華，遠移霜骨想專車。',64,'全唐诗/poet.song.123000.json','["落落喬松說九華，遠移霜骨想專車。", "淪脂此地能和藥，結實殊方却入茶。", "村女拾釵分翠葉，野人敲粉聚黄花。", "翛然一徑窮芝嶺，曉見飛雲夕見霞。"]'),
('7f864086-69a0-4b71-a184-de19cd7e46a8','和景盧雨中歎','洪适','宋','宋诗','song-poetry','','[]','工徒滯雨望朝華，好倩泥蠻指日車。',64,'全唐诗/poet.song.123000.json','["工徒滯雨望朝華，好倩泥蠻指日車。", "末利怯寒先近火，瑞香蒙潤免澆茶。", "莫嫌雲暗青油幕，尚恐天開端木花。", "待得嚴霜變陰翳，便須酌酒賞金霞。"]'),
('d8b52d99-e7ee-456b-97aa-c24507f0f5a5','和景盧喜晴','洪适','宋','宋诗','song-poetry','','[]','共喜胡塵不亂華，戍邊聊出武剛車。',64,'全唐诗/poet.song.123000.json','["共喜胡塵不亂華，戍邊聊出武剛車。", "天公欲遣風催雪，僧舍方疑烟濕茶。", "巡圃觀橙無墜葉，隔溪移杏恐傷花。", "舉頭忽見雲間日，急草詩章慶半霞。"]'),
('2522b1ac-7161-47a0-b70c-cce75616cbc7','閩商貨千葉牡丹疑其非而却之併懷藍憲所許','洪适','宋','宋诗','song-poetry','','[]','星文隕石應皇華，鵲語參差雨洗車。',64,'全唐诗/poet.song.123000.json','["星文隕石應皇華，鵲語參差雨洗車。", "忽報商人緘葦篋，初疑閩產雜官茶。", "栽培况乃三冬月，真贗難分千葉花。", "寧使雙壇且虛左，空吟輕日護香霞。"]'),
('9730b822-7bee-4012-b0bb-f2bd5a706e49','和景盧詠新得歙縣牡丹','洪适','宋','宋诗','song-poetry','','[]','旁搜嘉卉對韶華，寶玩明珠詫照車。',64,'全唐诗/poet.song.123000.json','["旁搜嘉卉對韶華，寶玩明珠詫照車。", "可使東壇無蔓草，如遊北苑得名茶。", "安排釀具多炊黍，准擬襟期共賞花。", "醉語美人無可恨，不教拖帔泣歸霞。"]'),
('006a65dd-2071-4172-8d91-0bf07e9be625','野處送百結花','洪适','宋','宋诗','song-poetry','','[]','盤屈枝仍墊，葱青葉未稀。',48,'全唐诗/poet.song.123000.json','["盤屈枝仍墊，葱青葉未稀。", "雙銜疑鳳带，百結類鶉衣。", "弱骨長連鎖，輕腰孰解圍。", "若教花自在，應作彩雲飛。"]'),
('cdad6661-0171-4b9b-8385-499d2364d72b','野處送金燈花','洪适','宋','宋诗','song-poetry','','[]','銀燈未茁有金燈，翠葉森森比劍稜。',32,'全唐诗/poet.song.123000.json','["銀燈未茁有金燈，翠葉森森比劍稜。", "待得花光無斷續，却須拈出問鄰僧。"]'),
('5795c167-8d34-4fa6-bb58-9c8254d4a2d4','和景嚴詠冬開木犀','洪适','宋','宋诗','song-poetry','','[]','桂枝冬更好，浪蘂到今稀。',48,'全唐诗/poet.song.123000.json','["桂枝冬更好，浪蘂到今稀。", "雅韻催吟筆，幽香傍舞衣。", "月分千里影，風突百花圍。", "倚策山亭暮，寒鴉亦倦飛。"]'),
('95a92be7-d011-427c-91d9-7c2e0edcc428','和景嚴約賞木犀','洪适','宋','宋诗','song-poetry','','[]','蔌蔌蟾宮桂，冬開自昔稀。',48,'全唐诗/poet.song.123000.json','["蔌蔌蟾宮桂，冬開自昔稀。", "犀通一點骨，蜜染六銖衣。", "樽淥拚深酌，爐紅漸可圍。", "賞花宜卜晝，莫待晚霞飛。"]'),
('a5de2840-055c-402c-9c0c-2bef4d958854','喜景盧有落成瓊樓之約','洪适','宋','宋诗','song-poetry','','[]','地近籃輿便，心清俗事稀。',48,'全唐诗/poet.song.123000.json','["地近籃輿便，心清俗事稀。", "檐花瓊結佩，窗月練垂衣。", "松竹添三徑，溪山豁四圍。", "落成歌管集，仰首暗塵飛。"]'),
('15de7948-c5a5-4397-90a2-968c91e3addd','和景嚴詠新得蒲萄','洪适','宋','宋诗','song-poetry','','[]','名傳馬乳久，物比蚌胎稀。',48,'全唐诗/poet.song.123000.json','["名傳馬乳久，物比蚌胎稀。", "高出酴醾架，輕鋪薜荔衣。", "孤根臨水窟，疏蔓接籬圍。", "急釀凉州酒，西園蓋欲飛。"]'),
('21ca560e-4580-475a-b623-dc44faecd404','得洛中牡丹','洪适','宋','宋诗','song-poetry','','[]','洛花天下選，千里湊三園。',48,'全唐诗/poet.song.123000.json','["洛花天下選，千里湊三園。", "望岫方緘恨，憑鶯忽踐言。", "群葩俱退舍，勝日便開尊。", "莫惜詩償債，真同香返魂。"]'),
('81170c97-b1d0-43be-9e0b-f15ca765ca31','藍憲所送牡丹道遠失時頗多枯槁','洪适','宋','宋诗','song-poetry','','[]','殷勤人有信，驚喜得花饒。',48,'全唐诗/poet.song.123000.json','["殷勤人有信，驚喜得花饒。", "可惜三冬晚，來從千里遥。", "根荄愆潤澤，牙蘗頓枯焦。", "儻有更生路，寧辭楚些招。"]'),
('d3416271-eaa3-4d15-8ab2-84191a67d05c','答景韋赴調還家見寄','洪适','宋','宋诗','song-poetry','','[]','迎歸烏鵲竟傳聲，擺落埃塵襟宇清。',64,'全唐诗/poet.song.123000.json','["迎歸烏鵲竟傳聲，擺落埃塵襟宇清。", "薪桂豈容留帝闕，幙蓮且得近鄉城。", "眼邊觸處梅爭破，陌上分行柳向榮。", "如約速來春可探，肩輿須去靜中行。"]'),
('3c991f16-1f25-41da-8e98-2ab79afb77f2','許倩遣舟送花栽','洪适','宋','宋诗','song-poetry','','[]','雙舟十日涉長湖，甆斛筠籃且百株。',64,'全唐诗/poet.song.123000.json','["雙舟十日涉長湖，甆斛筠籃且百株。", "可喜石榴初變白，更驚玉茗不施朱。", "臨風含笑勞花使，映水分行擁木奴。", "裝點園林娛杖屨，好來一醉倒金壺。"]'),
('4f1f3dec-08e3-4e20-8771-de15d9d012fc','予得圃芝山之麓去春始治畦徑名曰山居中爲芝榭四楹其秋雙芝產于榭南今夏復見四本而盤洲亦有其二因刻詩以志之','洪适','宋','宋诗','song-poetry','','[]','山中曾有采芝仙，此日靈根詎偶然。',64,'全唐诗/poet.song.123000.json','["山中曾有采芝仙，此日靈根詎偶然。", "題柱漫將詩紀實，憑欄真共酒忘年。", "英華可是丘園瑞，造化元非雨露偏。", "留與山居作嘉話，未甘草木羨平泉。"]'),
('3c530e25-245d-46bc-a9b2-991aac904b37','雙溪堂','洪适','宋','宋诗','song-poetry','','[]','負郭藏嘉處，清溪夾岸流。',48,'全唐诗/poet.song.123000.json','["負郭藏嘉處，清溪夾岸流。", "風漪前後起，雲態淺深浮。", "入戶松橫岫，開窗橘滿洲。", "心閑身自在，塵事底能留。"]'),
('bb88e981-0452-47b1-b95c-4866aef994be','檥齋二絕句  其一','洪适','宋','宋诗','song-poetry','','[]','野色山光列畫圖，坐看漁子入菰蒲。',32,'全唐诗/poet.song.123000.json','["野色山光列畫圖，坐看漁子入菰蒲。", "恰如放鷁穿三峽，何事航家問五湖。"]'),
('563ea687-38d0-48f6-99b9-2f58d4a01b07','檥齋二絕句  其二','洪适','宋','宋诗','song-poetry','','[]','青翰不動柳陰多，桂棹無聲鳥語和。',32,'全唐诗/poet.song.123000.json','["青翰不動柳陰多，桂棹無聲鳥語和。", "有此孤舟寄丘壑，可憐平地起風波。"]'),
('dd0b26f7-61ab-4fcb-88f2-6b7c0779da6a','侶鷗亭','洪适','宋','宋诗','song-poetry','','[]','憩策新亭上，波光入坐來。',48,'全唐诗/poet.song.123000.json','["憩策新亭上，波光入坐來。", "魚遊能自樂，鷗狎肯相陪。", "風快塵襟豁，雲深俗駕回。", "尋盟須日涉，未怕落霞催。"]'),
('ef41dd64-af6e-488f-bdf3-72430738e631','小隱芝草','洪适','宋','宋诗','song-poetry','','[]','芝叢盈百見聞希，不數嘉禾連理枝。',64,'全唐诗/poet.song.123000.json','["芝叢盈百見聞希，不數嘉禾連理枝。", "紫蓋堆雲光點添，金莖蒙露色凝脂。", "一時競秀園林勝，十載深藏天地知。", "急辦軒楹尊瑞物，泥封詔墨有來期。"]'),
('13250489-ca58-4000-b357-1a2855a33d8d','招二弟賞盤洲雙頭蓮','洪适','宋','宋诗','song-poetry','','[]','何須艷質鬥鮮妝，並蒂紅蕖本自雙。',32,'全唐诗/poet.song.123000.json','["何須艷質鬥鮮妝，並蒂紅蕖本自雙。", "却恐花飛成造次，急來相就倒銀缸。"]'),
('aa10212b-35d9-4567-8a5e-47f2c6ee3497','紫薇花以六月至自溧陽在道已五十日今有花滿樹因示二弟','洪适','宋','宋诗','song-poetry','','[]','六月炎天千里移，不期繁蘂便盈枝。',32,'全唐诗/poet.song.123000.json','["六月炎天千里移，不期繁蘂便盈枝。", "向來渾是西垣客，憶得看花草制時。"]'),
('c73ca531-90dd-40dc-a14b-bba9c480a681','九日欲爲雲松之集以病倦而輟','洪适','宋','宋诗','song-poetry','','[]','半秋翻藥裹，九日負雲松。',48,'全唐诗/poet.song.123000.json','["半秋翻藥裹，九日負雲松。", "黄菊從他好，清尊不我容。", "零丁憐敗葉，旁午羨遊蜂。", "今古登臨恨，雲迷五老峰。"]'),
('5d7f510e-0e1a-44e5-9f74-a4d6266b4716','景盧約賞朝天菊不克往','洪适','宋','宋诗','song-poetry','','[]','暮節真無分，頭風祇自知。',48,'全唐诗/poet.song.123000.json','["暮節真無分，頭風祇自知。", "朝天雖有菊，向日不如葵。", "久旱千株槁，深秋百草萎。", "吾衰亦相類，飲興謝東籬。"]'),
('430ad289-d354-40cd-b430-add2292a4244','除夕','洪适','宋','宋诗','song-poetry','','[]','歲盡春雖淺，更長夜亦闌。',48,'全唐诗/poet.song.123000.json','["歲盡春雖淺，更長夜亦闌。", "枕邊雞送曉，窗外雁衝寒。", "學圃心常在，籌邊力所難。", "老來驚節序，那復問椒盤。"]'),
('10a3c664-e4fe-4e45-a5f2-909ddfe36e6d','觀園人接花','洪适','宋','宋诗','song-poetry','','[]','植杖看園吏，揮斤接果栽。',48,'全唐诗/poet.song.123000.json','["植杖看園吏，揮斤接果栽。", "奪胎移造化，類我借根荄。", "一似雀爲蛤，能令桃作梅。", "天工待人力，信手便春來。"]'),
('8ddc5d50-34c4-4b0e-9834-f8a574f6e519','開歲三日有夜雨屢聞雷聲繼以大風晨起飛雪已盈積景盧作詩即事次其韻','洪适','宋','宋诗','song-poetry','','[]','旱災已歎失秋成，春到誰教夏令行。',64,'全唐诗/poet.song.123000.json','["旱災已歎失秋成，春到誰教夏令行。", "風陣驟來收雨脚，雪花未集聽雷聲。", "陰陽改變纔俄頃，冷暖乘除若晦明。", "待向斜川會鄰曲，占晴須問蜀君平。"]'),
('37b6c5aa-6d6f-453a-b1bd-3769b593a568','雪後遊盤洲','洪适','宋','宋诗','song-poetry','','[]','書事斜川日月同，行年過四逼衰翁。',64,'全唐诗/poet.song.123000.json','["書事斜川日月同，行年過四逼衰翁。", "縱情自洗和陶筆，乘興誰開訪戴蓬。", "梅萼僅存難聚雪，竹根未穩不禁風。", "莫將野趣逢人說，冰上輕鷗西復東。"]'),
('c3b1f368-60a5-4e42-b417-5744b7bff95c','檥齋觀耕','洪适','宋','宋诗','song-poetry','','[]','城下經營二頃田，倒囊不惜買山錢。',64,'全唐诗/poet.song.123000.json','["城下經營二頃田，倒囊不惜買山錢。", "一犁駐目雨初歇，三徑藏身地自偏。", "乞米帖來須領略，相牛經在與周旋。", "嘗新指擬翻匙雪，旱魃誅夷勝去年。"]'),
('c3539937-24ba-4fb4-8628-3b1a49edaa1f','景盧新治西園而亭榭未立以詩趣之','洪适','宋','宋诗','song-poetry','','[]','斬新曲徑治西園，野色春來已可觀。',32,'全唐诗/poet.song.123000.json','["斬新曲徑治西園，野色春來已可觀。", "便好作亭供客醉，望中流水有時乾。"]'),
('78bd0c27-be26-44fa-8a2d-8640fe07c4cf','答景盧和篇','洪适','宋','宋诗','song-poetry','','[]','致君無術合歸田，誰敢貪榮食萬錢。',64,'全唐诗/poet.song.123000.json','["致君無術合歸田，誰敢貪榮食萬錢。", "且對清尊希北海，最欣別墅接西偏。", "轉頭麥垅龍工往，緩步花蹊蟻磨旋。", "辛苦三農營一飽，莫教牟賊壞豐年。"]'),
('20ad4e07-10ce-4c3a-a2f2-eb674567ab07','上元日圃中歸','洪适','宋','宋诗','song-poetry','','[]','春風環柳岸，夜雨失沙痕。',48,'全唐诗/poet.song.123000.json','["春風環柳岸，夜雨失沙痕。", "環竹期新笋，移花護舊根。", "身閑貪獨樂，舌在戒多言。", "是處無燈火，荒凉一上元。"]'),
('01c76fb1-1cca-4630-8c86-72ebdfc28ec5','次韻梁憲盤洲之集','洪适','宋','宋诗','song-poetry','','[]','輕風吹雨稱行春，丘壑裝懷我輩人。',64,'全唐诗/poet.song.123000.json','["輕風吹雨稱行春，丘壑裝懷我輩人。", "照水軒窗如進艇，穿花旌節屢移輪。", "携壺迭講三杯酒，揮麈曾無一點塵。", "明日兵厨尋故事，已教園吏拂華茵。"]'),
('6259ddfb-d6c2-4030-9672-a1bc145ba6e9','再和','洪适','宋','宋诗','song-poetry','','[]','於越歸來三見春，買山學圃狎漁人。',64,'全唐诗/poet.song.123000.json','["於越歸來三見春，買山學圃狎漁人。", "非嫌厚祿輕捐印，所畏空餐詠伐輪。", "時運可驚如過隙，人生何苦不同塵。", "明年此會誰重講，唯把書郵問鼎茵。"]'),
('51c98487-565f-48ce-a7f1-b31f4d4bf254','江守置酒盤洲張貳卿兩憲及景盧同集時江新兼泉司','洪适','宋','宋诗','song-poetry','','[]','皇華分鼎坐添春，隱霧巢松三散人。',64,'全唐诗/poet.song.123000.json','["皇華分鼎坐添春，隱霧巢松三散人。", "半月陰雲濃似墨，今朝晴日大於輪。", "不辭多酌娛浮蟻，何用清歌落暗塵。", "歸去池塘入新夢，句中芳草醉中茵。"]'),
('831160b7-78f1-4cdb-adb5-68b302c57fd3','再賦','洪适','宋','宋诗','song-poetry','','[]','到處爭持麴米春，闐闐花底湊游人。',64,'全唐诗/poet.song.123000.json','["到處爭持麴米春，闐闐花底湊游人。", "同盟非是新傾蓋，巧匠誰云老斲輪。", "倚竹豈無人拾翠，凌波誰想襪生塵。", "後期直待荷花發，欲喚輕裾上舞茵。"]'),
('540b97e3-2402-41b4-8a57-915bde3f5b59','醉中三用韻','洪适','宋','宋诗','song-poetry','','[]','小車追逐賞光春，花塢行盤走隸人。',64,'全唐诗/poet.song.123000.json','["小車追逐賞光春，花塢行盤走隸人。", "水面落英如濯錦，雲心初月未安輪。", "今宵同舉盈觴酒，後夜還凝滿席塵。", "倒載歸時童稚舞，莫教騶哄滓馮茵。"]'),
('637287d6-ce2e-4d61-ab0c-6f6983d73469','雨中排悶','洪适','宋','宋诗','song-poetry','','[]','生怕花飛減却春，半旬苦雨惱幽人。',64,'全唐诗/poet.song.123000.json','["生怕花飛減却春，半旬苦雨惱幽人。", "山房挂壁有雙屐，村徑衝泥無隻輪。", "但見淥波侵碧草，不須皂莢去黄塵。", "擁爐更甚三冬月，轉覺寒威逼坐茵。"]'),
('8a54605a-51d0-4187-bfae-3039f1e63d69','次韻梁憲再集盤洲','洪适','宋','宋诗','song-poetry','','[]','春風步屧共優遊，小筑園廬匪拙謀。',64,'全唐诗/poet.song.123000.json','["春風步屧共優遊，小筑園廬匪拙謀。", "羅列清尊資嘯傲，安排好語待賡酬。", "茸茸香草裝三徑，恰恰鳴禽想十洲。", "玉節尋盟端不再，便回天上近凝旒。"]'),
('39772743-c955-47cb-90ac-af3ceddab3af','浮杯','洪适','宋','宋诗','song-poetry','','[]','南北芝泉一澗開，穿花度柳勢縈回。',64,'全唐诗/poet.song.123000.json','["南北芝泉一澗開，穿花度柳勢縈回。", "不須元巳方修禊，才遇良辰便泛杯。", "行止豈由人智巧，沉浮長與客驚猜。", "急流一去誰難進，却有先游殿後來。"]'),
('6e7265f1-1b37-4a75-abf8-1f9d97eb510e','送吳遠澤赴南宮','洪适','宋','宋诗','song-poetry','','[]','文壓秋闈擥桂華，一鳴天陛穩乘槎。',32,'全唐诗/poet.song.123000.json','["文壓秋闈擥桂華，一鳴天陛穩乘槎。", "歸來須踏盤洲路，要看荷衣醉藕花。"]'),
('ad9fb83a-127d-4231-9fa8-97926ed6db41','九曲有感','洪适','宋','宋诗','song-poetry','','[]','忽忽光陰轉，駸駸華髮添。',24,'全唐诗/poet.song.123000.json','["忽忽光陰轉，駸駸華髮添。", "迹陳三可歎，心賞四難兼。"]'),
('56fd769e-8c96-48c6-9daf-62676295678d','歲三日插柳','洪适','宋','宋诗','song-poetry','','[]','欲教垂柳匝池臺，尋覓長柯處處栽。',32,'全唐诗/poet.song.123000.json','["欲教垂柳匝池臺，尋覓長柯處處栽。", "待得成陰身益老，攀條能有幾番來。"]'),
('bad459a6-7391-48f9-bb49-710cd25ef14f','次韻梁子正詠棕亭','洪适','宋','宋诗','song-poetry','','[]','鬋得栟櫚製數椽，繡衣拈出少陵篇。',64,'全唐诗/poet.song.123000.json','["鬋得栟櫚製數椽，繡衣拈出少陵篇。", "倚楹見水幽情暢，駐屐迷花詩興牽。", "便覺茅軒俱退舍，若談竹室不同年。", "滿山所欠青青藥，且趁流觴集醉仙。"]'),
('e5641ba6-f5b0-49fc-a54c-cb7e00483712','梁子正有詩謝牡丹及聚仙花次其韻  其一','洪适','宋','宋诗','song-poetry','','[]','天教國色傲春華，不肯爭先伍雜花。',32,'全唐诗/poet.song.123000.json','["天教國色傲春華，不肯爭先伍雜花。", "西洛塵埃長太息，名園今屬犬羊家。"]'),
('608d9623-04cc-4e39-b24b-8cabe7d56910','梁子正有詩謝牡丹及聚仙花次其韻  其二','洪适','宋','宋诗','song-poetry','','[]','癡坐林間類守株，一年春事已無餘。',32,'全唐诗/poet.song.123000.json','["癡坐林間類守株，一年春事已無餘。", "直須九曲添清漲，灑掃棕亭進一盂。"]'),
('6aa265eb-84e0-4f27-9fa9-bc86a0c41eab','梁子正有詩謝牡丹及聚仙花次其韻  其三','洪适','宋','宋诗','song-poetry','','[]','玉蘂茸茸映四筵，團欒如集飲中仙。',32,'全唐诗/poet.song.123000.json','["玉蘂茸茸映四筵，團欒如集飲中仙。", "下方簇蝶非儔匹，上比瓊花難並緣。"]'),
('236c36e4-5990-42d5-a072-e914cbaab86d','病中憶九曲','洪适','宋','宋诗','song-poetry','','[]','新穿九曲望時霖，水到渠成病已侵。',64,'全唐诗/poet.song.123000.json','["新穿九曲望時霖，水到渠成病已侵。", "見說小舟穿柳岸，那知清漲入桃林。", "五旬藥裹長經眼，幾日荷花復賞心。", "夢裏亦知行樂處，老來尤更惜光陰。"]'),
('0210b0c9-b559-433c-ab76-ab53e72707f0','六月鄉城不雨禱賽無應得建康書一雨連半月至以望日丐晴感而有作','洪适','宋','宋诗','song-poetry','','[]','蒼蒼太手熟，歲歲厄吾鄉。',48,'全唐诗/poet.song.123000.json','["蒼蒼太手熟，歲歲厄吾鄉。", "千里均州縣，三旬殊雨暘。", "誰云不私覆，廼爾分此疆。", "遂令遠遊子，轉盼生炎凉。"]'),
('c7625776-2e57-4c96-b24c-13264ce9923c','江鳴玉遺蒼梧二蒼鶴其一病兩日而死陸魯望詩云醫鶴自須監吾鄉人醫尚無良手况禽醫乎','洪适','宋','宋诗','song-poetry','','[]','病骨摧頹警露難，草埋長脛委蒼翰。',32,'全唐诗/poet.song.123000.json','["病骨摧頹警露難，草埋長脛委蒼翰。", "吾鄉尚欠肱三折，况有禽醫爲一看。"]'),
('2bdc4342-071d-4107-bc0d-a38af1add1c5','八月下旬觀邸報二絕句  其一','洪适','宋','宋诗','song-poetry','','[]','黄卷漫窮年，天梯欲上難。',24,'全唐诗/poet.song.123000.json','["黄卷漫窮年，天梯欲上難。", "閭閻聽小子，競欲裂儒冠。"]'),
('206557ad-b1ee-4cea-a42d-ef3d3cd04d13','八月下旬觀邸報二絕句  其二','洪适','宋','宋诗','song-poetry','','[]','歎息東坡老，聰明誤一生。',24,'全唐诗/poet.song.123000.json','["歎息東坡老，聰明誤一生。", "不須多識字，捷徑自橫行。"]'),
('fa99ba4d-7159-48d7-9a50-d6ada10e3a9c','婺源乃歙之劇邑素有湯鼎之謗頃治此郡俾邑官作止沸之亭而不果吾宗應賢下車而風俗易書來求扁因爲賦詩','洪适','宋','宋诗','song-poetry','','[]','琴堂少值烹鮮手，壯縣空遭沸鼎名。',32,'全唐诗/poet.song.123000.json','["琴堂少值烹鮮手，壯縣空遭沸鼎名。", "止火絕薪俱下策，風移全在長官清。"]'),
('2ae7e798-b4d0-4ad9-841f-288e479fcc6e','宗人應賢婺源張氏之婿也治邑清介一無所私其列嶽詒書郡幕至以邑尊稱之其里諺如此戲成絕句','洪适','宋','宋诗','song-poetry','','[]','自昔爲門婿，于今是邑尊。',24,'全唐诗/poet.song.123000.json','["自昔爲門婿，于今是邑尊。", "秋毫無假借，情話與誰論。"]'),
('d74ed2bc-0f55-4df1-90bf-474c8757fcb0','朱叔召遺文官花二絕句  其一','洪适','宋','宋诗','song-poetry','','[]','幻出荷衣點雪衣，更將龜紫換牙緋。',32,'全唐诗/poet.song.123000.json','["幻出荷衣點雪衣，更將龜紫換牙緋。", "人中巧宦誰知此，好向天街插翅飛。"]'),
('f8dae9ec-d549-41d4-8c6c-a1f167a4d11e','朱叔召遺文官花二絕句  其二','洪适','宋','宋诗','song-poetry','','[]','綠心變却初時白，紫色由來昨夜朱。',32,'全唐诗/poet.song.123000.json','["綠心變却初時白，紫色由來昨夜朱。", "學得文官何足道，但堪花徑駭僮奴。"]'),
('a746a632-f856-400a-9496-b9a7e3b348c3','再賦  其一','洪适','宋','宋诗','song-poetry','','[]','不用風人怨綠衣，身兼魏紫與潜緋。',32,'全唐诗/poet.song.123000.json','["不用風人怨綠衣，身兼魏紫與潜緋。", "司花直爲文官地，可忍春殘一片飛。"]'),
('bd92634c-d429-40ae-af1c-26eb247dbd58','再賦  其二','洪适','宋','宋诗','song-poetry','','[]','解褐方聞上玉除，寵光轉眼疊金朱。',32,'全唐诗/poet.song.123000.json','["解褐方聞上玉除，寵光轉眼疊金朱。", "大夫不博喬松貴，嘉橘千頭也作奴。"]'),
('774cc963-c7c2-4aee-8c95-a7c1c5e25b76','景盧蠙洲','洪适','宋','宋诗','song-poetry','','[]','芳洲編地志，老蚌隱澄灣。',24,'全唐诗/poet.song.123000.json','["芳洲編地志，老蚌隱澄灣。", "軒檻今清絕，全勝合浦還。"]'),
('5a96df39-a25f-4470-b89c-9bfc8f4ee752','蠙橋','洪适','宋','宋诗','song-poetry','','[]','堤長交柳蔭，橋狹束荷香。',24,'全唐诗/poet.song.123000.json','["堤長交柳蔭，橋狹束荷香。", "掩戶回逋客，憑欄狎漫郎。"]'),
('0b12658f-5b0d-4008-b98d-a9b26c19281f','索笑亭思景嚴二絕句  其一','洪适','宋','宋诗','song-poetry','','[]','往日江梅發，巾車數數來。',24,'全唐诗/poet.song.123000.json','["往日江梅發，巾車數數來。", "自今花索笑，不復共銜杯。"]'),
('16dcc4f1-d92d-45ee-9ce3-68092942b2a9','索笑亭思景嚴二絕句  其二','洪适','宋','宋诗','song-poetry','','[]','常棣春來減，人如折脚鐺。',24,'全唐诗/poet.song.123000.json','["常棣春來減，人如折脚鐺。", "倚欄思舊事，老眼淚縱橫。"]'),
('12180762-8a4d-4aa6-bffe-4d02284fbce3','次韻景盧賞梅','洪适','宋','宋诗','song-poetry','','[]','曲塢梅藏白，東皇解出奇。',48,'全唐诗/poet.song.123000.json','["曲塢梅藏白，東皇解出奇。", "不嫌歌板鬧，直與酒尊宜。", "倚竹盟三友，凌風粲一枝。", "清標何水部，千古說能詩。"]'),
('5711c113-8251-4a17-b537-2f20da11f2ea','石鼓詩','洪适','宋','宋诗','song-poetry','','[]','天作高山太王荒，鸑鷟一鳴周翦商。',336,'全唐诗/poet.song.123000.json','["天作高山太王荒，鸑鷟一鳴周翦商。", "郟鄏卜年大蒐講，諸侯歛衽尊天王。", "六月中興繩祖武，平蕩犬戎恢境土。", "石崖可鑿詩可鎸，千載神光薄西滸。", "橐駝輓入大梁都，璧水湛湛河出圖。", "中間兩鼓備章句，日惟丙申不模糊。", "左驂秀弓射麋豕，有鰟有□君子漁。", "光和石經屹相望，詛楚登嶧非吾徒。", "辛壬癸甲雁分翅，橋門觀者堵牆如。", "星沉東壁干戈起，首下足上天倒置。", "景鐘糜碎九鼎飛，王迹皇風吁掃地。", "羣胡扛石徙幽燕，兵車亂載包無氈。", "敲火礪角小小爾，爲礎爲砧多歷年。", "宣和殿中圖復古，冠以車攻次十鼓。", "韓詩歐跋盡兼收，雲章剖判定魚魯。", "先君辛苦朔方歸，文犀拱璧棄弗携。", "一編十襲自鐍祕，更有司馬鳳翔碑。", "我生不辰今已老，岐陽三雍身不到。", "匆匆使虜接淅行，在耶亡耶問無報。", "整齊篆籀飾牙籤，簡撮篇詠勞窮探。", "致主有心歌小雅，汗顔無術下登三。"]'),
('e4fe11cd-0d7d-41f8-8a49-162a86142668','丙申臘二十五日落一左齒','洪适','宋','宋诗','song-poetry','','[]','行年六十已中枯，雪映衰髯歲且除。',32,'全唐诗/poet.song.123000.json','["行年六十已中枯，雪映衰髯歲且除。", "一齒驟然離左輔，益憐大嚼遠庖厨。"]'),
('c0d4d3d7-6409-42cd-abde-0c83303deb21','野處孔雀爲狸所斃','洪适','宋','宋诗','song-poetry','','[]','遠程萬里起南溟，文采葳蕤掩畫屏。',64,'全唐诗/poet.song.123000.json','["遠程萬里起南溟，文采葳蕤掩畫屏。", "展翼來朝金翠晃，竦身輕舉鵲烏停。", "園中但有辟蛇法，山下相望瘞鶴銘。", "野鶩家雞隨處有，孽狐何事獨淫刑。"]'),
('9183f246-136e-4623-8383-cdaca3c8cd76','過濠上','洪适','宋','宋诗','song-poetry','','[]','心隨溪水清，目逆岫雲生。',24,'全唐诗/poet.song.123000.json','["心隨溪水清，目逆岫雲生。", "不憚躧芳屐，橋南鷗乞盟。"]'),
('6678c7f7-06ed-42b6-8160-8910417adf73','豹岩之北脩竹數畝中有叢冢數十百處皆紹興末年所寄予得此地先定規撫某處起亭榭某處植花木七八年間成畦逕矣所寄之櫬願移者從之不强也作噩之春有姓淡人來啟菆卜日携鍤掘土數尺敗棺俱在朽骨爲土所蝕頗亦不具皆包裹而去後數日忽訴于縣于州于外臺追問證治踰月始定今不復塞其故穴欲使孫曾知之故作此詩','洪适','宋','宋诗','song-poetry','','[]','未央長樂宮，中有樗里墓。',252,'全唐诗/poet.song.123000.json','["未央長樂宮，中有樗里墓。", "沈沈天子居，咫尺穴狐兔。", "乃知古聖人，如天覆下土。", "雖袒裼裸裎，四目曾不顧。", "賢哉季武子，杜殯迫西廡。", "堂皇步武接，松檟暗鐘鼓。", "桃茢不屏除，芻靈許來祔。", "忌諱後愈多，今人不如古。", "曹瞞好發丘，兇德比夷虜。", "掩骼埋其胔，人當事斯語。", "我老得歸田，買山因學圃。", "鬰鬰琅玕林，叢冢不知數。", "豈忍去枯骨，爲我展杖屨。", "恣其笋侵疆，不使種瓜瓠。", "花木列四旁，亭榭亦回護。", "數年畦逕成，或徙或如故。", "尚有獷悍人，珥筆巧誣訴。", "無言事自明，有物眾所睹。", "舊壙今弗堙，朽木且支柱。", "尚恐妄男子，輕傳市中虎。", "書事示孫曾，無心覓佳句。"]'),
('b684322b-fcd3-4e59-b7c3-fa8e5598e56f','席上見姚泉壽母諸子求詩','洪适','宋','宋诗','song-poetry','','[]','潘輿隨五采，三釜古今榮。',24,'全唐诗/poet.song.123000.json','["潘輿隨五采，三釜古今榮。", "蘭玉盈階砌，追攀千佛名。"]'),
('57f4223e-5a2f-427a-bfed-ba202fb09e49','董伯魯以詩送川海棠用韻答之','洪适','宋','宋诗','song-poetry','','[]','花栽趁上春，重趼疲雙足。',24,'全唐诗/poet.song.123000.json','["花栽趁上春，重趼疲雙足。", "何日對仙姿，分題同刻燭。"]'),
('6911a40e-6cc9-4647-84e0-58f3bad4f2fc','次韻景盧題龜巢','洪适','宋','宋诗','song-poetry','','[]','拙速誰云勝巧遲，新亭結罷得能奇。',64,'全唐诗/poet.song.123000.json','["拙速誰云勝巧遲，新亭結罷得能奇。", "細看遠水兼天凈，可但中秋觀月宜。", "出郭自欣三徑樂，枕流今有幾人癡。", "巢蓮千歲同藏六，一笑泥塗曳尾龜。"]'),
('4c8fd3e8-33df-44d3-9252-7c3069f83788','三月十六日龜巢觀月渭師携寵同賞後兩日大雨復作景盧有詩同其韻','洪适','宋','宋诗','song-poetry','','[]','潜鱗故故上鈎遲，翠袖憑欄自一奇。',64,'全唐诗/poet.song.123000.json','["潜鱗故故上鈎遲，翠袖憑欄自一奇。", "半夜醉歸閑有趣，一年春盡事如宜。", "盍簪何憚再三瀆，覽鏡堪嗟六十癡。", "已辦尋盟臨斫鱠，不將可否問蓍龜。"]'),
('b31032bb-f4e8-4435-992b-550e96e12b7c','四月十三日流杯次景盧韻寄渭師','洪适','宋','宋诗','song-poetry','','[]','今年無好雨，曲水未勝杯。',48,'全唐诗/poet.song.123000.json','["今年無好雨，曲水未勝杯。", "誰伴山翁醉，難令俗客陪。", "青苔迎馬入，綠柳送鶯來。", "縱步濠梁上，垂緡更樂哉。"]'),
('1ed9ca3b-32d4-4b4b-9345-02d5416edbe4','流杯同景裴韻','洪适','宋','宋诗','song-poetry','','[]','三春少雨未行觴，槐影交加更漏長。',64,'全唐诗/poet.song.123000.json','["三春少雨未行觴，槐影交加更漏長。", "半夜水來山澗滿，四簷竹密酒尊凉。", "新亭方作龜巢葉，畫棟何妨燕語梁。", "滿引三觥拚一醉，老來真箇惜時光。"]'),
('6978af8c-d4ab-4f17-93ad-6ad7cc12c34c','流杯次日連雨渭師有詩次其韻','洪适','宋','宋诗','song-poetry','','[]','入夏濃雲日夕昏，舉頭烟雨暗前村。',64,'全唐诗/poet.song.123000.json','["入夏濃雲日夕昏，舉頭烟雨暗前村。", "風隨重客清葵扇，月爲佳人射翠樽。", "依舊建瓴欹屋角，幾番携杖失溪痕。", "小枰已在紗窗下，欲把明瓊看倒盆。"]'),
('2e2b22b8-65bb-46ba-9d00-666bb4b91bfa','再答','洪适','宋','宋诗','song-poetry','','[]','投老無能千慮昏，歸田浸久使令村。',64,'全唐诗/poet.song.123000.json','["投老無能千慮昏，歸田浸久使令村。", "長因步月成三影，難得朋雲共一樽。", "水漲溪橋孤釣隱，雨侵山徑洗鞸痕。", "寓公在此寧黔突，會有容光照覆盆。"]'),
('cd720dfb-76de-4ad5-b6fd-6431bb4e9ee9','景盧開尊阻雨展日復用前韻寄之','洪适','宋','宋诗','song-poetry','','[]','逐婦鳴鳩急定昏，不堪烟靄弄千村。',64,'全唐诗/poet.song.123000.json','["逐婦鳴鳩急定昏，不堪烟靄弄千村。", "掩關盡日資筇杖，改席何時對癭樽。", "雲暗松皮多節目，雨傷梨頰有瘢痕。", "溪神若也心無妬，迎出常娥照玉盆。"]'),
('9bd35dd4-93f3-4d79-a6d4-50fbef357f63','雨中排悶','洪适','宋','宋诗','song-poetry','','[]','飯牛戴笠牧童昏，安得斜陽過別村。',64,'全唐诗/poet.song.123000.json','["飯牛戴笠牧童昏，安得斜陽過別村。", "戶外涎蝸行半壁，床頭渴鼠側空樽。", "花殘鶯老渾如夢，水到渠成不見痕。", "天意未晴人未飲，家奴款曲辦籸盆。"]'),
('1d397060-320c-48ed-8a8f-357319f455d7','再賦','洪适','宋','宋诗','song-poetry','','[]','月在雲中破鏡昏，幾時清影散林村。',64,'全唐诗/poet.song.123000.json','["月在雲中破鏡昏，幾時清影散林村。", "杖藜難去尋漁艇，洗盞無因續蟻樽。", "竹葉弄風添秀色，榴花带雨露啼痕。", "不如暮捲珠簾醉，喚取佳人笑拊盆。"]'),
('a36850d5-a425-4508-bd30-00c9f56b1513','庚子山居采茶有感','洪适','宋','宋诗','song-poetry','','[]','憶昔采茶時，雨後山蹊濕。',132,'全唐诗/poet.song.123000.json','["憶昔采茶時，雨後山蹊濕。", "鷹爪喜盈襜，蟹眼思朝汲。", "歸路取盤洲，下昃行蹤急。", "珠汗透裳衣，更換登梯級。", "徙倚曲欄竿，鳴雁圓沙集。", "晚景不勝春，寒氣潜相襲。", "詰旦傍裝臺，欹側人扶立。", "輿疾望醫來，誰煮青黏汁。", "舉案念齊眉，幻泡何嗟及。", "重過故園門，不忍携筇入。", "引領顧前丘，空對旗槍泣。"]'),
('59ceed00-5c3a-45e7-95ac-7452c13bd1f1','一春置酒必苦風雨今日幸晴而景盧有行色','洪适','宋','宋诗','song-poetry','','[]','一春風雨厄遊遨，此際開樽始解嘲。',64,'全唐诗/poet.song.123000.json','["一春風雨厄遊遨，此際開樽始解嘲。", "恰恰鳴禽藏柳陌，訢訢嫩葉迸花梢。", "離筵欲動愁分袂，勝日何妨剩出郊。", "燕寢香凝公事了，頻將書札問龜巢。"]'),
('42eb7fde-12f2-44c1-ba31-9aed0525aab7','次景裴席上韻','洪适','宋','宋诗','song-poetry','','[]','桃李紛紛已半春，海棠睡覺晚妝新。',64,'全唐诗/poet.song.123000.json','["桃李紛紛已半春，海棠睡覺晚妝新。", "龜巢剩有千般景，瓊報渾無一點塵。", "酒未舉杯風逐客，詩方拈筆雨催人。", "從今只揀晴和日，草草杯盤勿厭頻。"]'),
('814dd340-2379-4d76-974d-a9c6a25cea3c','用景盧諸公詩軸韻招監司太守','洪适','宋','宋诗','song-poetry','','[]','淺白輕紅笑倚門，何須雪夜憶前村。',64,'全唐诗/poet.song.123000.json','["淺白輕紅笑倚門，何須雪夜憶前村。", "韶光定入詩人句，勝事難逢俗子言。", "風振繡衣須命駕，雲隨皂蓋欲窺園。", "人生易老愁春老，問柳尋花故事存。"]'),
('6dc7e6cd-fbe7-4a04-9570-42e5035d1797','景盧數日枕疾復用前韻','洪适','宋','宋诗','song-poetry','','[]','半載悠悠只閉門，不知紅綠遍千村。',64,'全唐诗/poet.song.123000.json','["半載悠悠只閉門，不知紅綠遍千村。", "山川滿目供衰境，桃李成蹊出怨言。", "可惜花飛聊洗盞，何期雨作阻行園。", "車公不出須重講，檢校芳菲心興存。"]'),
('b993da17-34e8-45af-9d05-44f678315f95','答景裴','洪适','宋','宋诗','song-poetry','','[]','春來剝啄少登門，澀雨慳風笑我村。',64,'全唐诗/poet.song.123000.json','["春來剝啄少登門，澀雨慳風笑我村。", "橋上垂綸裝好夢，花邊倚杖記前言。", "長楊美竹雖當戶，語燕流鶯不到園。", "此會明年千里隔，詩筒猶有置郵存。"]'),
('c271b735-7037-4e3a-a5fc-0050c0881775','席上遺景盧','洪适','宋','宋诗','song-poetry','','[]','白髮歸休閱半生，棣華酬唱得娛情。',64,'全唐诗/poet.song.123000.json','["白髮歸休閱半生，棣華酬唱得娛情。", "雙旌欲指閩中去，三徑誰同月下行。", "蕙帳風清知鶴怨，蘋洲波細憶鷗盟。", "新壇留慰人千里，把盞相思淚睫橫。"]'),
('c4fc9d3e-09f2-44c5-bbb7-cb7cc4346875','枕上示景盧  其一','洪适','宋','宋诗','song-poetry','','[]','朱轓皂蓋有行期，暮景無情惜別離。',32,'全唐诗/poet.song.123000.json','["朱轓皂蓋有行期，暮景無情惜別離。", "枕疾半旬乖語笑，急風吹雨淚垂垂。"]'),
('4dd87828-b1eb-4b48-8348-1fc686f9f0bb','枕上示景盧  其二','洪适','宋','宋诗','song-poetry','','[]','南憩番禺北抵燕，片帆西上駐荆門。',32,'全唐诗/poet.song.123000.json','["南憩番禺北抵燕，片帆西上駐荆門。", "平生不作東甌夢，荔子丹時念灌園。"]'),
('b249bdf2-8800-4cf1-818e-8a57484d7833','答太守謝牡丹','洪适','宋','宋诗','song-poetry','','[]','華髮歸來不記春，優游學圃傲江村。',64,'全唐诗/poet.song.123000.json','["華髮歸來不記春，優游學圃傲江村。", "已欣勝日臨千騎，漫折香霞佐一尊。", "對竹便當尋曲水，藏花那肯效慈恩。", "行厨若有真消息，奔走畦丁急掃門。"]'),
('8e39e53f-a62f-4475-a839-ee6367bdf649','懷景盧','洪适','宋','宋诗','song-poetry','','[]','菖蒲節近暑風高，常棣叢疏月影交。',64,'全唐诗/poet.song.123000.json','["菖蒲節近暑風高，常棣叢疏月影交。", "清夜不曾空鶴帳，浮生何幸老龜巢。", "酒杯獨引今無侶，書卷閑開共苦抄。", "想得公堂鳧鶩退，須懷西塢欠誅茅。"]'),
('9adc4902-453b-48fa-a7da-b7c283188d0e','答徐守  其一','洪适','宋','宋诗','song-poetry','','[]','改日開尊已十成，冬曦特地晚來晴。',32,'全唐诗/poet.song.123000.json','["改日開尊已十成，冬曦特地晚來晴。", "江梅獨報春消息，應笑羣花太薄情。"]'),
('881818d5-4518-4b50-a655-e6c4501d77e2','答徐守  其二','洪适','宋','宋诗','song-poetry','','[]','不教絲竹沸層臺，促席飛談懷抱開。',32,'全唐诗/poet.song.123000.json','["不教絲竹沸層臺，促席飛談懷抱開。", "夜半夢回聊趁韻，愧無好語答瓊瑰。"]'),
('6184fe39-bef1-4b37-80dd-0e6a47ec4761','排悶','洪适','宋','宋诗','song-poetry','','[]','數日雷中雨，凝寒懶舉頭。',48,'全唐诗/poet.song.123000.json','["數日雷中雨，凝寒懶舉頭。", "出遊閑豹舄，危坐索狐裘。", "怕冷杯常執，扶衰藥屢投。", "滿園冰木稼，天遣阿誰憂。"]'),
('6f5e69e8-279c-419d-b014-ada4a200d81b','雪中歎','洪适','宋','宋诗','song-poetry','','[]','連綿春雪助兇年，平地盈庭大可歎。',64,'全唐诗/poet.song.123000.json','["連綿春雪助兇年，平地盈庭大可歎。", "詞客罷吟梅散漫，園夫慚報竹平安。", "烏鳶腹餒飛穿屋，牛馬毛寒病倚欄。", "天意欲添人殍野，四時玉燭古來難。"]'),
('b665d023-0a71-4ba3-a605-d658faf95737','答裴弟','洪适','宋','宋诗','song-poetry','','[]','常棣成陰慰暮年，困人春雪好長嘆。',64,'全唐诗/poet.song.123000.json','["常棣成陰慰暮年，困人春雪好長嘆。", "閉門終日詩頻和，伏枕盈旬病未安。", "已遣携鋤移竹徑，更思杖策整花欄。", "飽聞冰下游魚躍，所恨雙溪一笑難。"]'),
('794b482b-087a-40b9-8b83-b370b997b770','憶昔','洪适','宋','宋诗','song-poetry','','[]','跨馬春衢裊翠鞭，垂綸圯下解漁船。',32,'全唐诗/poet.song.123000.json','["跨馬春衢裊翠鞭，垂綸圯下解漁船。", "霞飛綺散無蹤跡，依舊清霄月在川。"]'),
('7cc81875-78a9-4c04-b47a-50c915ca575d','寄景盧時往豫章','洪适','宋','宋诗','song-poetry','','["\u6ed5\u738b\u9601"]','聞得荼？語牡丹，蜂回蝶散恨春殘。',64,'全唐诗/poet.song.123000.json','["聞得荼？語牡丹，蜂回蝶散恨春殘。", "西山拄笏晨光爽，北海空尊夜漏寒。", "徐孺堂中同下榻，滕王閣外久憑欄。", "歸來已失蘭亭集，照眼榴花待細看。"]'),
('adf87881-d8af-4fd4-8459-64ac503be19d','辛幼安稼軒','洪适','宋','宋诗','song-poetry','','[]','濟時方略滿心胸，卜筑依城樂事重。',64,'全唐诗/poet.song.123000.json','["濟時方略滿心胸，卜筑依城樂事重。", "豈是求田謀萬頃，聊因學圃問三農。", "高牙暫借藩維重，燕寢未須歸興濃。", "且爲君王開再造，它年植杖得從容。"]'),
('6bdb6600-f4a6-4a40-b5a8-1d3841e07293','盤洲雜韻上 盤洲','洪适','宋','宋诗','song-poetry','','[]','曲曲盤洲徑，蒼崖路幾層。',24,'全唐诗/poet.song.123000.json','["曲曲盤洲徑，蒼崖路幾層。", "翠微深處坐，閒話正留僧。"]'),
('2176e0a4-3213-4705-b132-ecdc34738a55','盤洲雜韻上 雙溪','洪适','宋','宋诗','song-poetry','','[]','清溪夾桃逕，玉洞萬株春。',24,'全唐诗/poet.song.123000.json','["清溪夾桃逕，玉洞萬株春。", "爲有雙溪悞，漁人休問津。"]'),
('6eb66427-ec90-4a1c-81a5-5541f817fbd9','盤洲雜韻上 日涉門','洪适','宋','宋诗','song-poetry','','[]','小圃固日涉，柴門常自關。',24,'全唐诗/poet.song.123000.json','["小圃固日涉，柴門常自關。", "此心無一事，應共白雲閒。"]'),
('f6c4886a-9f2d-4630-9a3a-b7ecdc2808fb','盤洲雜韻上 索笑亭','洪适','宋','宋诗','song-poetry','','[]','虎谿當日事，此處可留蹤。',24,'全唐诗/poet.song.123000.json','["虎谿當日事，此處可留蹤。", "相逢索一笑，何必話中峰。"]'),
('155f7505-4288-4189-ba13-f368a311c1d5','盤洲雜韻上 綠萼梅','洪适','宋','宋诗','song-poetry','','[]','香濃逾粉質，碧膩素娥粧。',24,'全唐诗/poet.song.123000.json','["香濃逾粉質，碧膩素娥粧。", "若使羊郎見，仙姿應並芳。"]'),
('f07267ee-88ab-459f-8e3d-c5b46f71d605','盤洲雜韻上 鴛鴦梅','洪适','宋','宋诗','song-poetry','','[]','疏枝分異蕊，孤幹列鴛鴦。',24,'全唐诗/poet.song.123000.json','["疏枝分異蕊，孤幹列鴛鴦。", "應知爲贈遠，異樣綴清裝。"]'),
('70779076-681a-491d-b8a9-aa5604f131f0','盤洲雜韻上 紅梅','洪适','宋','宋诗','song-poetry','','[]','綻玉聞欺雪，含章妬絳紗。',24,'全唐诗/poet.song.123000.json','["綻玉聞欺雪，含章妬絳紗。", "不同桃李種，粲煞赤城霞。"]'),
('f83f1937-5881-411a-b42c-05a2864cfe62','盤洲雜韻上 臘梅','洪适','宋','宋诗','song-poetry','','[]','籬菊初殘後，疏香忽傲霜。',24,'全唐诗/poet.song.123000.json','["籬菊初殘後，疏香忽傲霜。", "一枝衝臘綻，紫瑰列金房。"]'),
('e62b9924-aba8-4aad-9f5e-d89c97f2c8c4','盤洲雜韻上 黄梅','洪适','宋','宋诗','song-poetry','','[]','未結金丸果，先吐黄芽花。',24,'全唐诗/poet.song.123000.json','["未結金丸果，先吐黄芽花。", "却悞林和靖，翻疑姚氏家。"]'),
('f5ce5ac8-5781-4f5f-bece-72dd25679faf','盤洲雜韻上 芝徑','洪适','宋','宋诗','song-poetry','','[]','金莖豈受塵，三秀已通神。',24,'全唐诗/poet.song.123000.json','["金莖豈受塵，三秀已通神。", "不競銅池瑞，逢蘭肯卜鄰。"]'),
('00657bff-76c4-47d4-a8e7-b0a45d9fc181','盤洲雜韻上 種秫倉','洪适','宋','宋诗','song-poetry','','[]','種秫無多子，猶勝避俗翁。',24,'全唐诗/poet.song.123000.json','["種秫無多子，猶勝避俗翁。", "盡將供釀具，不復用青銅。"]'),
('47f670bc-7008-4ac5-9d37-2b9d083532ac','盤洲雜韻上 芝泉','洪适','宋','宋诗','song-poetry','','[]','美瑞山祇管，幽泉地脈通。',24,'全唐诗/poet.song.123000.json','["美瑞山祇管，幽泉地脈通。", "漱甘冰熨齒，短綆走溪童。"]'),
('792b5d76-fad9-48e9-9c2f-fbfec2bdbeb4','盤洲雜韻上 草塘','洪适','宋','宋诗','song-poetry','','[]','茸茸春草茁，碧水涌方塘。',24,'全唐诗/poet.song.123000.json','["茸茸春草茁，碧水涌方塘。", "入夢無佳句，看雲憶對床。"]'),
('c3e5bee4-7f60-4819-b15a-3365bdbfbce8','盤洲雜韻上 魚臺','洪适','宋','宋诗','song-poetry','','[]','掩關麾俗子，裂網禁畦丁。',24,'全唐诗/poet.song.123000.json','["掩關麾俗子，裂網禁畦丁。", "臺下魚相賀，溪邊人獨醒。"]'),
('42c1f888-1284-4bee-b17f-668efd559f42','盤洲雜韻上 兌橋','洪适','宋','宋诗','song-poetry','','[]','橋橫桑下澗，望處極西郊。',24,'全唐诗/poet.song.123000.json','["橋橫桑下澗，望處極西郊。", "有客同飛蓋，何人伴結茅。"]'),
('54e707be-5941-49e9-a252-a166786c3278','盤洲雜韻上 泛杯巖','洪适','宋','宋诗','song-poetry','','[]','酒進鸕鶿杓，花隨翡翠盤。',24,'全唐诗/poet.song.123000.json','["酒進鸕鶿杓，花隨翡翠盤。", "巖邊多怪石，巖下有奔湍。"]'),
('cb4551c7-1489-4f6b-a5fc-e45e42953bb5','盤洲雜韻上 九曲','洪适','宋','宋诗','song-poetry','','[]','風輕杯蕩漾，岸曲水逶迤。',24,'全唐诗/poet.song.123000.json','["風輕杯蕩漾，岸曲水逶迤。", "遇坎亦可喜，倒行羞接籬。"]'),
('971e6cbd-0c97-45d1-bbac-35e31fe4ab4c','盤洲雜韻上 棕亭','洪适','宋','宋诗','song-poetry','','[]','乞得栟櫚葉，都將當屋茅。',24,'全唐诗/poet.song.123000.json','["乞得栟櫚葉，都將當屋茅。", "青青夸藥申，可怕杜陵嘲。"]'),
('071ee075-8744-46cf-ba15-c2795a75404c','盤洲雜韻上 一詠亭','洪适','宋','宋诗','song-poetry','','[]','有水足浮醴，寧拘秋與春。',24,'全唐诗/poet.song.123000.json','["有水足浮醴，寧拘秋與春。", "共將詩擬古，不必語驚人。"]'),
('b5c86669-a9a5-4f57-bbb4-a1342e0b9338','盤洲雜韻上 小垂手','洪适','宋','宋诗','song-poetry','','[]','醉袖起如舞，翩然三島仙。',24,'全唐诗/poet.song.123000.json','["醉袖起如舞，翩然三島仙。", "約君爲石友，伴我傲林泉。"]'),
('ddc59868-0706-49c8-9329-026b8af00a45','盤洲雜韻上 醒酒石','洪适','宋','宋诗','song-poetry','','[]','名高牛氏品，地接燕兒窠。',24,'全唐诗/poet.song.123000.json','["名高牛氏品，地接燕兒窠。", "有客圖沉醉，翻嫌石是魔。"]'),
('bcc2c4ae-afaf-4754-b71d-422183dfff4f','盤洲雜韻上 墨沼','洪适','宋','宋诗','song-poetry','','[]','鑿地肖風輪，洗雲吞月扇。',24,'全唐诗/poet.song.123000.json','["鑿地肖風輪，洗雲吞月扇。", "敗墨起緇塵，山陰勞北面。"]'),
('59212665-ed66-44af-b9a1-9b80bfdeed7a','盤洲雜韻上 既醉亭','洪适','宋','宋诗','song-poetry','','[]','酒半興方濃，瓶空罍弗耻。',24,'全唐诗/poet.song.123000.json','["酒半興方濃，瓶空罍弗耻。", "更看一籌輸，各盡三觥醉。"]'),
('0d3054cd-2ceb-4307-b8f7-b7e6b4caef64','盤洲雜韻上 溪簾','洪适','宋','宋诗','song-poetry','','[]','雨過溪添綠，橫瀾自在流。',24,'全唐诗/poet.song.123000.json','["雨過溪添綠，橫瀾自在流。", "水精簾欲捲，何處著銀鉤。"]'),
('3ace1911-713f-443a-9141-6be880c28e6b','盤洲雜韻上 可止亭','洪适','宋','宋诗','song-poetry','','[]','循除泉漱石，改席酒分船。',24,'全唐诗/poet.song.123000.json','["循除泉漱石，改席酒分船。", "到此須知止，行前將墜淵。"]'),
('2113535e-5839-4e0c-a2bd-3a1c0721ae7f','盤洲雜韻上 鵝池','洪适','宋','宋诗','song-poetry','','[]','路轉左畫方，水來斜中矩。',24,'全唐诗/poet.song.123000.json','["路轉左畫方，水來斜中矩。", "不解寫黄庭，倚筇看白羽。"]'),
('3b5ceca9-c8e2-4bcf-9a76-5f0672bec299','盤洲雜韻上 流瀑','洪适','宋','宋诗','song-poetry','','[]','高坡勢建瓴，觸石驚濤沸。',24,'全唐诗/poet.song.123000.json','["高坡勢建瓴，觸石驚濤沸。", "入耳轉聲清，廬峽參差是。"]'),
('fe746fb1-3253-419b-8591-46cc8fe10aca','盤洲雜韻上 薝蔔澗','洪适','宋','宋诗','song-poetry','','[]','夾澗榮薝蔔，倚竹顔如玉。',24,'全唐诗/poet.song.123000.json','["夾澗榮薝蔔，倚竹顔如玉。", "溪魚大上時，臨流香可掬。"]'),
('fed0a67c-306b-45cc-9825-b70cbf2a5f32','盤洲雜韻上 菊澨','洪适','宋','宋诗','song-poetry','','[]','夕英色衰落，小摘尚盈襟。',24,'全唐诗/poet.song.123000.json','["夕英色衰落，小摘尚盈襟。", "錯會離騷意，元無滿地金。"]'),
('7fb228f3-b394-4fb1-be4d-52993706b897','盤洲雜韻上 末利菊','洪适','宋','宋诗','song-poetry','','[]','化工將末利，改作壽潭花。',24,'全唐诗/poet.song.123000.json','["化工將末利，改作壽潭花。", "零露團佳色，鵝黄自一家。"]'),
('27f2607f-830e-4581-a260-76183016a702','盤洲雜韻上 雙溪堂','洪适','宋','宋诗','song-poetry','','[]','溪光摇四壁，瓦影落中流。',24,'全唐诗/poet.song.123000.json','["溪光摇四壁，瓦影落中流。", "洗耳百聞寂，清心千慮休。"]'),
('a1e2d873-536d-4007-82b4-c47eec7e73a9','盤洲雜韻上 檥齋','洪适','宋','宋诗','song-poetry','','[]','隨波堪泛宅，因壑遂藏舟。',24,'全唐诗/poet.song.123000.json','["隨波堪泛宅，因壑遂藏舟。", "坐穩無維楫，任他風打頭。"]'),
('4a9f80ac-c038-45f7-8ae6-4ac59f3ace94','盤洲雜韻上 雲葉','洪适','宋','宋诗','song-poetry','','[]','支機何代石，風截秋雲根。',24,'全唐诗/poet.song.123000.json','["支機何代石，風截秋雲根。", "一葉下人境，坐令臺榭尊。"]'),
('88302066-66c8-49fe-9af6-6f99e8c8796c','盤洲雜韻上 嘯風巖','洪适','宋','宋诗','song-poetry','','[]','於菟嘯空山，萬竅寒風出。',24,'全唐诗/poet.song.123000.json','["於菟嘯空山，萬竅寒風出。", "隄防飛將軍，漢箭有神物。"]'),
('e6d43e9f-79cc-4328-9588-24896c990105','盤洲雜韻上 蜂房','洪适','宋','宋诗','song-poetry','','[]','石是蜂窠變，蜂來有處藏。',24,'全唐诗/poet.song.123000.json','["石是蜂窠變，蜂來有處藏。", "不須開戶牖，薜荔爲穿房。"]'),
('d7f9789a-d648-4765-8e93-addb982a6407','盤洲雜韻上 磐磯','洪适','宋','宋诗','song-poetry','','[]','有竿不見綸，無綸焉用餌。',24,'全唐诗/poet.song.123000.json','["有竿不見綸，無綸焉用餌。", "終日坐釣磯，旁人笑兒戲。"]'),
('082f4a26-3cd1-45cb-9638-4728677b3a85','盤洲雜韻上 問柳橋','洪适','宋','宋诗','song-poetry','','[]','濡毫求露柱，墮履望奇書。',24,'全唐诗/poet.song.123000.json','["濡毫求露柱，墮履望奇書。", "問訊緣溪柳，新條可拂裾。"]'),
