('94391486-a5a0-44bc-bee8-89f40eba13e1','雜詠下 玉虹洞','洪适','宋','宋诗','song-poetry','','[]','天晴玉連蜷，洞邃香吞吐。',24,'全唐诗/poet.song.123000.json','["天晴玉連蜷，洞邃香吞吐。", "趁逐牡丹時，游人推不去。"]'),
('46e0445a-ca1f-48ed-9c0f-59682e78c196','雜詠下 綠沈谷','洪适','宋','宋诗','song-poetry','','[]','塞翁馬論谷，山房谷名竹。',24,'全唐诗/poet.song.123000.json','["塞翁馬論谷，山房谷名竹。", "千駟後無聞，一竿清亦足。"]'),
('bf680480-ce9b-42c4-a37d-e1c5018c96a4','雜詠下 聚螢齋','洪适','宋','宋诗','song-poetry','','[]','廣野螢如織，凉郊書好觀。',24,'全唐诗/poet.song.123000.json','["廣野螢如織，凉郊書好觀。", "借光須繼晷，莫遣案頭乾。"]'),
('028ce3b2-d697-4cb9-844a-fb76f6e0ef55','雜詠下 螢','洪适','宋','宋诗','song-poetry','','[]','得夜不韜藏，飛星亂草塘。',24,'全唐诗/poet.song.123000.json','["得夜不韜藏，飛星亂草塘。", "都緣光影誤，無路出書囊。"]'),
('3ac7b9ac-f348-42bf-94ef-4e0e1860a1c9','雜詠下 美可茹亭','洪适','宋','宋诗','song-poetry','','[]','勿誇萬錢食，可畏五鼎烹。',24,'全唐诗/poet.song.123000.json','["勿誇萬錢食，可畏五鼎烹。", "采山逃後悔，碧澗有芹羹。"]'),
('068af2a4-bff6-47eb-aa42-fb4fabfa18c7','雜詠下 蕨','洪适','宋','宋诗','song-poetry','','[]','塊破擎拳出，盤行轉眼空。',24,'全唐诗/poet.song.123000.json','["塊破擎拳出，盤行轉眼空。", "救荒非小補，粉骨不言功。"]'),
('05d3cdc5-ceb9-4cc9-bf77-31d0a1057c10','雜詠下 薺','洪适','宋','宋诗','song-poetry','','[]','犯寒青匝野，信手各盈襜。',24,'全唐诗/poet.song.123000.json','["犯寒青匝野，信手各盈襜。", "不與草爭長，聽教荼比甘。"]'),
('9cca256a-9739-4980-a636-38753ce0bedc','雜詠下 筍','洪适','宋','宋诗','song-poetry','','[]','出羖瘞五皮，獲麟髠一角。',24,'全唐诗/poet.song.123000.json','["出羖瘞五皮，獲麟髠一角。", "煮簀太憨生，非關渠善謔。"]'),
('60dd983a-97a3-401b-8c9a-47661dc8911e','雜詠下 雲起亭','洪适','宋','宋诗','song-poetry','','[]','水窮雲四起，出岫本無心。',24,'全唐诗/poet.song.123000.json','["水窮雲四起，出岫本無心。", "莫負蒼生望，須爲旱歲霖。"]'),
('92f9e2d5-77d0-4c68-9081-0847d4245e27','雜詠下 西戶','洪适','宋','宋诗','song-poetry','','[]','行樂惜分陰，或風雨有疾。',24,'全唐诗/poet.song.123000.json','["行樂惜分陰，或風雨有疾。", "細數一年中，戶開能幾日。"]'),
('bddc1d97-e495-4089-9345-e10613fc7d68','山居二十詠 山居','洪适','宋','宋诗','song-poetry','','[]','經始得山居，幽尋跡不疏。',24,'全唐诗/poet.song.123000.json','["經始得山居，幽尋跡不疏。", "自開溪上徑，花露泣前魚。"]'),
('49522b40-fc94-4ee0-930e-cc95a19db8ea','山居二十詠 竹坡','洪适','宋','宋诗','song-poetry','','[]','有圃無修竹，其如借宅何。',24,'全唐诗/poet.song.123000.json','["有圃無修竹，其如借宅何。", "寧忘三月味，不厭此君多。"]'),
('ff0b322a-f728-4597-b3be-76198f2b7f76','山居二十詠 芝榭','洪适','宋','宋诗','song-poetry','','[]','筑榭芝山麓，仍年再產芝。',24,'全唐诗/poet.song.123000.json','["筑榭芝山麓，仍年再產芝。", "欲求茹芝法，已與赤松期。"]'),
('bfc1cef2-7a01-49ad-ab55-f8def5fe19a6','山居二十詠 樵徑','洪适','宋','宋诗','song-poetry','','[]','松釵藏曲徑，林浪積枯枝。',24,'全唐诗/poet.song.123000.json','["松釵藏曲徑，林浪積枯枝。", "足了園炊用，何須壞扊扅。"]'),
('8f41e663-4a21-44d4-a050-0d53b7e707d1','山居二十詠 茶丘','洪适','宋','宋诗','song-poetry','','[]','半世別玉州，夢憶仙人掌。',24,'全唐诗/poet.song.123000.json','["半世別玉州，夢憶仙人掌。", "經丘獲鎗旗，清思飄雲上。"]'),
('89a23aa7-21ff-440f-9381-cea33297dc42','山居二十詠 栗嶺','洪适','宋','宋诗','song-poetry','','[]','霜栗大如拳，皺開穰獻熟。',24,'全唐诗/poet.song.123000.json','["霜栗大如拳，皺開穰獻熟。", "借問嘉卉山，何如白鴉谷。"]'),
('504bf76c-153e-464e-9da4-713965c8614a','山居二十詠 茅軒','洪适','宋','宋诗','song-poetry','','[]','翦茅聊復爾，步屧欲何之。',24,'全唐诗/poet.song.123000.json','["翦茅聊復爾，步屧欲何之。", "風捲三重去，危簷雀護兒。"]'),
('2da2e372-19db-477d-9559-57aed1cd5d9d','山居二十詠 蜂廬','洪适','宋','宋诗','song-poetry','','[]','分窠能擇地，識路自尋花。',24,'全唐诗/poet.song.123000.json','["分窠能擇地，識路自尋花。", "不候譙門鼓，群飛晚趁衙。"]'),
('fea02628-7627-4b05-a2ac-5572bde6a709','山居二十詠 情話齋','洪适','宋','宋诗','song-poetry','','[]','意到非饒舌，情親易解頤。',24,'全唐诗/poet.song.123000.json','["意到非饒舌，情親易解頤。", "或時鐺脚坐，不效劍頭炊。"]'),
('140eb1db-fb87-4b3f-8ce9-923bfd72d173','山居二十詠 榴花城','洪适','宋','宋诗','song-poetry','','[]','榴艷對枯筇，西來解后同。',24,'全唐诗/poet.song.123000.json','["榴艷對枯筇，西來解后同。", "折花羞鬢白，未插已顔紅。"]'),
('af871166-07e1-46d1-828a-0eed2a5c6551','山居二十詠 錦被堆','洪适','宋','宋诗','song-poetry','','[]','錦衾鋪綠野，山麝可曾眠。',24,'全唐诗/poet.song.123000.json','["錦衾鋪綠野，山麝可曾眠。", "蕙帳塵凝席，花殘鶴惘然。"]'),
('45cbea47-8639-4522-9396-67085aca09da','山居二十詠 頳桐','洪适','宋','宋诗','song-poetry','','[]','花涵百日紅，色到三秋重。',24,'全唐诗/poet.song.123000.json','["花涵百日紅，色到三秋重。", "葉大好題詩，叢卑難集鳳。"]'),
('c3c63ed2-4bfc-4dfc-bbd5-673800f265ce','山居二十詠 雙魚','洪适','宋','宋诗','song-poetry','','[]','犀角透魚龍，石肌藴星斗。',24,'全唐诗/poet.song.123000.json','["犀角透魚龍，石肌藴星斗。", "亦有無情花，枝頭魚貫柳。"]'),
('e92e6ae5-b7c9-4a7f-b51f-9b0ff992b127','山居二十詠 薔薇','洪适','宋','宋诗','song-poetry','','[]','竹外霞爲幄，花間錦作籬。',24,'全唐诗/poet.song.123000.json','["竹外霞爲幄，花間錦作籬。", "離宮多怨女，吃吃竟亡隋。"]'),
('7930306c-4ee8-4813-8849-e2386fd39554','山居二十詠 迎春','洪适','宋','宋诗','song-poetry','','[]','桃杏正酣酣，光春當仲月。',24,'全唐诗/poet.song.123000.json','["桃杏正酣酣，光春當仲月。", "吐艷既後時，嘉名安可竊。"]'),
('4a06c003-6b8b-401e-b483-a26117f4b32b','山居二十詠 長生草','洪适','宋','宋诗','song-poetry','','[]','經時久枯槁，得水即青葱。',24,'全唐诗/poet.song.123000.json','["經時久枯槁，得水即青葱。", "起死醫無藥，返魂香有功。"]'),
('fd696d11-e1c9-41d0-961f-c9469cfb3d64','山居二十詠 雲松關','洪适','宋','宋诗','song-poetry','','[]','葉生新易舊，歲寒凋獨後。',24,'全唐诗/poet.song.123000.json','["葉生新易舊，歲寒凋獨後。", "不改四時柯，賢言非聖耦。"]'),
('4f8752e6-9cc8-49dc-9c1b-d23e4ddc7a0f','山居二十詠 山樊','洪适','宋','宋诗','song-poetry','','[]','蘂碎葉傷多，風韻弗娛目。',24,'全唐诗/poet.song.123000.json','["蘂碎葉傷多，風韻弗娛目。", "獨抱絕塵香，無心出幽谷。"]'),
('50360057-7c3a-4587-9cab-4fe10f91157c','山居二十詠 躑躅崦','洪适','宋','宋诗','song-poetry','','[]','一氣浹群芳，漫山躑躅黄。',24,'全唐诗/poet.song.123000.json','["一氣浹群芳，漫山躑躅黄。", "有誰相領略，自解度春光。"]'),
('37122ac0-43ea-45d6-8cfd-731fff24de1e','山居二十詠 草野','洪适','宋','宋诗','song-poetry','','[]','發生寧有種，滋蔓妨人路。',24,'全唐诗/poet.song.123000.json','["發生寧有種，滋蔓妨人路。", "不得十月霜，掃除難盡去。"]'),
('79989e2a-930a-4930-8654-10f01965e498','錢伸仲挽詩二首  其一','洪适','宋','宋诗','song-poetry','','[]','佩蘭扈芷楚三閭，騁祕抽妍漢子虛。',64,'全唐诗/poet.song.123000.json','["佩蘭扈芷楚三閭，騁祕抽妍漢子虛。", "甘向黑頭辭印綬，肯將白眼對圖書。", "清規盡入先賢傳，繡帳空馳長者車。", "千里纏悲付虞殯，西風吹淚著襟裾。"]'),
('ff93b886-66b8-4578-91f1-61794fafba01','錢伸仲挽詩二首  其二','洪适','宋','宋诗','song-poetry','','[]','秋來鴻羽得新文，不謂回封限九原。',64,'全唐诗/poet.song.123000.json','["秋來鴻羽得新文，不謂回封限九原。", "起起若爲償歲夢，嘻嘻無復對朝言。", "一編徒挂延陵劍，三徑誰開靖節樽。", "塵迹蓋棺渾莫問，墓頭黄石拜兒孫。"]'),
('7f042d32-8e70-4fff-b535-1a6827f80f25','程通判挽詩二首  其一','洪适','宋','宋诗','song-poetry','','[]','力行先孝友，潜處伴耕樵。',48,'全唐诗/poet.song.123000.json','["力行先孝友，潜處伴耕樵。", "日奉斑衣戲，風移尺布謠。", "白頭方得祿，朱紱便登朝。", "車作驊騮折，松烟喝鼓簫。"]'),
('4164f128-50a6-470f-855c-524f2c0634ec','程通判挽詩二首  其二','洪适','宋','宋诗','song-poetry','','[]','日游通德里，會面蓋先傾。',48,'全唐诗/poet.song.123000.json','["日游通德里，會面蓋先傾。", "我作南垂去，君成東蓼行。", "忽持芻束奠，忍聽薤歌聲。", "爲看三珠樹，門高莫與京。"]'),
('5454f5ad-0d9f-4d86-a4c9-f4d5f98ca201','熊直閣挽詩二首  其一','洪适','宋','宋诗','song-poetry','','[]','文石榮三接，君王膝屢前。',48,'全唐诗/poet.song.123000.json','["文石榮三接，君王膝屢前。", "蒲鞭如漢日，鹽筴有蘇天。", "未上甘泉道，俄開京兆阡。", "傳家文史足，不在一囊錢。"]'),
('101a47dc-4a88-4bb7-824d-05e656e794ff','熊直閣挽詩二首  其二','洪适','宋','宋诗','song-poetry','','[]','居巷相南北，登門久歲時。',48,'全唐诗/poet.song.123000.json','["居巷相南北，登門久歲時。", "溫言流肺腑，和氣見須眉。", "日昃長沙傅，年凋絳縣師。", "春雲冒丹旐，同會袂成帷。"]'),
('ed5d14a2-50e1-4536-b00d-82182f7d8f0f','中大族伯挽詩二首  其一','洪适','宋','宋诗','song-poetry','','[]','笑談登月窟，轉盼戛天池。',48,'全唐诗/poet.song.123000.json','["笑談登月窟，轉盼戛天池。", "十載董狐筆，兩州龔遂祠。", "文章傳古法，名姓畏人知。", "忽作龍蛇夢，今無甲子疑。"]'),
('d77eeede-dab1-4442-828d-caf33428332c','中大族伯挽詩二首  其二','洪适','宋','宋诗','song-poetry','','[]','久矣宮盤谷，幡然筑大逵。',48,'全唐诗/poet.song.123000.json','["久矣宮盤谷，幡然筑大逵。", "方瞻烏亦好，已問鵩何之。", "無復竹林會，忍聞蒿里期。", "行行遡西日，有淚若連絲。"]'),
('f127fa65-e6fa-4a54-a237-04c82d155df5','朱承事挽詩','洪适','宋','宋诗','song-poetry','','[]','鄉關聞德耀，子姓有佳聲。',48,'全唐诗/poet.song.123000.json','["鄉關聞德耀，子姓有佳聲。", "五十貴不驗，三千功已成。", "山幽雙劍合，桂近一枝榮。", "他日先賢傳，求之月旦評。"]'),
('a82a30a5-800c-4b93-8af8-5e6c3c513e9f','臧縣尉挽詩','洪适','宋','宋诗','song-poetry','','[]','共在鄉人後，相高君子前。',48,'全唐诗/poet.song.123000.json','["共在鄉人後，相高君子前。", "家聲郜大鼎，利器楚龍淵。", "不相買臣貴，竟傳梅福仙。", "只令空漬酒，落筆更悽然。"]'),
('3974408c-0c6b-49ed-b543-4774ecf60a2d','程參政挽詩三首  其一','洪适','宋','宋诗','song-poetry','','[]','身近長安日，官無州縣勞。',48,'全唐诗/poet.song.123000.json','["身近長安日，官無州縣勞。", "黄麻襲姚姒，赤舄等伊咎。", "量與南溟闊，名如北斗高。", "十年蟠綠野，軒冕一秋毫。"]'),
('2fb7858e-8589-4e57-96cd-983c50095fc2','程參政挽詩三首  其二','洪适','宋','宋诗','song-poetry','','[]','聖主更琴瑟，真儒政事參。',48,'全唐诗/poet.song.123000.json','["聖主更琴瑟，真儒政事參。", "上階占兩兩，東第得潭潭。", "忽卧漳濱疾，虛傳澠水談。", "驊騮好千里，底事學吳蠶。"]'),
('d628f53a-5a1c-4ea3-aef6-b56e6ccb4a42','程參政挽詩三首  其三','洪适','宋','宋诗','song-poetry','','[]','一顧駑增價，兼收雁作行。',48,'全唐诗/poet.song.123000.json','["一顧駑增價，兼收雁作行。", "篇章非子墨，藻鑒誤雌黄。", "雲淡番君國，年荒陸氏莊。", "眼看飛旐出，雨泣漫淋浪。"]'),
('27b5d414-0aab-4304-adae-b7c6023c406b','李沅州挽詩二首  其一','洪适','宋','宋诗','song-poetry','','[]','籍籍臺郎日，臯蘇遠拍肩。',48,'全唐诗/poet.song.123000.json','["籍籍臺郎日，臯蘇遠拍肩。", "疏陳三尺法，制可九重天。", "不使金橫带，俄驚酒漬綿。", "平亭知有報，高蓋拂修椽。"]'),
('96cb6282-4f92-4e98-9986-f7a2c3c5eebf','李沅州挽詩二首  其二','洪适','宋','宋诗','song-poetry','','[]','朱轓今素幔，歸路乃長迷。',48,'全唐诗/poet.song.123000.json','["朱轓今素幔，歸路乃長迷。", "露菊荒三逕，春棠疊五溪。", "新丘悲寓馬，陳迹記談犀。", "淚迸無乾袖，重雲入望低。"]'),
('b135b37e-00d9-4c5e-9f65-6c0bb9467f01','程司戶挽詩','洪适','宋','宋诗','song-poetry','','[]','把酒論詩日，高標迥絕塵。',48,'全唐诗/poet.song.123000.json','["把酒論詩日，高標迥絕塵。", "那知三語掾，便作百年人。", "山霧鉻旌濕，松風挽鐸頻。", "流光須有後，何必在其身。"]'),
('f23df742-0073-4222-aa65-a667ba53f7a6','程樞母永嘉郡夫人挽詩二首  其一','洪适','宋','宋诗','song-poetry','','[]','華族鳴徽久，閨風藹德門。',47,'全唐诗/poet.song.123000.json','["華族鳴徽久，閨風藹德門。", "鴻樞看子貴，象揥君恩。", "純孝纏吹棘，端憂隕得萱。", "板輿無復御，舊迹識家園。"]'),
('fa934096-fee2-4f81-bb20-76ff0b4aa856','程樞母永嘉郡夫人挽詩二首  其二','洪适','宋','宋诗','song-poetry','','[]','赫奕家聲振，吾鄉今所稀。',48,'全唐诗/poet.song.123000.json','["赫奕家聲振，吾鄉今所稀。", "北堂黄髮壽，西府黑頭歸。", "方羨含飴樂，俄聞侍膳非。", "萬家旁置處，空愴白雲飛。"]'),
('1530b8a9-61f8-48f2-913d-948050829d21','郭太尉挽詩','洪适','宋','宋诗','song-poetry','','[]','閒適珍臺腆舊儀，趣歸方俟詔封泥。',64,'全唐诗/poet.song.123000.json','["閒適珍臺腆舊儀，趣歸方俟詔封泥。", "人生七十古猶少，執政二三今與齊。", "忽見墓門陳石馬，空懷賓閣奉金犀。", "不須知識方流涕，處處俱成桃李蹊。"]'),
('0331fdcc-5420-4e28-8be8-4314877fa588','羅尚書挽詩三首  其一','洪适','宋','宋诗','song-poetry','','[]','周旋儀禁路，契合本孤忠。',48,'全唐诗/poet.song.123000.json','["周旋儀禁路，契合本孤忠。", "帝識尚書履，人驚御史驄。", "貴名青史上，讜論皂囊中。", "不入三台志，鹽梅事竟空。"]'),
('40805b60-5101-48c1-bfe8-a2ee0ec3d75e','羅尚書挽詩三首  其二','洪适','宋','宋诗','song-poetry','','[]','當年持從橐，白髮奉親闈。',48,'全唐诗/poet.song.123000.json','["當年持從橐，白髮奉親闈。", "安否君王問，尊榮簡策稀。", "祥琴曾未御，丹旐已同飛。", "蕭瑟千章柏，深藏五彩衣。"]'),
('91fc65e1-7b51-4f53-8e03-19b8a9f409aa','羅尚書挽詩三首  其三','洪适','宋','宋诗','song-poetry','','[]','連蹇魚符忝，宗師藻鑑亡。',48,'全唐诗/poet.song.123000.json','["連蹇魚符忝，宗師藻鑑亡。", "但瞻楊子宅，莫避蓋公堂。", "遠水松區對，東風紼路長。", "九原精爽在，遺恨一莊荒。"]'),
('fd3ccdce-9288-4c88-b1ce-001c9846ac50','向通判挽詩二首  其一','洪适','宋','宋诗','song-poetry','','[]','屢薦聲名白，低飛鬢髮蒼。',48,'全唐诗/poet.song.123000.json','["屢薦聲名白，低飛鬢髮蒼。", "平生幾朱紱，夢寐一黄粱。", "利刃盤根出，明珠後乘光。", "洪都囚不死，陰德未渠央。"]'),
('89bb45ef-628a-4f8f-9a13-614edb1ed300','向通判挽詩二首  其二','洪适','宋','宋诗','song-poetry','','[]','里社承顔舊，情非數面親。',48,'全唐诗/poet.song.123000.json','["里社承顔舊，情非數面親。", "令名高月旦，和氣藹陽春。", "乍闊談揮麈，俄驚冢卧麟。", "濡毫記遺事，顧我不如人。"]'),
('6c2c4a71-1787-411c-87ad-78ba86fc84a7','俞淑人挽詩','洪适','宋','宋诗','song-poetry','','[]','名父尹京日，移天冠柏臺。',48,'全唐诗/poet.song.123000.json','["名父尹京日，移天冠柏臺。", "齊眉豐俎豆，繼踵蛻塵埃。", "德比人如玉，情鍾子在梅。", "山高雲不去，虞殯有餘哀。"]'),
('bd5ba82a-fabc-47f1-9b54-79047091a6d7','何宜人挽詩','洪适','宋','宋诗','song-poetry','','[]','心了金剛偈，身膺石窌封。',48,'全唐诗/poet.song.123000.json','["心了金剛偈，身膺石窌封。", "靈津雙劍合，平壤萬家容。", "感慕風吹棘，悲凉霧喝松。", "鄉人清淚落，可但輟鄰舂。"]'),
('9ceb1f34-d59d-4d88-bf68-62c32eef7dc2','魏恭人挽詩','洪适','宋','宋诗','song-poetry','','[]','儒門傳禮法，婦道有初終。',48,'全唐诗/poet.song.123000.json','["儒門傳禮法，婦道有初終。", "石窌重封貴，金章上壽同。", "含飴談往日，吹棘愴來風。", "紼路芻靈隘，春朝里巷空。"]'),
('9a9ad514-7aeb-4252-b2e1-f219bad4f6fe','沈淑人挽詩','洪适','宋','宋诗','song-poetry','','[]','尊章歡二姓，八座對厖眉。',48,'全唐诗/poet.song.123000.json','["尊章歡二姓，八座對厖眉。", "井井傳家法，繩繩賴母儀。", "川靈雙劍躍，壤吉萬家移。", "多少龍灣樹，雲藏不盡悲。"]'),
('436531d8-a7f5-49ef-89a9-efb5495d3492','余吏部挽詩三首  其一','洪适','宋','宋诗','song-poetry','','[]','石月顓門學，儒林譽翕然。',48,'全唐诗/poet.song.123000.json','["石月顓門學，儒林譽翕然。", "虀鹽家有塾，菽水坐無氈。", "孝永趨庭日，名成佩韘年。", "流芳千載下，不減漢韋賢。"]'),
('916321bd-ccea-4322-8aa8-3621e03169ba','余吏部挽詩三首  其二','洪适','宋','宋诗','song-poetry','','[]','入臺光六察，言事過同寮。',48,'全唐诗/poet.song.123000.json','["入臺光六察，言事過同寮。", "可畏觸邪豸，元非開口椒。", "召來仍襆被，老去但乘軺。", "未報蒲輪聘，巫陽已下招。"]'),
('a51120d8-fbb9-4b35-af74-6c1b3ab652c6','余吏部挽詩三首  其三','洪适','宋','宋诗','song-poetry','','[]','清音扁新閣，山色送溪聲。',48,'全唐诗/poet.song.123000.json','["清音扁新閣，山色送溪聲。", "尚欠題詩債，難尋把酒盟。", "囊空無長物，甑墮底浮名。", "紼路它州遠，臨風淚睫橫。"]'),
('5fef194a-fbee-4809-90ea-ed84eeea21c4','章通判挽詩二首  其一','洪适','宋','宋诗','song-poetry','','[]','丹霄箝薦口，白首滯微官。',48,'全唐诗/poet.song.123000.json','["丹霄箝薦口，白首滯微官。", "涉世無圭角，論交出肺肝。", "翔鸞說秋浦，展驥到新安。", "泉下齎遺恨，絲綸趣挂冠。"]'),
('268d3a6d-8278-4e97-990d-c752c3320d10','章通判挽詩二首  其二','洪适','宋','宋诗','song-poetry','','[]','富州春再見，風月款平分。',48,'全唐诗/poet.song.123000.json','["富州春再見，風月款平分。", "翠竹曾留我，紅梅獨對君。", "遣書成挂劍，揮涕屢霑巾。", "千里佳城閉，哀笳不得聞。"]'),
('be9984ff-cf75-486a-a9ab-7044b84248c9','陳左相挽詩三首  其一','洪适','宋','宋诗','song-poetry','','[]','盛德波千頃，清風偃俊躔。',48,'全唐诗/poet.song.123000.json','["盛德波千頃，清風偃俊躔。", "兩朝隆柱石，四海入陶甄。", "致主唐虞上，齊名房杜前。", "期頤慳上壽，底處問蒼天。"]'),
('48c88595-903d-4087-9299-e35f2f57a35b','陳左相挽詩三首  其二','洪适','宋','宋诗','song-poetry','','[]','往昔旄頭起，群心共震驚。',48,'全唐诗/poet.song.123000.json','["往昔旄頭起，群心共震驚。", "指麾戎幕固，談笑虜巢傾。", "繡黼重當國，氈裘即歛兵。", "巖巖謝安石，不數晉公卿。"]'),
('595615d4-36a7-4f51-879c-bf77c7aa21fb','陳左相挽詩三首  其三','洪适','宋','宋诗','song-poetry','','[]','天意尊黄髮，人扶上玉墀。',48,'全唐诗/poet.song.123000.json','["天意尊黄髮，人扶上玉墀。", "傳呼晝接後，邂逅日斜時。", "瞻仰三台坼，淪亡一鑑悲。", "千秋名不朽，奎畫在豐碑。"]'),
('c111f4d8-4577-4105-afbc-ef28d48f6e1b','楊和王挽詩二首  其一','洪适','宋','宋诗','song-poetry','','[]','矍鑠狨韉出，魁梧玉带輕。',48,'全唐诗/poet.song.123000.json','["矍鑠狨韉出，魁梧玉带輕。", "良家三世將，幕府萬人英。", "長嘯臨天塹，妖氛散虜營。", "黄壚有遺恨，不見朔方平。"]'),
('8cce02b8-b919-4e6a-a2d1-b7bdca2ff9fd','楊和王挽詩二首  其二','洪适','宋','宋诗','song-poetry','','[]','三紀羽林衛，千秋彝鼎銘。',48,'全唐诗/poet.song.123000.json','["三紀羽林衛，千秋彝鼎銘。", "拔材多男爵，教子寶遺經。", "淮上開王社，雲邊落將星。", "後來思燕頷，麟閣仰丹青。"]'),
('ec361fee-1b4f-42e1-8c85-e69dbd0ff83a','許倩幼失所恃得地辦葬名其亭曰棘風求詩紀事','洪适','宋','宋诗','song-poetry','','[]','擇鄰傳懿範，負土踵前規。',48,'全唐诗/poet.song.123000.json','["擇鄰傳懿範，負土踵前規。", "回首樹萱錄，動心吹棘詩。", "幽亭三鼎變，吉壤萬家隨。", "度曲薰絃絕，臨風淚滿頤。"]'),
('fcda1ae9-0702-4b00-85a2-cc2d86804ad1','汪德邵挽詩','洪适','宋','宋诗','song-poetry','','[]','監郡能名播，分符治行高。',48,'全唐诗/poet.song.123000.json','["監郡能名播，分符治行高。", "俄驚駒過隙，不見鶴鳴皋。", "三徑賓朋散，重樓柱石牢。", "傷心丹旐舉，舊事記松醪。"]'),
('4967084a-780e-4218-ac2d-8c4c1fb732f4','彭叔容挽詩','洪适','宋','宋诗','song-poetry','','[]','襟宇無畦町，鄉評有譽言。',48,'全唐诗/poet.song.123000.json','["襟宇無畦町，鄉評有譽言。", "宦途材智出，名閥典刑存。", "未試牛刀手，俄招馬鬣魂。", "有懷尊酒日，揮淚北山昏。"]'),
('a7558b0e-90ab-4b77-a135-f63e80710406','章令人挽詩','洪适','宋','宋诗','song-poetry','','[]','肥家尊淑範，閱世悟浮漚。',48,'全唐诗/poet.song.123000.json','["肥家尊淑範，閱世悟浮漚。", "風棘慈顔隔，堂萱子舍憂。", "六珈齊上壽，一劍躍中流。", "紼路傾鄰曲，凄其松露秋。"]'),
('ce219bd2-1497-4088-b0c7-ba486379a153','梁竑夫挽詩二首  其一','洪适','宋','宋诗','song-poetry','','[]','材高易盤錯，語妙出波瀾。',48,'全唐诗/poet.song.123000.json','["材高易盤錯，語妙出波瀾。", "和氣如春暖，交情耐歲寒。", "牧民千里治，奉使五刑寬。", "杖屨懷陳迹，琴亡曲罷彈。"]'),
('a6b56131-6575-48dd-845d-798ed24684a6','梁竑夫挽詩二首  其二','洪适','宋','宋诗','song-poetry','','[]','向來持國秉，貢禹合彈冠。',48,'全唐诗/poet.song.123000.json','["向來持國秉，貢禹合彈冠。", "予節緣心計，飛章或面謾。", "開陳疑已釋，騰躍事非難。", "覆餗長緘恨，何知便蓋棺。"]'),
('5df943cb-33da-4458-8429-8bbf58fd1b12','魏彥誠挽詩三首  其一','洪适','宋','宋诗','song-poetry','','[]','星文推獨步，風采偃先聲。',48,'全唐诗/poet.song.123000.json','["星文推獨步，風采偃先聲。", "沉慮千人廢，高談一坐傾。", "蘇枯崇治效，去草折姦萌。", "春霧新阡暗，裁詩淚睫橫。"]'),
('59a8ac48-0c11-4d9c-acbb-2f64166ee064','魏彥誠挽詩三首  其二','洪适','宋','宋诗','song-poetry','','[]','偃月欺天日，淫刑及反脣。',48,'全唐诗/poet.song.123000.json','["偃月欺天日，淫刑及反脣。", "程論傳學者，粵嶺作流人。", "貽後端無憾，瞻前詎有鄰。", "太剛終齟齬，袖手老江濱。"]'),
('b2f376d5-493f-4617-a894-27bba757ccb2','魏彥誠挽詩三首  其三','洪适','宋','宋诗','song-poetry','','[]','昔年同攬轡，累日到門闌。',48,'全唐诗/poet.song.123000.json','["昔年同攬轡，累日到門闌。", "題竹飛松管，觀魚走玉槃。", "著鞭顔有媿，推轂力何難。", "翻坐葭莩累，塵凝貢氏冠。"]'),
('906f72ce-c48f-4757-8a52-42a5527a5e42','汪樞使挽詩二首  其一','洪适','宋','宋诗','song-poetry','','[]','兩朝尊輔拂，一德贊規恢。',48,'全唐诗/poet.song.123000.json','["兩朝尊輔拂，一德贊規恢。", "簡劾人所畏，囊封天可回。", "指揮兵事密，談笑塞氛開。", "尺五魁三象，俄驚山嶽頹。"]'),
('05414ac9-2bfe-40d4-91b4-c93e3db4f2ff','汪樞使挽詩二首  其二','洪适','宋','宋诗','song-poetry','','[]','天陛黄麻出，同時拜寵榮。',48,'全唐诗/poet.song.123000.json','["天陛黄麻出，同時拜寵榮。", "薦賢窺汲引，謀國冀升平。", "睽闊仍寒暑，吁嗟隔死生。", "門人有碑誄，不數漢公卿。"]'),
('9b47e31a-3d88-4ae8-bd21-90677fabd453','榮國李夫人挽詩','洪适','宋','宋诗','song-poetry','','[]','斗樞光梓里，壺德講魚軒。',48,'全唐诗/poet.song.123000.json','["斗樞光梓里，壺德講魚軒。", "教子詩書足，齊家禮法尊。", "相隨雙劍逝，來弔一芻存。", "松霧銘旌暗，悲歌塞墓門。"]'),
('dc5e9cad-b8a1-4f68-a202-b13dc7d8ede3','許碩人挽詩','洪适','宋','宋诗','song-poetry','','[]','敬蘭光相閥，采藻助儒宗。',48,'全唐诗/poet.song.123000.json','["敬蘭光相閥，采藻助儒宗。", "偕老金犀貴，增封石窌重。", "川深雙劍合，壤吉萬家容。", "遥想銘旌舉，悲風喝霧松。"]'),
('4e971b51-b90b-4b8c-99f9-72cbe847f72d','向侍郎挽詩二首  其一','洪适','宋','宋诗','song-poetry','','[]','策足王城日，聲名顯妙年。',48,'全唐诗/poet.song.123000.json','["策足王城日，聲名顯妙年。", "剸裁無肯綮，施置不拘牽。", "驚坐瞻揮麈，豐財賴算鞭。", "中興良吏盛，佳傳壓甘泉。"]'),
('46b17792-037e-41e3-bfad-e76d0400c38b','向侍郎挽詩二首  其二','洪适','宋','宋诗','song-poetry','','[]','沃轡環天下，澄清今范滂。',48,'全唐诗/poet.song.123000.json','["沃轡環天下，澄清今范滂。", "带牛姦破穴，問馬智盈囊。", "踰七春秋足，尊三爵德光。", "鄉閭失耆舊，紼路送車忙。"]'),
('62fd857b-093a-4d3b-8f2a-043365a0f794','余文特挽詩','洪适','宋','宋诗','song-poetry','','[]','决科榮彩服，諾仕振芳埃。',48,'全唐诗/poet.song.123000.json','["决科榮彩服，諾仕振芳埃。", "金玉胸懷好，珠璣言語堆。", "一麾臨白首，八載厄黄能。", "情話今陳迹，悲悰衮衮來。"]'),
('32c1ea04-a162-4e94-bc61-f77facba47a0','張待制挽詩','洪适','宋','宋诗','song-poetry','','[]','松關辭舊隱，平步漢甘泉。',48,'全唐诗/poet.song.123000.json','["松關辭舊隱，平步漢甘泉。", "破虜資長策，豐財簡細旃。", "救荒陰德大，尚齒達尊全。", "觴豆懷陳迹，風悲馬鬣阡。"]'),
('58fde036-b58f-478d-a546-620a604d1abe','彭仲光挽詩','洪适','宋','宋诗','song-poetry','','[]','吉德傳鄉黨，家聲企大儒。',48,'全唐诗/poet.song.123000.json','["吉德傳鄉黨，家聲企大儒。", "九霄欣得路，五馬議分符。", "歎息人琴逝，凄凉鄰曲孤。", "霜風丹旐舉，松霧暗黄壚。"]'),
('f663150b-3495-425c-8b82-0ece759cb425','樞弟挽詩三首  其一','洪适','宋','宋诗','song-poetry','','[]','少小猶朋友，陳編晝夜開。',48,'全唐诗/poet.song.123000.json','["少小猶朋友，陳編晝夜開。", "同時題雁塔，旬月聚麟臺。", "詞掖君先達，臺階我後來。", "傷心今古隔，楚挽不勝哀。"]'),
('d544940f-8b6b-41f6-8e72-f43db53e96f8','樞弟挽詩三首  其二','洪适','宋','宋诗','song-poetry','','[]','投老開三逕，聯翩北郭門。',48,'全唐诗/poet.song.123000.json','["投老開三逕，聯翩北郭門。", "嘲花詩插架，對竹酒盈尊。", "歎息千秋宅，荒凉十畝園。", "談叢鐺折脚，雲暗脊令原。"]'),
('1d4b2471-80c8-46fe-a675-ef245858a3f2','樞弟挽詩三首  其三','洪适','宋','宋诗','song-poetry','','[]','靜鎮多遺愛，存橋有遠謀。',48,'全唐诗/poet.song.123000.json','["靜鎮多遺愛，存橋有遠謀。", "禁林傳大冊，宥地簡前旒。", "疾也勞心得，生乎撒手休。", "三年棠棣徑，倚杖淚爭流。"]'),
('25fa6afc-8879-47cb-8e35-1e26749081b8','陳公秀吏部挽詩','洪适','宋','宋诗','song-poetry','','[]','頃陟詞壇日，初瞻雁塔名。',48,'全唐诗/poet.song.123000.json','["頃陟詞壇日，初瞻雁塔名。", "坐氈甘獨冷，揭節守真清。", "蠭蠆能陰中，驊騮使却行。", "佳城千里外，無處送銘旌。"]'),
('22914eaf-5d8d-41d7-8266-6de5f5e7a0fb','張龍學挽詩二首  其一','洪适','宋','宋诗','song-poetry','','[]','今代風雲會，何人善論兵。',48,'全唐诗/poet.song.123000.json','["今代風雲會，何人善論兵。", "丹墀凝睿想，黄石踵家聲。", "瑞國儀千仞，籌邊妙兩楹。", "重泉有遺恨，不見復神京。"]'),
('0905366c-6331-4d02-bfa1-bf6ef2c49473','張龍學挽詩二首  其二','洪适','宋','宋诗','song-poetry','','[]','中臺雙挈橐，重鎮四分符。',48,'全唐诗/poet.song.123000.json','["中臺雙挈橐，重鎮四分符。", "井地觀佳政，林蠻鑠異圖。", "犁添長樂犢，鞭截豫章蒲。", "處處甘棠淚，黄童白叟俱。"]'),
('55196796-5314-4cd9-a0f7-80089f2059a4','周尚書挽詩二首  其一','洪适','宋','宋诗','song-poetry','','[]','九師迷易說，皇極倡先天。',48,'全唐诗/poet.song.123000.json','["九師迷易說，皇極倡先天。", "學苦韋編絕，名高雁塔懸。", "朱轓多惠露，紫橐表甘泉。", "歎息佳城閉，喬松鎖暮烟。"]'),
('a784a2be-0f52-4510-ad91-85299d8e20c9','周尚書挽詩二首  其二','洪适','宋','宋诗','song-poetry','','[]','憶昨登瀛日，官曹幸接聯。',48,'全唐诗/poet.song.123000.json','["憶昨登瀛日，官曹幸接聯。", "再來聞國論，及見上經筵。", "淵識闚靈憲，嘉謨湊細旃。", "生芻千里奠，覓句一潸然。"]'),
('a337a8ef-a3f0-4002-a224-ab3b054e4092','姚參政挽詩二首  其一','洪适','宋','宋诗','song-poetry','','[]','發軔詞壇日，曾同蕭寺盟。',48,'全唐诗/poet.song.123000.json','["發軔詞壇日，曾同蕭寺盟。", "望洋吞渤澥，歷塊指幽并。", "不競二三策，難淹九萬程。", "君王顓賜第，千佛漫聯名。"]'),
('7ed1bbde-6c49-4616-be42-08b266e35a5a','姚參政挽詩二首  其二','洪适','宋','宋诗','song-poetry','','[]','晉晝光三接，霜臺肅紀綱。',48,'全唐诗/poet.song.123000.json','["晉晝光三接，霜臺肅紀綱。", "栽培指佞草，重疊上書囊。", "筆橐留施設，鈞樞憶贊襄。", "傷心左溪路，松檜已成行。"]'),
('4c79978b-1998-4176-a242-7e03bf224e8c','周知郡挽詩','洪适','宋','宋诗','song-poetry','','[]','德比圭璋潤，言如布帛溫。',48,'全唐诗/poet.song.123000.json','["德比圭璋潤，言如布帛溫。", "休心馳官路，寓意傲家園。", "侯國思遺愛，吾鄉欠達尊。", "佳城鄰別墅，松霧望中昏。"]'),
('8e2e94f9-51f1-4e43-a42f-c7edced81d38','葉提刑挽詩','洪适','宋','宋诗','song-poetry','','[]','冠带橋門擁，曾披星斗文。',48,'全唐诗/poet.song.123000.json','["冠带橋門擁，曾披星斗文。", "屬鞬尋耿賈，投筆遠淵雲。", "獻納頻三接，平反自一欣。", "凄凉真率會，鷗鷺也離群。"]'),
('64510b8f-e195-4198-9ad0-6b974c8b5729','彭叔陽挽詩','洪适','宋','宋诗','song-poetry','','[]','買鄰喬木近，不隔一牛鳴。',48,'全唐诗/poet.song.123000.json','["買鄰喬木近，不隔一牛鳴。", "甲第夸新作，高樓待落成。", "未教長縱壑，亦合且專城。", "矯首天難問，傷哉挽鐸聲。"]'),
('802b73ab-44ff-48bd-893d-dd866a9e9867','參議弟挽詩','洪适','宋','宋诗','song-poetry','','[]','新筑久同隱，崇桃存舊栽。',48,'全唐诗/poet.song.123000.json','["新筑久同隱，崇桃存舊栽。", "壺中春漫別，花下我頻來。", "議幕三年隔，喪舟千里回。", "琴亡情話絕，淚落有餘哀。"]'),
('0dd8f3e4-97f4-4a06-952f-53d418545dd1','台州會太守致語口號','洪适','宋','宋诗','song-poetry','','[]','子墨聲名滿上都，同時曾喜得相如。',64,'全唐诗/poet.song.123000.json','["子墨聲名滿上都，同時曾喜得相如。", "二年寧俟棠陰久，一日先看薤本除。", "已向雲霄班玉筍，却思風月佩銅魚。", "百川莫靳長鯨吸，會即泥封虎爪書。"]'),
('208e71d1-1dc6-493a-99ad-a1af306e9646','秋閱致語口號','洪适','宋','宋诗','song-poetry','','[]','使星兩兩下人間，南伯來臨黄木灣。',64,'全唐诗/poet.song.123000.json','["使星兩兩下人間，南伯來臨黄木灣。", "蓋海旌幢龍戶集，折衝樽俎豹韜閒。", "銛鋒似雪摇銀海，美酒如澠倒玉山。", "賓主一時皆偉望，璇霄不日侍天顔。"]'),
('72bfdf49-8ded-4244-a3c7-3aa53c56b8f2','又歸路','洪适','宋','宋诗','song-poetry','','[]','風動旌旗熊虎開，喧轟鼓吹隱晴雷。',64,'全唐诗/poet.song.123000.json','["風動旌旗熊虎開，喧轟鼓吹隱晴雷。", "襟裾夾道邦人出，介胄填郛方伯來。", "按轡傳聲真烜赫，鋪茵呈舞少徘徊。", "林蠻洞蜑皆心讋，共看威伸講武臺。"]'),
('f843bd2c-cd60-416c-9e53-b91562d0a873','設蕃樂語口號','洪适','宋','宋诗','song-poetry','','[]','海山樓下水朝東，此去瀰漫拍太空。',64,'全唐诗/poet.song.123000.json','["海山樓下水朝東，此去瀰漫拍太空。", "稛載寧尋蕞爾國，舟行好趁快哉風。", "往來雲漢經星外，出入魚龍巨浪中。", "拜手君王零湛露，舉觴須似吸川虹。"]'),
('4d852c2d-a415-46a9-8a91-10e92c604868','會肇慶新守樂語口號','洪适','宋','宋诗','song-poetry','','[]','元戎好客過當時，喜報江頭鷁首飛。',64,'全唐诗/poet.song.123000.json','["元戎好客過當時，喜報江頭鷁首飛。", "款曲西賓香作陣，安排南食妓分圍。", "甘醪不必金貂換，清話頻看玉麈揮。", "祇隔嵩臺衣带水，未須輕賦醉言歸。"]'),
('7f2a6201-4df9-482a-8b7a-46f47ca2caf5','會肇慶舊守樂語口號','洪适','宋','宋诗','song-poetry','','[]','再歲專城屈令才，西江人至說清埃。',64,'全唐诗/poet.song.123000.json','["再歲專城屈令才，西江人至說清埃。", "瓜時解組飄飄去，雪夜乘舟得得來。", "一笑坐間桑落酒，幾聲樂奏越王臺。", "元戎預起陽關恨，不放譙門玉漏催。"]'),
('f7c5c7ae-887e-43d8-8a3f-891697c90ad1','會黄雷州樂語口號','洪适','宋','宋诗','song-poetry','','[]','二難辭藻琢瓊瑰，入洛當年擅軼才。',64,'全唐诗/poet.song.123000.json','["二難辭藻琢瓊瑰，入洛當年擅軼才。", "五嶺達官今寂寞，九齡高躅久塵埃。", "分符有此二千石，投轄中之三百杯。", "衣繡還鄉真罕見，戲魚同隊幾駑駘。"]'),
('43195f3e-c935-4327-8987-aaffb52b6bf1','平齊孫致語口號','洪适','宋','宋诗','song-poetry','','[]','山越逋誅歲屢更，元戎指縱有奇兵。',64,'全唐诗/poet.song.123000.json','["山越逋誅歲屢更，元戎指縱有奇兵。", "長歌壯士歸三箭，必勝良籌妙兩楹。", "兔窟已空春草碧，鯨波無事暮潮平。", "干戈便挽天河洗，桴鼓從今不復鳴。"]'),
('5f0b17e8-1ec9-41ae-a4f6-004ad898a694','會南恩守傅侍郎致語口號','洪适','宋','宋诗','song-poetry','','[]','向來烽火起邊塵，膚使南翔譽益振。',64,'全唐诗/poet.song.123000.json','["向來烽火起邊塵，膚使南翔譽益振。", "肯爲魚符臨海角，合歸鷺序映朝紳。", "高情如泛陰山雪，喜氣能添澤國春。", "一斗百篇推敏捷，醉中端有語驚人。"]'),
('7586e035-a1cf-467c-bcaa-7440fd4545ed','韓提舶解印致語口號','洪适','宋','宋诗','song-poetry','','[]','萬戶封侯識面難，南來清譽落諸蠻。',64,'全唐诗/poet.song.123000.json','["萬戶封侯識面難，南來清譽落諸蠻。", "指揮浪舶風帆了，談笑木牛流馬間。", "回牡言歸光帳餞，一杯相屬看弓彎。", "行行日遠長安近，平步逍遥玉筍班。"]'),
('c3905590-d020-48b3-a4ea-3c4aa9b20d6b','韓提舶餞行致語口號','洪适','宋','宋诗','song-poetry','','[]','激濁揚清有渭涇，鞭鸞歸去侍天庭。',64,'全唐诗/poet.song.123000.json','["激濁揚清有渭涇，鞭鸞歸去侍天庭。", "文星持節光南斗，巨翼摩空擊北溟。", "黄木灣頭波湛碧，陽關聲裏柳吹青。", "莫辭更盡一杯酒，明日相思過短亭。"]'),
('d54c236d-6b0b-46ee-a8e8-ebbbec8f0d33','眾官餞提舶樂語口號','洪适','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','泰山英譽冠當時，五嶺人人說繡衣。',64,'全唐诗/poet.song.123000.json','["泰山英譽冠當時，五嶺人人說繡衣。", "平步便應持紫橐，它年何止到黄扉。", "遲遲暖日離筵啟，渺渺澄江畫航歸。", "若問越裝無一物，篋中寶唾盡珠璣。"]'),
('0e10c160-5680-4fc2-b658-c486887daa20','廣東春教致語口號','洪适','宋','宋诗','song-poetry','','[]','高管嗷嘈疊鼓忙，春雲輕覆饗軍堂。',64,'全唐诗/poet.song.123000.json','["高管嗷嘈疊鼓忙，春雲輕覆饗軍堂。", "二星光動狐狸伏，六纛威騰貔虎良。", "海孽向來如薙草，射夫無有不穿楊。", "時平已卧邊庭鼓，不廢蒐田謹舊章。"]'),
('390f7e23-32f7-4125-b486-6674dfe3797f','歸路致語口號','洪适','宋','宋诗','song-poetry','','[]','轅門返旆到康莊，甚寵傳呼實鮮雙。',64,'全唐诗/poet.song.123000.json','["轅門返旆到康莊，甚寵傳呼實鮮雙。", "麗錦輕翻青玉案，高牙旁聳碧油幢。", "令行遐嶠真無事，盜息潢池不受降。", "會見追鋒歸禁密，獨留威譽紀南邦。"]'),
('ed204843-fdad-4c14-9dd8-3aff64d7915e','天申節道場所回欄階白語口號','洪适','宋','宋诗','song-poetry','','[]','濯冠沐浴意能虔，已萃緇黄介萬年。',64,'全唐诗/poet.song.123000.json','["濯冠沐浴意能虔，已萃緇黄介萬年。", "樂備八音浮喜氣，香飄九陌凝祥烟。", "雙旌未用催茸纛，四牡何妨款著鞭。", "夾道邦人方屬目，試教舞袖略回旋。"]'),
('cfbf718b-4815-499d-8dbc-16d41431e812','前筵祝聖致語口號','洪适','宋','宋诗','song-poetry','','[]','帝暉咫尺照龍楹，繞殿嵩呼若震霆。',64,'全唐诗/poet.song.123000.json','["帝暉咫尺照龍楹，繞殿嵩呼若震霆。", "朝士班齊鸞步武，仙官瑞集鶴儀形。", "奉觴亦有單于使，秉筆應書南極星。", "遐嶠莫瞻天日表，願將湛露等滄溟。"]'),
('8df4893c-5722-48a4-af71-f56f706a9117','對廳致語口號','洪适','宋','宋诗','song-poetry','','[]','時逢化國日舒長，解慍風來宇宙凉。',64,'全唐诗/poet.song.123000.json','["時逢化國日舒長，解慍風來宇宙凉。", "飛鷁闓祥瞻北極，頒魚錫宴暨南方。", "紛紛人贊元侯德，兩兩星舒使者光。", "來歲廣庭班玉筍，斯辰同奉萬年觴。"]'),
('1d0ed89e-00e7-443e-be17-ddbd001b799c','王母隊祝聖致語口號','洪适','宋','宋诗','song-poetry','','[]','六幕紛紛啟瑞篇，非烟深處下芝軿。',64,'全唐诗/poet.song.123000.json','["六幕紛紛啟瑞篇，非烟深處下芝軿。", "穆王擾擾不謀治，武帝區區空學仙。", "今代一人真間世，昔時五老與疑年。", "歡呼亦有南山頌，誰解吹噓上九天。"]'),
('6cf920e7-4195-48fd-8dce-df8a68ee0d44','對廳致語口號','洪适','宋','宋诗','song-poetry','','[]','天街蹀躞跨連錢，帝念遐萌輟雋賢。',64,'全唐诗/poet.song.123000.json','["天街蹀躞跨連錢，帝念遐萌輟雋賢。", "玉節繡衣三絕席，翠樽瓊斝再開筵。", "管弦聲動宮商叶，雨露恩均草木妍。", "定有千秋金鑑錄，明年親奏御牀前。"]'),
('34ad41e1-83a2-4c4a-9c3d-49e2d3343761','廣西春教致語口號','洪适','宋','宋诗','song-poetry','','[]','元戎堂上有奇兵，樓堞旌旗未易名。',64,'全唐诗/poet.song.123000.json','["元戎堂上有奇兵，樓堞旌旗未易名。", "光接二星瞻使節，令行八桂暢軍聲。", "指揮已定熊羆肅，什伍纔分鵝鸛成。", "威烈遠超銅柱外，雕題交趾盡魂驚。"]'),
('5061ec71-795a-48ec-9fd6-ebc259d29e4e','道上致語口號','洪适','宋','宋诗','song-poetry','','[]','廣陌無風柳絮藏，輕塵不起整戎裝。',64,'全唐诗/poet.song.123000.json','["廣陌無風柳絮藏，輕塵不起整戎裝。", "洞丁纍化青春寂，師乙諧聲白晝長。", "無數冠裳雲塞道，兩行鈇鉞雪摇光。", "英英如此桂林伯，便令腰金上玉堂。"]'),
('d5a0d56b-1deb-4687-a09d-ec2a79bda530','歸府致語口號','洪适','宋','宋诗','song-poetry','','[]','凝笳疊鼓壓天南，從此邦人作美談。',64,'全唐诗/poet.song.123000.json','["凝笳疊鼓壓天南，從此邦人作美談。", "北里聲名皆擢秀，東州歌舞總懷慚。", "輕裘坐嘯青油幕，積甲高齊碧玉簪。", "聞道家家賣釵釧，武夫歸去亦醺酣。"]'),
('1152c43e-5c4f-4a18-a546-5ccbb52e4ed5','水教致語口號','洪适','宋','宋诗','song-poetry','','[]','元戎膚使憩胡牀，寓目舟師夏日長。',63,'全唐诗/poet.song.123000.json','["元戎膚使憩胡牀，寓目舟師夏日長。", "捷比黄頭能輯濯，勇於長鬣取餘皇。", "水中劍影蛟龍避，帳下兵威狐兔藏。", "見說潢池毀多？新來歸去事耕桑。"]'),
('fa555de7-d323-4bc8-b510-3b9720bcacdb','歸路致語口號','洪适','宋','宋诗','song-poetry','','[]','油幢紅旆屆通衢，共聽歌詩我不誣。',64,'全唐诗/poet.song.123000.json','["油幢紅旆屆通衢，共聽歌詩我不誣。", "弭盜初無沈命法，應時誰用辟兵符。", "翻然奮袖回羅綺，觀者駢肩足袴襦。", "早晚天書頒瑞錦，好書樂石遺番禺。"]'),
('e0c3fa5e-9c98-440b-af05-4fea4d739c19','會肇慶黄通判樂語口號','洪适','宋','宋诗','song-poetry','','[]','古錦銜標戶戶知，瀛洲準擬上雲逵。',64,'全唐诗/poet.song.123000.json','["古錦銜標戶戶知，瀛洲準擬上雲逵。", "當今便便五經笥，自昔汪汪千頃陂。", "肯向江邊留鷁首，莫辭花底罄鴟夷。", "康沂成詠頒歸詔，剝啄相尋後會期。"]'),
('7fc2fb9a-1f79-4a9f-b85f-04ae1a878198','會鄭韓二守樂語口號','洪适','宋','宋诗','song-poetry','','[]','江別東西說二賢，魚書同拜喜聯翩。',64,'全唐诗/poet.song.123000.json','["江別東西說二賢，魚書同拜喜聯翩。", "穉卿風采齊龔遂，延壽規模載潁川。", "玉麈揮談飛玉屑，金龜換酒泛金船。", "莫辭痛飲娛清夜，對此中秋璧月天。"]'),
('6882177b-9b74-4b22-b9d9-69c5b1ac2414','廣東秋教致語口號','洪适','宋','宋诗','song-poetry','','[]','清秋大試斧尋柯，噭咷誰言用楚歌。',64,'全唐诗/poet.song.123000.json','["清秋大試斧尋柯，噭咷誰言用楚歌。", "帥閫威名傳籍籍，使臺材業辦多多。", "兵機總是師黄石，酒令同看卷白波。", "見說鄰偷蜂蟻聚，遠聞軍政已投戈。"]'),
('43a4ad70-fb06-402e-8ef1-07b6d9527115','歸路致語口號','洪适','宋','宋诗','song-poetry','','[]','旌旗獵獵戰西風，介胄精明霜與同。',64,'全唐诗/poet.song.123000.json','["旌旗獵獵戰西風，介胄精明霜與同。", "擁道共瞻元帥至，折衝誰許十賢功。", "夸銀拖綵征師喜，迴袖垂螺舞女工。", "已向黄樞贊籌畫，便應歸侍大明宮。"]'),
('b6b268a7-883b-4aeb-ac00-c11e8e05526e','設蕃致語口號','洪适','宋','宋诗','song-poetry','','[]','艫人指日欲開檣，洽此需雲寵遠商。',64,'全唐诗/poet.song.123000.json','["艫人指日欲開檣，洽此需雲寵遠商。", "奇物試求師子國，去帆穩過大蛇洋。", "銀杯更盡金杯飲，黑暗仍兼白暗將。", "方伯使華清澈底，不聞私有橐中藏。"]'),
('36585015-7a30-418c-a19e-b9e3077234bf','會廣西田提刑致語口號','洪适','宋','宋诗','song-poetry','','[]','北斗南邊雲物明，燁然天節仰祥星。',64,'全唐诗/poet.song.123000.json','["北斗南邊雲物明，燁然天節仰祥星。", "朝端獬豸曾張膽，道上狐狸已匿形。", "欲奉三章仁遠嶠，定知五管迓虛囹。", "迂程肯顧交情厚，莫惜花前倒綠醽。"]'),
('8cf067cf-274a-4d72-bf6e-be02e2d3de54','廣東春教致語口號','洪适','宋','宋诗','song-poetry','','[]','豪竹繁弦振粵臺，鬭場雨過凈纖埃。',64,'全唐诗/poet.song.123000.json','["豪竹繁弦振粵臺，鬭場雨過凈纖埃。", "台符款曲三揮麈，軍令分明屢舉杯。", "兔窟久空春草出，鯨波無事早潮來。", "已知樽俎遐衝折，且欲班勞激趫材。"]'),
('e96dc27b-5c99-49c8-868b-fc6f051da204','歸路致語口號','洪适','宋','宋诗','song-poetry','','[]','旌旆摇摇卷碧雲，元戎振旅入城闉。',64,'全唐诗/poet.song.123000.json','["旌旆摇摇卷碧雲，元戎振旅入城闉。", "蜚騰廣譽孚朝野，講肄强兵動鬼神。", "無數冠裳聲聒晝，兩行羅綺艷嬌春。", "看看夜半朝宣室，便把金犀換玉麟。"]'),
('affb3fbc-9c00-4e48-8522-08ee218f717c','天申節道場回欄階白語口號','洪适','宋','宋诗','song-poetry','','[]','垂魚擁笏萃官僚，黄宅緇廬再祝堯。',64,'全唐诗/poet.song.123000.json','["垂魚擁笏萃官僚，黄宅緇廬再祝堯。", "九夏正中調玉燭，五雲爲瑞爛璇霄。", "無勞廣陌張戎幕，且駐高牙挽使軺。", "觀者如牆汗成雨，爲呼歌舞相歡謠。"]'),
('3da9107c-66ea-4c4f-b484-5c9d1f449265','前筵祝聖致語口號','洪适','宋','宋诗','song-poetry','','[]','薰風濯熱自南來，陛戟傳聲殿繞雷。',64,'全唐诗/poet.song.123000.json','["薰風濯熱自南來，陛戟傳聲殿繞雷。", "九奏鳴球陳露甕，八珍登俎奉天杯。", "爐烟結篆狻猊噴，扇影分行孔雀開。", "海角無階就堯日，但知長曝報恩腮。"]'),
('50596a4e-92ff-4a51-8517-e4e0302d00e8','對廳致語口號','洪适','宋','宋诗','song-poetry','','[]','填然歌頌沸康莊，郁郁捎雲晝漏長。',64,'全唐诗/poet.song.123000.json','["填然歌頌沸康莊，郁郁捎雲晝漏長。", "禮浹三行盈綠醑，樂催百戲擁黄堂。", "挹泉清節推吳隱，攬轡威聲小范滂。", "來歲同稱千萬壽，天顔有喜舉瑶觴。"]'),
('4d600493-6b4f-4f2a-ae7f-b1051bec0e84','王母隊祝聖致語口號','洪适','宋','宋诗','song-poetry','','[]','想像編星拱紫微，龍蛇日暖動旌旗。',64,'全唐诗/poet.song.123000.json','["想像編星拱紫微，龍蛇日暖動旌旗。", "恭維虹瑞生虞帝，遠以鸞驂會宓妃。", "雲氣先飛三足使，風紋不皺六銖衣。", "君王若問蟠桃木，溜雨霜皮幾萬圍。"]'),
('7b80ff93-2a4a-4b33-bebc-c489d434855a','對廳致語口號','洪适','宋','宋诗','song-poetry','','[]','心傾葵藿斗南邊，秩秩簪紳再就筵。',64,'全唐诗/poet.song.123000.json','["心傾葵藿斗南邊，秩秩簪紳再就筵。", "方伯舉杯均舜酒，外臺連璧頌堯年。", "望雲鼇鼇躍三百，指日鵷行官九遷。", "祕殿此時同廣宴，宮花深處拜傳宣。"]'),
('0ba7dc5b-b06f-4262-8550-abe4492ce55b','廣東水教致語口號','洪适','宋','宋诗','song-poetry','','[]','水戰橫江一百舟，海山樓裏坐元侯。',64,'全唐诗/poet.song.123000.json','["水戰橫江一百舟，海山樓裏坐元侯。", "偷兒已罷三年伎，猛士聊因五月秋。", "不用辟兵酬令節，從今行客但安流。", "將軍盡列長安第，留取樓船震海頭。"]'),
('e092cc65-d271-4825-b70b-5f3d61d72303','歸路致語口號','洪适','宋','宋诗','song-poetry','','[]','州民爭看使君歸，千騎闐闐此一時。',64,'全唐诗/poet.song.123000.json','["州民爭看使君歸，千騎闐闐此一時。", "鼠子已知焚大棹，馬人又是建豐碑。", "但將海閣嚴軍政，不比湖亭習水嬉。", "赤壁功成八十萬，小橋應奏舞腰支。"]'),
('2c70670f-a35e-49c9-86cb-63c56f9134d5','會江正字樂語口號','洪适','宋','宋诗','song-poetry','','[]','一鳴曾使萬人驚，亙地馳聲若建瓴。',64,'全唐诗/poet.song.123000.json','["一鳴曾使萬人驚，亙地馳聲若建瓴。", "此日東州披宿霧，幾年南斗避魁星。", "共看騏驥騰夷路，便接夔龍侍楚廷。", "千里尋盟須舉白，海珍無謝五侯鯖。"]'),
('6c3e6919-658f-4678-8ee5-271513db66fb','廣東秋教致語口號','洪适','宋','宋诗','song-poetry','','[]','八月師田不失時，武蠭赳赳震雕題。',64,'全唐诗/poet.song.123000.json','["八月師田不失時，武蠭赳赳震雕題。", "耳批秋竹圖騏驥，鋒瑩朝霜拭鷿鵜。", "連率名高方叔後，外臺志與范滂齊。", "向來佩犢潢池子，一一腰鐮走稻畦。"]'),
('9157f4ef-c151-4d16-ab2c-93b32f551c46','歸路致語口號','洪适','宋','宋诗','song-poetry','','[]','旌旄照海塞通逵，共說元戎校武歸。',64,'全唐诗/poet.song.123000.json','["旌旄照海塞通逵，共說元戎校武歸。", "三歲麟符寬遠顧，一方鼠子讋英威。", "征袍劍立嚴師律，舞袖弓彎有妓圍。", "頃刻連營俱解甲，室中寧復歎蛜蝛。"]'),
('a94cd348-42da-497a-b4da-fbe5854871c8','鹿鳴宴致語口號','洪适','宋','宋诗','song-poetry','','[]','采芹東魯浪歌僖，領海儒風異昔時。',64,'全唐诗/poet.song.123000.json','["采芹東魯浪歌僖，領海儒風異昔時。", "學有淵源能貫通，文如藻繡總紬奇。", "軒然西笑騰三級，對此南烹舉一巵。", "勳業權輿自今日，廣寒折取最高枝。"]'),
('d7405c3a-710f-4f1a-bd29-34512c8412a5','會肇慶章守致語口號','洪适','宋','宋诗','song-poetry','','[]','風翼翔嬉雲路輕，合班玉筍直承明。',64,'全唐诗/poet.song.123000.json','["風翼翔嬉雲路輕，合班玉筍直承明。", "鰐溪已作思棠雅，龍邸先馳拔薤聲。", "皂蓋朱轓仍斂惠，青簾白舫豈爭程。", "元戎政欲傾家釀，喚取佳人進麯生。"]'),
('dd7e6e4c-2997-4fc8-bf38-4f8f8a09fefd','福州會權府趙提刑致語口號','洪适','宋','宋诗','song-poetry','','[]','三山分鼎肖蓬瀛，仰首雲逵上使星。',64,'全唐诗/poet.song.123000.json','["三山分鼎肖蓬瀛，仰首雲逵上使星。", "綬带一年聊疊組，破觚八郡久虛囹。", "元戎自喜聯高躅，勝日何妨醉淥醹。", "雅望不應長攬轡，便須筆橐侍天庭。"]'),
('0036ad2e-518c-48b3-8c2a-d2ab5426a5df','會交代趙知郡致語口號','洪适','宋','宋诗','song-poetry','','[]','雪意商量未肯忙，使君歸騎已騰驤。',64,'全唐诗/poet.song.123000.json','["雪意商量未肯忙，使君歸騎已騰驤。", "二年治行留襦袴，萬戶生涯足稻粱。", "便去峨冠登要路，誰能截鐙款行裝。", "胸中久矣吞雲夢，一舉瓊彝有別腸。"]'),
('1c5082ae-78d6-4a19-9826-835102e6d4ee','适兩日小疾謁告聞知府郎中丈有東湖之游而不果陪遂蒙佳句寵問輒趁韵以謝','洪适','宋','宋诗','song-poetry','','[]','佳時行樂阻追陪，喜得詩筒手自開。',64,'全唐诗/poet.song.123000.json','["佳時行樂阻追陪，喜得詩筒手自開。", "雲岫送凉隨皂蓋，風漪獻狀屬金罍。", "也知萍底魚相得，更有荷閒蝶鼎來。", "不識重游在何日，便須扶病走輿臺。"]'),
('2ba13885-a9c1-457a-acf7-827fe1855457','臘雪應祈因成鄙語呈使君','洪适','宋','宋诗','song-poetry','','[]','黄雲仰首聚還飛，臘雪今年故作遲。',64,'全唐诗/poet.song.123000.json','["黄雲仰首聚還飛，臘雪今年故作遲。", "涓日朱轓方有請，因風縞带即如期。", "寒梅正爾慚五出，茂麥懸知頌兩歧。", "千室一辭欣響答，直須書事付歌詩。"]'),
('1971f3b3-9af5-401f-aaba-036e45ee58f0','開歲五日使君見約同宮使尚書諸丈觀山宮梅花因成拙詩','洪适','宋','宋诗','song-poetry','','[]','天知風月主人賢，况是江梅望著鞭。',64,'全唐诗/poet.song.123000.json','["天知風月主人賢，况是江梅望著鞭。", "已報兵厨招客醉，故教晴日作春妍。", "一年行樂能多少，十騎聯飛相後先。", "好向山宮記名氏，它時嘉話踵斜川。"]'),
('7f58d9f0-24f3-4880-bf37-266ecd294116','至寧海縣有懷曾守','洪适','宋','宋诗','song-poetry','','[]','郊行十日天宇清，回首靜鎮薰鑪凝。',64,'全唐诗/poet.song.123000.json','["郊行十日天宇清，回首靜鎮薰鑪凝。", "寄聲已爲謝亭長，去甚復且容聾丞。", "萬牛策勳場可滌，一犬徹警門無譍。", "呼農來前問所自，歸之刺史南豐曾。"]'),
('31822abd-7d83-4a3a-905f-0f2474b96280','次酬曾守分繡閣','洪适','宋','宋诗','song-poetry','','[]','城隅喬木可怡顔，小閣初成尺五閒。',64,'全唐诗/poet.song.123000.json','["城隅喬木可怡顔，小閣初成尺五閒。", "好客飛觴同嘯傲，新詩銜袖莫追攀。", "片時凉雨洗疏竹，向晚輕雲留遠山。", "坐想清香凝燕寢，也思一笑十眉彎。"]'),
('8bc1229f-90e9-491d-ab6e-c49a1652f84d','中巖寺','洪适','宋','宋诗','song-poetry','','[]','覽勝尋幽性所耽，不教騶哄滓筠杉。',64,'全唐诗/poet.song.123000.json','["覽勝尋幽性所耽，不教騶哄滓筠杉。", "霞城散綺留仙袂，露磴凝珠拂客衫。", "曾有金龍潛邃洞，却因赤蟻遠崇巖。", "來遊無復從容計，自笑羸驂束轡銜。"]'),
('b133a50b-c7bf-4eab-9d33-1c0d9317a221','贈崇教寺顔上人','洪适','宋','宋诗','song-poetry','','[]','禪窟夸金碧，經行失舊蹤。',48,'全唐诗/poet.song.123000.json','["禪窟夸金碧，經行失舊蹤。", "鐘聲穿茂竹，轍迹蔭長松。", "遠到水常瑩，前陳山更重。", "勤勤紫藤杖，一覽爲從容。"]'),
('051c69b1-86b6-48e4-897b-65c3da08f2c4','送劉元忠學士還南京','洪适','宋','宋诗','song-poetry','','[]','昔見相公登瀛洲，今見公子爲校讎。',96,'全唐诗/poet.song.123000.json','["昔見相公登瀛洲，今見公子爲校讎。", "鯤鵬變化三十載，我生安得不白頭。", "君前拜恩父前慶，暫向南都秉順流。", "南都留守頗爲喜，將吏入賀靴聲遒。", "酒舁銀甕羊臠炙，上下和煦移凉秋。", "歸來却上柳堤路，西風健馬控花虬。"]'),
('f268d0ad-9b7f-44b3-9029-0104fb45c696','賦孤雁','洪适','宋','宋诗','song-poetry','','[]','雲飛水宿過炎凉，回想來時道路長。',64,'全唐诗/poet.song.123000.json','["雲飛水宿過炎凉，回想來時道路長。", "夜月照驚唯吊影，朔風吹斷不成行。", "人間無處逃矰繳，歲晚何曾飽稻粱。", "儻以能鳴免烹殺，繫書猶可到衡陽。"]'),
('2789c1da-469c-4aec-87d9-3afd30886843','題清芬閣','洪适','宋','宋诗','song-poetry','','[]','先生此地舊眠雲，喬木森然數百春。',64,'全唐诗/poet.song.123000.json','["先生此地舊眠雲，喬木森然數百春。", "海內多傳詩弟子，壁間曾記藥君臣。", "仙廬隱瀨跡皆古，柏寺蓬山代有人。", "今日耳孫尤烜赫，慶源須信渺無垠。"]'),
('50d05a98-22e8-4c7f-9259-7e68a907947f','雨中泊舟蕭山縣驛','洪适','宋','宋诗','song-poetry','','[]','端居無策散閑愁，聊作人間汗漫遊。',64,'全唐诗/poet.song.123000.json','["端居無策散閑愁，聊作人間汗漫遊。", "晚笛隨風來倦枕，春潮带雨送孤舟。", "店家菰飯香初熟，市檐蓴絲滑欲流。", "自笑勞生成底事，黄塵陌上雪蒙頭。"]'),
('d4472c67-d101-49ae-b8c5-f731d8dc0eed','壽秦太師  其一','洪适','宋','宋诗','song-poetry','','[]','北斗回春半浹辰，秦淮衮衮灧精神。',64,'全唐诗/poet.song.123000.json','["北斗回春半浹辰，秦淮衮衮灧精神。", "六朝舊鬰興王業，千載猶鍾命世人。", "便與斯文生羽翼，懸知上聖倚經綸。", "形容盛德非常事，再拜寒儒請具陳。"]'),
('3c7423b3-78a0-4e48-920d-d9afdd8043c4','壽秦太師  其二','洪适','宋','宋诗','song-poetry','','[]','竹帛班班社稷臣，陳編窺讀已成塵。',64,'全唐诗/poet.song.123000.json','["竹帛班班社稷臣，陳編窺讀已成塵。", "聖朝置相超三代，輿議推公第一人。", "夾日豫章蟠厚地，回天大冶轉洪鈞。", "后皇當宁年盈萬，長向璇霄侍玉宸。"]'),
('8378db92-9934-43db-9cee-1e4bbbe4643e','壽秦太師  其三','洪适','宋','宋诗','song-poetry','','[]','彬彬文物悉□張，大厦扶持有棟梁。',64,'全唐诗/poet.song.123000.json','["彬彬文物悉□張，大厦扶持有棟梁。", "今日典刑新漢閣，舊時耆老拜虞庠。", "夙臨壇陛皇儀究，載祚城闉常藉荒。", "公有裨天五色石，指揮餘事亦晶光。"]'),
('9a13b221-4fff-43ca-8742-1831eda405d9','壽秦太師  其四','洪适','宋','宋诗','song-poetry','','[]','恨無官職可酬公，□□寰區寵數隆。',64,'全唐诗/poet.song.123000.json','["恨無官職可酬公，□□寰區寵數隆。", "甲第益高丞相府，多儀新出大明宮。", "九重禮絕恩三顧，一德名尊報兩崇。", "安得奇才來學賦，試令給札命揚雄。"]'),
('05f4173d-ede6-4f55-8dc6-6715c25b1c8e','壽秦太師  其五','洪适','宋','宋诗','song-poetry','','[]','十載操持將相權，親提四海入陶甄。',64,'全唐诗/poet.song.123000.json','["十載操持將相權，親提四海入陶甄。", "周公禮樂未墜地，伊尹勤勞真格天。", "青海不傳南下箭，黄河長渡北歸船。", "濟時毫髮無遺力，數盡名臣孰與肩。"]'),
('d32e7ad9-179e-4181-a587-9c3196b64ede','壽秦太師  其六','洪适','宋','宋诗','song-poetry','','[]','聖皇問孝日東朝，報德流恩冠百僚。',64,'全唐诗/poet.song.123000.json','["聖皇問孝日東朝，報德流恩冠百僚。", "九命衮衣蟬插首，萬釘寶带玉圍腰。", "渠渠廣厦開黄道，圉圉鳴珂下紫霄。", "宇宙人間榮至此，榆枋無地著扶摇。"]'),
('80704118-e5f9-44b9-8d57-20b5137ea347','壽秦太師  其七','洪适','宋','宋诗','song-poetry','','[]','左弧垂慶記南州，日轉天旋歲一周。',64,'全唐诗/poet.song.123000.json','["左弧垂慶記南州，日轉天旋歲一周。", "風入江梅香暗度，霜滿翠柏景深留。", "定知與國同箕翼，不用占星問斗牛。", "却使松喬羨眉壽，大椿何啻八千秋。"]'),
('987b0dd2-05ed-43ef-84d3-4a280f1f9886','壽太師益公  其一','洪适','宋','宋诗','song-poetry','','[]','四海十年無武功，邊人歲下還耕農。',320,'全唐诗/poet.song.123000.json','["四海十年無武功，邊人歲下還耕農。", "向來紛紜戰爭地，方今不見旌旗紅。", "東窮滄溟西盡蜀，道路行歌鎮相續。", "奇祥異瑞□莫論，但道年豐萬家足。", "固知至治天相之，朝廷清明本無爲。", "問誰始終主張是，一德享天維太師。", "太師勳業青冥上，丹青已揭蓬山象。", "大鴻力牧空耳聞，未似身逢真聖相。", "九重日侍慈祥宮，雞鳴問寢聲融融。", "人間快樂直餘事，都在指揮談笑中。", "太師少保各開府，玉带金魚行按武。", "同時兩相父子間，此事古今誰得數。", "今年臘尾春全回，江梅正爲生朝開。", "化工暗與人意合，更送雪花浮玉杯。", "內中數出黄封酒，紫衣飛鞚無停手。", "跪奉傳觴再拜頻，天子勸公千萬壽。", "賤生魯鈍何足程，六年眼繫文昌星。", "冷官無路報恩地，孤負翹林畫姓名。", "惡詩寄將千里遠，引領南州望英衮。", "青芝赤箭儻可庸，此身許人良未晚。"]'),
('922c975f-366c-4cd2-a72d-339cfcc4d940','壽太師益公  其二','洪适','宋','宋诗','song-poetry','','[]','自從麟閣雲臺後，直到凌烟不乏人。',32,'全唐诗/poet.song.123000.json','["自從麟閣雲臺後，直到凌烟不乏人。", "唐突漢唐今日是，元勳唯有一師臣。"]'),
('1d8e6ede-0c06-40e5-8092-3d739721fbd3','壽太師益公  其三','洪适','宋','宋诗','song-poetry','','[]','向來群議幾紛紜，决策和戎斷若神。',32,'全唐诗/poet.song.123000.json','["向來群議幾紛紜，决策和戎斷若神。", "談笑之間了天下，誠方前古有何人。"]'),
('51486c0b-db10-46c6-9ddf-76e02f4c7560','壽太師益公  其四','洪适','宋','宋诗','song-poetry','','[]','淮北淮南應戰場，只今春草飽牛羊。',32,'全唐诗/poet.song.123000.json','["淮北淮南應戰場，只今春草飽牛羊。", "時平不假金湯固，淮水湯湯一葦航。"]'),
('c8a0ca7a-eee7-47e4-bbaa-5da8795feda5','壽太師益公  其五','洪适','宋','宋诗','song-poetry','','[]','聖皇日日侍庭闈，七十春秋自古稀。',32,'全唐诗/poet.song.123000.json','["聖皇日日侍庭闈，七十春秋自古稀。", "不是相公平國後，誰令六騩得南歸。"]'),
('41598368-7718-4eb9-9b15-a61b1ef804f8','壽太師益公  其六','洪适','宋','宋诗','song-poetry','','[]','晉公貌狀誰能畫，曹霸丹青與世殊。',32,'全唐诗/poet.song.123000.json','["晉公貌狀誰能畫，曹霸丹青與世殊。", "頭上進賢何足道，至尊書贊古來無。"]'),
('b36ee8ee-dd41-4f4b-88a3-bf36d3823d20','壽太師益公  其七','洪适','宋','宋诗','song-poetry','','[]','六龍齋潔疑圓壇，百辟奔趨列後先。',32,'全唐诗/poet.song.123000.json','["六龍齋潔疑圓壇，百辟奔趨列後先。", "華髮都人驚未見，一門兩使並貂蟬。"]'),
('c9802d26-f8a8-4e0a-b2ba-87b1932eeea2','壽太師益公  其八','洪适','宋','宋诗','song-poetry','','[]','慶源衮衮益光華，聞道諸孫總稱家。',32,'全唐诗/poet.song.123000.json','["慶源衮衮益光華，聞道諸孫總稱家。", "活却生靈千百萬，陰功天報的無差。"]'),
('885777af-d134-42c9-8fa0-761db43d6548','壽太師益公  其九','洪适','宋','宋诗','song-poetry','','[]','不論南北與西東，道路歌謠觸處同。',32,'全唐诗/poet.song.123000.json','["不論南北與西東，道路歌謠觸處同。", "要識太平真面目，豐年長入頌聲中。"]'),
('897f939c-6ec9-40f0-ba27-43a61624ceab','壽太師益公  其一○','洪适','宋','宋诗','song-poetry','','[]','年年臘尾慶生申，共祝槐庭過萬春。',32,'全唐诗/poet.song.123000.json','["年年臘尾慶生申，共祝槐庭過萬春。", "天使長生輔真主，人間不用說莊椿。"]'),
('ad38c78e-174b-4775-9b21-e6c71ca6786f','壽太師益公  其一一','洪适','宋','宋诗','song-poetry','','[]','殘生無似辱甄收，正作儒官已過優。',32,'全唐诗/poet.song.123000.json','["殘生無似辱甄收，正作儒官已過優。", "只有望雲朝夕念，恩波儻得下炎洲。"]'),
('d3ce31f0-e715-485f-9a19-2afd3bdc5f8f','壽張侍郎  其一','洪适','宋','宋诗','song-poetry','','[]','少日聲名滿學宮，中年遭遇冠群公。',64,'全唐诗/poet.song.123000.json','["少日聲名滿學宮，中年遭遇冠群公。", "一言坐决興邦策，學世誰知料敵功。", "上見嚴安方恨晚，人推汲黯盍居中。", "由來大用須詳試，出處之間本自同。"]'),
('bb03ed24-7263-4d64-928a-a4ae05b889de','壽張侍郎  其二','洪适','宋','宋诗','song-poetry','','[]','三吳政化捷如神，八桂威名逐日新。',64,'全唐诗/poet.song.123000.json','["三吳政化捷如神，八桂威名逐日新。", "此地只今煩督護，一方何足費經綸。", "清心省事真無訟，約己豐財祇爲民。", "聞道潢池總安堵，新來不見弄兵人。"]'),
('30f205bc-2f65-42c8-a271-77afa628e7b8','壽孫提刑','洪适','宋','宋诗','song-poetry','','[]','溪山擢秀稱陽羨，族望推高獨富春。',64,'全唐诗/poet.song.123000.json','["溪山擢秀稱陽羨，族望推高獨富春。", "潄石風流宜有後，擲金詞翰不無人。", "聲名已覺寰區滿，事業方看日夜新。", "今代太平難藻繪，須公提筆侍楓宸。"]'),
('ce3520d8-f599-429a-a879-04d2b36f5cad','壽王饒州  其一','洪适','宋','宋诗','song-poetry','','[]','淮水湯湯自古傳，王家衮衮更多賢。',64,'全唐诗/poet.song.123000.json','["淮水湯湯自古傳，王家衮衮更多賢。", "人門秀出烏衣右，時論誰居鳳閣先。", "已有聲名騰眾口，故應勳業在長年。", "安知今代文章伯，定是前身李謫仙。"]'),
('6c566ea3-02bb-416b-89a5-8dff60a42765','壽王饒州  其二','洪适','宋','宋诗','song-poetry','','[]','憶曾簪筆侍明光，細細熏香拱御床。',64,'全唐诗/poet.song.123000.json','["憶曾簪筆侍明光，細細熏香拱御床。", "正掌絲綸開畫省，忽嚴兵衛坐黄堂。", "一時童子能騎竹，三郡詞人總詠棠。", "漢世公卿盡良吏，趣歸須著紫荷囊。"]'),
('a74c550e-3658-4b82-824d-1259a22a162c','壽王饒州  其三','洪适','宋','宋诗','song-poetry','','[]','南風一夜入虞絃，帝遣文星下斗邊。',64,'全唐诗/poet.song.123000.json','["南風一夜入虞絃，帝遣文星下斗邊。", "冠蓋鼎來詩殷篋，兒孫羅立酒明船。", "掃除霜髮三千□，笑傲銅人五百年。", "再拜願公如許壽，幾看滄海變桑田。"]'),
('8b104d3c-3b38-4850-9afe-f80ce7832609','壽施徽州  其一','洪适','宋','宋诗','song-poetry','','[]','苕溪出天日，青雲相鮮新。',48,'全唐诗/poet.song.123000.json','["苕溪出天日，青雲相鮮新。", "春風舞綠凈，鏡滑無埃塵。", "江山有英姿，生此第一人。", "公貴當自致，名聲誰與鄰。"]'),
('5c814e0d-8eeb-4000-be4c-513e2cb8e565','壽施徽州  其二','洪适','宋','宋诗','song-poetry','','[]','文章妙機杼，作吏非雪清。',48,'全唐诗/poet.song.123000.json','["文章妙機杼，作吏非雪清。", "召見天歎晚，豸冠振臺評。", "驊騮丁漢苑，萬里方長鳴。", "翻成一麾去，何用慰蒼生。"]'),
('fa8eefbc-2ff7-4f75-8b4c-9245186fd245','壽施徽州  其三','洪适','宋','宋诗','song-poetry','','[]','新安誰云小，領縣數過五。',48,'全唐诗/poet.song.123000.json','["新安誰云小，領縣數過五。", "異時廟堂人，剖竹來接武。", "斯民亦何幸，父母□召杜。", "大惠先一州，要知非久處。"]'),
('157abe2d-fb1c-4e50-8baf-297df1d90356','壽施徽州  其四','洪适','宋','宋诗','song-poetry','','[]','兒童擁道邊，父老拜車下。',48,'全唐诗/poet.song.123000.json','["兒童擁道邊，父老拜車下。", "使君爲我至，歡喜不勝寫。", "壽公生朝重，滿酌白玉斝。", "明年更好在，璽詔來金馬。"]'),
('08131c20-c338-46f6-9cb9-2e6519a1304b','壽施徽州  其五','洪适','宋','宋诗','song-poetry','','[]','銅人五百年，大椿八千歲。',48,'全唐诗/poet.song.123000.json','["銅人五百年，大椿八千歲。", "寓言了無實，木石何足貴。", "公身有仙骨，坐閱此塵世。", "汗漫真可期，高揖浮丘袂。"]'),
('aef176e7-1129-4295-8c5e-5090c9a9f55a','送陸務觀福建提倉','洪适','宋','宋诗','song-poetry','','["\u79bb\u522b", "\u5fc6\u65e7", "\u996e\u9152", "\u611f\u6168"]','觥船相對百分空，京口追隨一夢中。',64,'全唐诗/poet.song.123000.json','["觥船相對百分空，京口追隨一夢中。", "落紙雲烟君似舊，盈巾霜雪我成翁。", "春來茗葉還爭白，臘近梅梢近放紅。", "領略溪山須妙語，小迂旌節上凌風。"]'),
('7ef8eed9-7ff7-44d2-b5f1-93ed497cdd9c','郊祀慶成','周麟之','宋','宋诗','song-poetry','','[]','紫極三階正，黄宮一氣旋。',288,'全唐诗/poet.song.123000.json','["紫極三階正，黄宮一氣旋。", "迎陽周吉土，練日漢甘泉。", "考典陳商輅，占祥察舜璿。", "朝冠紛璀璨，齋幄湛蟺蜎。", "荔席方顒若，油雲已廓然。", "瑶源尊始祖，絳節從羣仙。", "碧瓦霏煙外，雕梁麗日邊。", "大音諧美樂，芳薦列嘉籩。", "默喜雲孫燕，深期鼎祚延。", "六虬紆制蹕，九廟闢崇筵。", "鬰鬯香稃熟，芝楹瑞葉連。", "醇犧登碩俎，肅倡被朱絃。", "孝奏靈咸格，誠存禮不愆。", "清晨登玉軑，綵仗揭龍旃。", "虎旅羅三衛，蜺旌亙百廛。", "展容趨泰畤，裒福對蒼圜。", "扆坐張皇邸，帷宮駕采椽。", "鼓鐘傳禁漏，星月粲高躔。", "蠖略車迴斗，熒煌衮象天。", "華支金擢秀，雅奏玉鳴鋗。", "虛次停垂佩，登壇儼奉瑄。", "蘭生芬獻斝，電燎鬰升煙。", "氣晏樵蒸焜，天澄境落褰。", "涓成均拜胙，抃慶趣摩肩。"]'),
('ad2f44c6-489a-4c3d-8e51-0b89fdf47cd1','太廟觀芝草  其一','周麟之','宋','宋诗','song-poetry','','[]','九廟寧神藹德馨，煌煌又見産芝英。',64,'全唐诗/poet.song.123000.json','["九廟寧神藹德馨，煌煌又見産芝英。", "香凝薦斝椒蘭潤，色映雕梁日月明。", "紹復祖宗全達孝，感通天地契精誠。", "試披瑞牒占休應，看取皇家萬葉榮。"]'),
('b48fd898-b970-4007-95ff-d3c02f4e6ee4','太廟觀芝草  其二','周麟之','宋','宋诗','song-poetry','','[]','曉開疏屏望榮光，仰見威靈燭下方。',64,'全唐诗/poet.song.123000.json','["曉開疏屏望榮光，仰見威靈燭下方。", "二本同楹真盛事，三年疊秀是殊祥。", "好圖瑞采增旗幟，更誦靈華續樂章。", "拜舞共陳歸美頌，喜浮春殿九霞觴。"]'),
('a3808404-7eae-429c-9075-3abce823cc1f','苦熱行','周麟之','宋','宋诗','song-poetry','','[]','君不見浣花老翁初作掾，觸熱簿書塵滿案。',166,'全唐诗/poet.song.123000.json','["君不見浣花老翁初作掾，觸熱簿書塵滿案。", "坐曹束带總不能，但欲赤脚踏層冰。", "又不見青蓮居士金門客，懶摇白羽巾挂壁。", "有時裸袒青林中，只知露頂洒松風。", "二子英規凜千古，筆奪造化驅風雨。", "如何避暑如避仇，叫呼競作驚人語。", "是身本與天地同，要當捫腹無弗容。", "世間冷煖翻覆手，焉用夷隘惠不恭。", "我方窮居度炎熱，火雲爍山金石裂。", "一讀清詩百念空，炯若冰壺浸明月。"]'),
('7b27deb0-c85b-43a7-af95-0d56e3eaef03','憂旱','周麟之','宋','宋诗','song-poetry','','[]','老農病旱如膏肓，汲井灌秧秧已黄。',96,'全唐诗/poet.song.123000.json','["老農病旱如膏肓，汲井灌秧秧已黄。", "湖田半作龜兆坼，河渠斷道不可航。", "救旱不必焚巫尪，當去民害烹弘羊。", "嗟哉銷變此不務，龍川佛舍徒祈禳。", "中興天子食不遑，側身感天天與祥。", "霈然坐待三尺雨，擬賦雲漢歌宣王。"]'),
('2278f5c2-e165-4736-bf2c-69511a9aa02e','讀戰國策','周麟之','宋','宋诗','song-poetry','','[]','從人爲從六國强，橫人爲橫六國亡。',112,'全唐诗/poet.song.123000.json','["從人爲從六國强，橫人爲橫六國亡。", "悲夫不用擯秦計，徒以委肉强虎狼。", "一朝秦甲下函谷，指揮韓魏如羣羊。", "坐令不費一隻矢，山東千里無金湯。", "我窺塵編三太息，諸侯自覆非秦力。", "紛紛二百四十年，說士遊談空滿籍。", "我將西上吊興亡，南山自有能言石。"]'),
('af721404-38ff-46be-afb1-dd29ecc449fc','秋日坐寐覺而有作','周麟之','宋','宋诗','song-poetry','','[]','南國逢秋色，西風擾客心。',288,'全唐诗/poet.song.123000.json','["南國逢秋色，西風擾客心。", "久閒安飲啄，多病廢登臨。", "壁倚青藜杖，窗橫綠綺琴。", "無魚甘糲食，有酒任孤斟。", "地僻千山瘠，人稀萬籟瘖。", "懶同牛卧壠，倦劇鳥歸林。", "紙閣居容膝，繩牀坐整襟。", "縮頭須爾伴，便腹莫吾箴。", "俛仰三眠柳，徘徊五戲禽。", "忘形初隠几，得趣漸欹簪。", "不假仙遊枕，寧須女抱衾。", "乍疑身栩栩，已覺息深深。", "白鳳才難繼，黄粱事可尋。", "有人呼晝漏，何處起寒砧。", "短夢蘧然覺，斜暉慘欲陰。", "桂開香吐粟，菊認蘂攢金。", "磨熟雙旗茗，爐殘小瓣沈。", "感時思別墅，開戶見遥岑。", "自別堯庭邃，俄驚墨突黔。", "背無三甲起，頭有二毛侵。", "咎往眉難炙，言歸足尚肣。", "靜忘波洶洶，老諳歲駸駸。", "幸得安心法，聊爲擁鼻吟。", "黑甜誇勝味，黄落寄餘音。"]'),
('1d53a31f-9d61-4153-851e-6c6cc5038f6d','雙投酒','周麟之','宋','宋诗','song-poetry','','[]','君不見白玉壺中瓊液白，避暑一盃冰雪敵。',310,'全唐诗/poet.song.123000.json','["君不見白玉壺中瓊液白，避暑一盃冰雪敵。", "只今名冠萬錢厨，此法妙絕天下無。", "又不見九重春色薔薇露，君王自酌觴金母。", "味涵椒桂光耀泉，御方弗許人間傳。", "向來我作金門客，不假釀花并漬核。", "日日公堂給上尊，時時帝所分餘瀝。", "一朝釋珮投江村，却訪田家老瓦盆。", "道院丹泉灰脚重，官爐玉友糟頭渾。", "有酒如此寧不飲，但賦獨醒招楚魂。", "錦谿昨夜秋風入，梧葉雨殘溪水急。", "呼奴爲我挽飛流，滌甕燎薪炊玉粒。", "奴言新釀良未宜，此間寒燠來無時。", "雙投舊法酒經載，今焉可試君無疑。", "初觀白醑寒漿溜，再加麴米成重酎。", "色如竹葉照人明，香似蘭英和露透。", "妻孥一笑醆斝空，所恨無多纔數斗。", "嗟予性與禮法疏，況此掃軌甘窮居。", "肯學鴟夷隨後車，不煩騎馿驥子扶。", "焉用拊缶歌烏烏，一觴一詠聊自娛。"]'),
('2db79e0a-8147-4bc9-bec0-4efda0e966bc','飛來峰','周麟之','宋','宋诗','song-poetry','','["\u897f\u6e56"]','西域嶄崱羣玉峰，懸崖萬丈穿玲瓏。',144,'全唐诗/poet.song.123000.json','["西域嶄崱羣玉峰，懸崖萬丈穿玲瓏。", "世人不識真鬼工，夜半躍起隨雷風。", "天與西湖作奇觀，嶷然飛墮羣山中。", "海風吹雨萬壑暝，往往密有雲相通。", "遥望煙鬟出林塢，重巒面面青蓮宇。", "孤雲起石風生泉，游人六月不知暑。", "世傳飛來我亦疑，摩挲蒼璧心更悲。", "當年禁囿山水遠，艮岑一石須人挽。", "無人把酒酹山靈，飛入君王上林苑。"]'),
('a54f7c47-03fb-42d6-9368-e69c31f54ae7','賦張參政四老堂  其一','周麟之','宋','宋诗','song-poetry','','[]','散策相從倚玉鳩，不須更伴赤松遊。',64,'全唐诗/poet.song.123000.json','["散策相從倚玉鳩，不須更伴赤松遊。", "林塘在眼供舒嘯，花鳥催詩好勸酬。", "一座幾盈三百歲，四翁宜壽八千秋。", "堂前風物如伊洛，尚欠香山與石樓。"]'),
('27c08b12-ac84-4a44-acba-2b2b122959e0','賦張參政四老堂  其二','周麟之','宋','宋诗','song-poetry','','[]','西望斜川烟靄低，荆溪東下泛清漪。',64,'全唐诗/poet.song.123000.json','["西望斜川烟靄低，荆溪東下泛清漪。", "夜來風雨秋懷共，春草池塘晝夢遲。", "江左便傳花萼集，曲中休奏紫芝詞。", "安車不日聯鑣至，銀角桃枝上玉墀。"]'),
('b06c9f8e-7a93-45ca-8961-b2e8f74c2a30','呈郫人李簽判','周麟之','宋','宋诗','song-poetry','','[]','錦江煙水春茫茫，錦城遊宴歌舞狂。',256,'全唐诗/poet.song.123000.json','["錦江煙水春茫茫，錦城遊宴歌舞狂。", "酒酣緩轡踏花去，尚說當年先侍郎。", "後來游宦家因徙，子孫不復歸桑梓。", "世居淮海二百年，路隔關山七千里。", "兵戈南下風塵昏，衣冠渡江黄屋奔。", "淮鄉幾作邊戍地，叢桂舊第無一存。", "我從避亂梅花塢，釣月眠雲拉巢許。", "爾來又卜南郭居，自笑飄萍無定所。", "見君襟韵真謫仙，從來遊戲壺中天。", "眷言我祖舊同閈，邂逅笑語心豁然。", "平生行李遍方外，南逾五嶺入蒼翠。", "脫靴未屈力士手，探囊已壓髯奴背。", "爲歎干戈何日休，浮家泛宅江海遊。", "丹砂鍊就葛洪鼎，茶竈行隨魯望舟。", "天涯一見傾蓋舊，青城猿鶴知存否。", "會當叱馭過邛郲，相從却飲郫筒酒。"]'),
('8f60a765-b2b6-4bec-9e46-29c39bd819e0','呈伯父元仲二首  其一','周麟之','宋','宋诗','song-poetry','','[]','我伯氣吐虹，貫日干文光。',180,'全唐诗/poet.song.123000.json','["我伯氣吐虹，貫日干文光。", "胸中有和璞，發揮見文章。", "筆追羲獻風，句壓曹劉牆。", "平生太古心，孰得窺行藏。", "人間富貴味，掩口不一嘗。", "方朔饑欲死，次公醒而狂。", "方寸不受折，養此百鍊剛。", "江湖五十年，飄飄曳征裳。", "晚歲一區宅，欲並幽林塘。", "浙東山水窟，選勝方徜徉。", "蘭溪得佳致，行築鍾山堂。", "自顧世路險，機穽寧易防。", "俛首吾不能，高卧庸何傷。", "貧賤苟自得，麫糗皆膏粱。", "願言守此志，鵬鷃聊相忘。"]'),
('7ef34494-7950-47cf-b3ed-f4f02f3bd732','呈伯父元仲二首  其二','周麟之','宋','宋诗','song-poetry','','[]','干戈十年餘，荏苒百憂至。',180,'全唐诗/poet.song.123000.json','["干戈十年餘，荏苒百憂至。", "誰憐齒未壯，遽失綵衣戲。", "捫心天不聞，空下千斛淚。", "藐然一星孤，未忍隨以逝。", "雨濕新松楸，塵生舊鞶帨。", "奈此愁絕何，況復形夢寐。", "蕭蕭風樹悲，此恨豈有既。", "念昔齠齓中，從公識奇字。", "一從江淮別，歲月不復記。", "公尋武夷春，我友頤山桂。", "此來忽相見，再拜只流涕。", "忽忽悅情話，恍若已隔世。", "先人有遺經，夙夜焉敢墜。", "餘生倘未殞，肯負平日志。", "但恨不及親，臨風一歔欷。"]'),
('34ad575a-f9e8-4fc8-bab9-abea7b4bf86c','寄伯父元舉','周麟之','宋','宋诗','song-poetry','','[]','我家百笏門，族望甲鄉國。',288,'全唐诗/poet.song.123000.json','["我家百笏門，族望甲鄉國。", "堂堂六世祖，名在碧落籍。", "人曰吾故侯，善政光古昔。", "後裔聯簪纓，北原蔭榆柏。", "里居百餘年，世出二千石。", "當時叢桂中，鳴珂動城陌。", "變故忽相仍，流蕩兵火厄。", "一經焚劫餘，故里半荆棘。", "奔騰豺虎羣，逃避天地窄。", "十年湖山游，幸不死鋒鏑。", "朝穿雲麓青，夜釣月溪白。", "間關度陽九，闔室僅安適。", "遽嬰風樹悲，呼天淚橫臆。", "坡陁東龍岡，悵望隔窀穸。", "故鄉渺歸期，異縣悲久客。", "北轅吾未能，遼絕江海隔。", "思我伯父賢，一別幾更歷。", "寇至獨不去，巍坐空四壁。", "高標揖夷齊，九死出焚溺。", "居爲一鄉望，後學所矜式。", "泮水修復初，儒盟首開席。", "我獨隨風蓬，孤陋阻規益。", "明年秋鴻飛，槐花動行色。", "庶遂升堂拜，情話輸悃愊。"]'),
('ac0c3c77-c1e6-454a-8b34-d0d3460e426e','答宋子閑','周麟之','宋','宋诗','song-poetry','','[]','冀北百馬一駃騠，沅江之鼈九肋稀。',272,'全唐诗/poet.song.123000.json','["冀北百馬一駃騠，沅江之鼈九肋稀。", "海邑千室士半之，異材傑出今其誰。", "有客有客氣吐霓，行年五十縫掖衣。", "青鞋白帽鬢未摧，筆下妙絕黄絹碑。", "句中參徹後山詩，邂逅一見秋雲披。", "立談展盡胸中奇，如刮眼膜如起痿。", "便許握手論交期，看君有藴未一施。", "杜門却掃甘幽棲，草樹薿薿含奇姿。", "兩堂對啟白板扉，我時剝啄叩扊扅。", "君出迎笑喜見眉，晴窗坐隠花影移。", "茗椀未盡爐香遲，手弄麈尾風颸颸。", "主人得意客忘歸，嗟予懵學安所師。", "矧復少也逢百罹，尚頼先德流餘滋。", "遺編爛爛星斗垂，墨猶未乾吾忍窺。", "梅花一詠偶弗遺，君能鑒賞了不疑。", "惜哉不與君同時，生前未免俗子嗤。", "身後有此名流知，嗚呼吾意其何悲。"]'),
('3fe800af-d965-4565-88be-cd1ca17e7a58','上王吏部','周麟之','宋','宋诗','song-poetry','','[]','人物南州望，風流一代英。',288,'全唐诗/poet.song.123000.json','["人物南州望，風流一代英。", "夙傳天上譽，早夢月中名。", "車載三千牘，鵬飛九萬程。", "向來辭泮水，端合上仙瀛。", "接武虞廷邃，含香漢殿清。", "漸看丹極近，首冠列星明。", "準擬陪三接，周旋位六卿。", "鑑分金背重，橐並紫荷輕。", "未見恩綸出，那知謗篋盈。", "去朝雲路杳，歸侍綵衣榮。", "地借徽之竹，樓吹子晉笙。", "赤心何所負，白眼不須驚。", "自顧銜恩厚，親逢較藝精。", "妍媸歸藻鑑，高下見文衡。", "夢絕懷蛟異，詞非吐鳳成。", "賦能窺小小，經漫說鏗鏗。", "誤玷春官籍，終慙月旦評。", "搶榆幾類鷃，出谷僅同鶑。", "志慕青錢士，名參玉筍生。", "別深秋鶴怨，歸問海鷗盟。", "未作河西尉，聊爲江上行。", "夜沈灘月釣，曉壓隴雲耕。", "歲暮人初返，天寒雨未晴。", "久稽從杖履，且復卧柴荆。"]'),
('a0ff676d-663e-43b5-a678-3894bb003660','見張運使郎中  其一','周麟之','宋','宋诗','song-poetry','','[]','風度顒顒白首郎，清朝趨奏久含香。',64,'全唐诗/poet.song.123000.json','["風度顒顒白首郎，清朝趨奏久含香。", "東南德望龍津闊，甲乙科名雁序長。", "使節不辭驪駕遠，卿家重見㦸門光。", "願公早入承明去，一試囊中活國方。"]'),
('09841758-3065-4722-ba70-8fa50e345a0c','見張運使郎中  其二','周麟之','宋','宋诗','song-poetry','','[]','野鶴摩雲萬里心，一枝聊復寄高林。',64,'全唐诗/poet.song.123000.json','["野鶴摩雲萬里心，一枝聊復寄高林。", "愁邊舉目江山異，客裏登樓歲月深。", "長鋏誓爲知己用，短檠空伴讀書吟。", "龍門不拒通家子，應許來聽正始音。"]'),
('f00f1e46-82be-40c8-a49d-a3e8d305e59a','送王時亨舍人帥蜀詩二首  其一','周麟之','宋','宋诗','song-poetry','','[]','煌煌大筆照坤維，忽見文星下紫微。',64,'全唐诗/poet.song.123000.json','["煌煌大筆照坤維，忽見文星下紫微。", "萬里江山渾改觀，九重紳笏更爭輝。", "占松不假刀形夢，換馬端期鵠趁飛。", "試問郫筒故鄉酒，路人應唱踏花歸。"]'),
('1a348bb3-60a6-4d6f-b5ce-14cc2338ac16','送王時亨舍人帥蜀詩二首  其二','周麟之','宋','宋诗','song-poetry','','[]','一從雁塔綴英游，又見功名得志秋。',64,'全唐诗/poet.song.123000.json','["一從雁塔綴英游，又見功名得志秋。", "丹闕萬人窺榜眼，碧幢千騎擁遨頭。", "錦城日暖惸鰥舞，玉壘煙深鎧仗收。", "它日中和聞善政，一琴寧復久淹留。"]'),
('1d781bcf-704e-49cb-8b04-11047af688f6','和陳大監','周麟之','宋','宋诗','song-poetry','','[]','君不見漢業已定猶勒兵，白登坐困師無名。',227,'全唐诗/poet.song.123000.json','["君不見漢業已定猶勒兵，白登坐困師無名。", "席門先生計無誤，黠虜不得窺平城。", "論功自合班人傑，蓋世拔山威盡折。", "漫誇勳業是韓彭，我出六奇秦項滅。", "後來漢道如衰周，德尊一代陳太丘。", "二方相繼厲名節，不顧羔雁真善謀。", "雪霜貿貿年芳改，凜凜松筠見風采。", "豺狼當路狐狸號，獨有孤鴻橫四海。", "至今逸韵傳清商，雲和之瑟絃高張。", "耳孫磊落天下士，大才有出皆其長。", "胸中萬卷饒丘壑，鮮取遺音叩寂寞。", "一朝解組又彈冠，出處無心付天樂。", "我輩等是風月人，昔也同閈今爲鄰。", "不妨對語味如蠟，擾擾萬事從橫陳。"]'),
('af2bebcb-911e-4493-996c-efbd0e35298a','再次韵爲謝','周麟之','宋','宋诗','song-poetry','','[]','公詩律嚴如用兵，江淮草木先知名。',224,'全唐诗/poet.song.123000.json','["公詩律嚴如用兵，江淮草木先知名。", "少當千人掃文陣，晚策百勝攻愁城。", "詩壇老將天下傑，筆倒三江流萬折。", "時將妙句吐長虹，李杜文章光不滅。", "由來事業師伊周，詎止博識窮九丘。", "星列丹墀藹華望，月昇金掌陳嘉謀。", "脫冠歸來雙鬢改，任爾功名爭好采。", "揮絃月下奏高山，擊楫波間哦小海。", "方今祝網仁如商，聖賢相逢治具張。", "鶴書旁午詔多士，不以椳闑遺寸長。", "如公豈得栖林壑，焉問曉猿驚索寞。", "歲晚方諧魏闕心，官閒不減商山樂。", "湖上春來花惱人，我不憂貧依富鄰。", "朋友膠漆古來事，願言握臂追雷陳。"]'),
('b30d3b35-8241-400f-99bc-67682c332323','趙見獨示所業并詩次韵謝之','周麟之','宋','宋诗','song-poetry','','[]','沅江九肋稀，端問學不學。',168,'全唐诗/poet.song.123000.json','["沅江九肋稀，端問學不學。", "向來屠沽輩，過眼褐寬博。", "如公負奇才，尚隔雲津躍。", "昔吾先隠君，早識麟一角。", "聯翩錦囊句，紆餘仍卓犖。", "千載埋玉悲，孤芳竟誰擢。", "別來二十年，歷歷記前作。", "賤子更百罹，素業守彌恪。", "餘輝忽振耀，如獲西山藥。", "清夢到鈞天，求音叩寂寞。", "中宵對蓮炬，何以稱光渥。", "辱君瓊瑶篇，重愧鼠呼璞。", "大軸闚洪源，洶湧千澗落。", "一洗胸中塵，豁若春雲廓。"]'),
('104a4563-ca86-4940-b53a-1f7ac232abce','以珠子香建茶寄皖公山馬先生','周麟之','宋','宋诗','song-poetry','','[]','筠谷珠璣北苑春，寸誠千里託靈芬。',32,'全唐诗/poet.song.123000.json','["筠谷珠璣北苑春，寸誠千里託靈芬。", "爲投白鹿岩前客，何日容分半席雲。"]');
